export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  groundingLinks?: { title: string; uri: string }[];
}

export interface GeneratedImage {
  url: string;
  prompt: string;
  timestamp: number;
}

import React, { useState } from 'react';
