export default App;

import { GoogleGenAI, Type, Modality } from "@google/genai";

// Standard decoding for audio
export function decodeBase64Audio(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function encodeUint8ArrayToBase64(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export const getGeminiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const generateText = async (prompt: string, model: string = 'gemini-3-flash-preview', tools: any[] = []) => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools,
    },
  });
  return response;
};

export const generateImage = async (prompt: string, model: string = 'gemini-2.5-flash-image') => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model,
    contents: { parts: [{ text: prompt }] },
    config: {
        imageConfig: {
            aspectRatio: "1:1"
        }
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (imgPart?.inlineData) {
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  }
  return null;
};

import React, { useState, useRef, useEffect } from 'react';
import { generateText } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Send, Loader2, Search, Map as MapIcon, Link as LinkIcon, AlertCircle } from 'lucide-react';

const ChatView: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [useSearch, setUseSearch] = useState(true);
  const [useMaps, setUseMaps] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const tools = [];
      if (useSearch) tools.push({ googleSearch: {} });
      if (useMaps) tools.push({ googleMaps: {} });

      // If maps is used, we need a 2.5 model as per rules
      const model = useMaps ? 'gemini-2.5-flash' : 'gemini-3-flash-preview';

      const response = await generateText(input, model, tools);

      const groundingLinks: { title: string; uri: string }[] = [];
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

      if (chunks) {
        chunks.forEach((chunk: any) => {
          if (chunk.web) groundingLinks.push({ title: chunk.web.title, uri: chunk.web.uri });
          if (chunk.maps) groundingLinks.push({ title: chunk.maps.title, uri: chunk.maps.uri });
        });
      }

      const modelMsg: ChatMessage = {
        role: 'model',
        text: response.text || "I couldn't generate a response.",
        timestamp: Date.now(),
        groundingLinks: groundingLinks.length > 0 ? groundingLinks : undefined
      };

      setMessages(prev => [...prev, modelMsg]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, {
        role: 'model',
        text: "Error: Failed to fetch response from Gemini. Please check your connection or API configuration.",
        timestamp: Date.now()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto">
      {/* Header */}
      <div className="p-6 border-b border-slate-800 flex items-center justify-between sticky top-0 bg-slate-950/80 backdrop-blur-md z-10">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <Search className="text-blue-400" size={20} />
            Grounding Chat
          </h2>
          <p className="text-sm text-slate-500">Enhanced reasoning with Search & Maps</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setUseSearch(!useSearch)}
            className={`px-3 py-1.5 rounded-lg text-xs font-medium flex items-center gap-2 transition-all ${useSearch ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : 'bg-slate-800 text-slate-400'}`}
          >
            <Search size={14} /> Search
          </button>
          <button 
             onClick={() => {
               setUseMaps(!useMaps);
               if(!useMaps) setUseSearch(true); // Maps works best with Search
             }}
             className={`px-3 py-1.5 rounded-lg text-xs font-medium flex items-center gap-2 transition-all ${useMaps ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20' : 'bg-slate-800 text-slate-400'}`}
          >
            <MapIcon size={14} /> Maps
          </button>
        </div>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-slate-500 space-y-4">
            <div className="p-4 bg-slate-900 rounded-full">
              <Sparkles size={32} className="text-blue-500" />
            </div>
            <p className="text-center max-w-sm">
              Ask anything! Try queries like "What's happening in tech news today?" or "Show me top rated pizza places in Seattle."
            </p>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-3xl p-4 md:p-5 ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white shadow-xl shadow-blue-600/10' 
                : 'bg-slate-900 border border-slate-800 text-slate-200'
            }`}>
              <div className="text-sm md:text-base leading-relaxed whitespace-pre-wrap">{msg.text}</div>

              {msg.groundingLinks && (
                <div className="mt-4 pt-4 border-t border-slate-800 space-y-2">
                  <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Sources</p>
                  <div className="flex flex-wrap gap-2">
                    {msg.groundingLinks.map((link, idx) => (
                      <a 
                        key={idx} 
                        href={link.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-xs bg-slate-800 hover:bg-slate-700 text-blue-400 px-3 py-1 rounded-full flex items-center gap-1 transition-colors border border-slate-700"
                      >
                        <LinkIcon size={12} /> {link.title || 'Source'}
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <div className={`text-[10px] mt-2 opacity-40 font-mono ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {new Date(msg.timestamp).toLocaleTimeString()}
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-900 border border-slate-800 rounded-3xl p-4 flex items-center space-x-3">
              <Loader2 className="animate-spin text-blue-400" size={18} />
              <span className="text-sm text-slate-400">Gemini is thinking...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-6 pt-0 mt-auto sticky bottom-0 bg-slate-950/80 backdrop-blur-md">
        <div className="relative group">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your prompt here..."
            className="w-full bg-slate-900 border border-slate-800 rounded-2xl py-4 pl-6 pr-14 focus:outline-none focus:border-blue-500 transition-all text-slate-100 placeholder-slate-500 shadow-2xl"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className={`absolute right-3 top-1/2 -translate-y-1/2 p-2.5 rounded-xl transition-all ${
              !input.trim() || isLoading 
                ? 'text-slate-600 bg-slate-800' 
                : 'text-white bg-blue-600 hover:bg-blue-500 active:scale-95'
            }`}
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatView;

import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Loader2, Download, Image as ImageIcon, Sparkles, AlertCircle, Info } from 'lucide-react';

const ImageGenView: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [modelType, setModelType] = useState<'flash' | 'pro'>('flash');
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    setGeneratedImage(null);
    setError(null);

    try {
      // Check for Pro model permissions
      if (modelType === 'pro') {
        // @ts-ignore
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          // @ts-ignore
          await window.aistudio.openSelectKey();
          // After openSelectKey we proceed as if success as per instructions
        }
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const modelName = modelType === 'pro' ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';

      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts: [{ text: prompt }] },
        config: {
          imageConfig: {
            aspectRatio: "1:1",
            ...(modelType === 'pro' ? { imageSize: "1K" } : {})
          }
        }
      });

      const imgPart = response.candidates?.[0]?.content?.parts.find((p: any) => p.inlineData);
      if (imgPart?.inlineData) {
        setGeneratedImage(`data:image/png;base64,${imgPart.inlineData.data}`);
      } else {
        throw new Error("No image data received from API");
      }
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        setError("API Key Error. Please re-select your key in the AI Studio dialog.");
        // @ts-ignore
        await window.aistudio.openSelectKey();
      } else {
        setError("Generation failed. " + (err.message || "Unknown error occurred."));
      }
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-extrabold flex items-center gap-3">
            <ImageIcon className="text-purple-400" size={32} />
            Visual Studio
          </h2>
          <p className="text-slate-400">Bring your imagination to life with Gemini</p>
        </div>

        <div className="flex bg-slate-900 p-1 rounded-xl border border-slate-800">
          <button 
            onClick={() => setModelType('flash')}
            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${modelType === 'flash' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-500'}`}
          >
            FLASH
          </button>
          <button 
            onClick={() => setModelType('pro')}
            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${modelType === 'pro' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
          >
            PRO (1K)
          </button>
        </div>
      </div>

      <div className="space-y-6">
        <div className="relative group">
          <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="A surreal landscape with floating islands, purple trees, and a silver river under a triple sunset, high detail, digital art..."
            className="w-full bg-slate-900 border border-slate-800 rounded-3xl p-6 min-h-[120px] focus:outline-none focus:border-purple-500 transition-all text-slate-100 placeholder-slate-600 resize-none shadow-xl"
          />
          <button
            onClick={handleGenerate}
            disabled={!prompt.trim() || isGenerating}
            className={`absolute right-4 bottom-4 px-6 py-2.5 rounded-2xl font-bold flex items-center gap-2 transition-all ${
              !prompt.trim() || isGenerating
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
                : 'bg-gradient-to-r from-purple-600 to-indigo-600 text-white hover:from-purple-500 hover:to-indigo-500 shadow-lg shadow-purple-600/20 active:scale-95'
            }`}
          >
            {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
            {isGenerating ? 'Creating...' : 'Generate'}
          </button>
        </div>

        {error && (
          <div className="p-4 bg-red-900/20 border border-red-900/50 rounded-2xl flex items-center gap-3 text-red-400 text-sm">
            <AlertCircle size={20} />
            {error}
          </div>
        )}

        <div className="relative min-h-[400px] flex items-center justify-center rounded-3xl bg-slate-900 border border-slate-800 overflow-hidden shadow-2xl">
          {isGenerating ? (
            <div className="flex flex-col items-center space-y-4">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-purple-600/20 border-t-purple-600 rounded-full animate-spin"></div>
                <ImageIcon size={24} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-purple-400 opacity-50" />
              </div>
              <div className="text-center">
                <p className="text-lg font-bold text-slate-200">Generating Masterpiece</p>
                <p className="text-sm text-slate-500">Wait a few seconds for our AI to dream it up...</p>
              </div>
            </div>
          ) : generatedImage ? (
            <div className="relative w-full h-full group">
              <img src={generatedImage} alt="Generated" className="w-full h-full object-contain" />
              <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                <a 
                  href={generatedImage} 
                  download={`gemini-${Date.now()}.png`}
                  className="p-4 bg-white text-black rounded-full hover:scale-110 transition-transform shadow-xl"
                >
                  <Download size={24} />
                </a>
              </div>
            </div>
          ) : (
            <div className="text-center p-12 space-y-4">
              <div className="mx-auto w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center">
                <ImageIcon size={40} className="text-slate-700" />
              </div>
              <div>
                <p className="text-slate-400">Your generated image will appear here</p>
                <p className="text-xs text-slate-600 mt-1">PRO model requires a paid API key and billing documentation.</p>
              </div>
            </div>
          )}
        </div>

        {modelType === 'pro' && (
          <div className="bg-blue-900/10 border border-blue-900/30 rounded-2xl p-4 flex items-start gap-3">
            <Info size={18} className="text-blue-400 mt-1 flex-shrink-0" />
            <div className="text-xs text-slate-400 leading-relaxed">
              Gemini 3 Pro Image supports 1K resolution and higher quality details. Ensure you have selected a valid API key from a paid GCP project. 
              <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-blue-400 hover:underline ml-1">Learn more about billing.</a>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageGenView;

import React, { useState, useRef } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import { Volume2, Play, Loader2, Music, User, Users } from 'lucide-react';
import { decodeBase64Audio, decodeAudioData } from '../services/geminiService';

const TTSView: React.FC = () => {
  const [text, setText] = useState('Welcome to the Gemini Multi-Modal Hub. I can speak in many different voices!');
  const [isProcessing, setIsProcessing] = useState(false);
  const [voice, setVoice] = useState('Kore');
  const [mode, setMode] = useState<'single' | 'multi'>('single');
  const audioContextRef = useRef<AudioContext | null>(null);

  const handleSpeak = async () => {
    if (!text.trim()) return;
    setIsProcessing(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      let config: any = {
        responseModalities: [Modality.AUDIO],
      };

      let finalPrompt = text;

      if (mode === 'single') {
        config.speechConfig = {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voice },
          },
        };
      } else {
        finalPrompt = `TTS the following conversation between Joe and Jane:
        Joe: ${text.split('\n')[0] || 'Hello!'}
        Jane: ${text.split('\n')[1] || 'Hi there, how are you?'}`;

        config.speechConfig = {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: 'Joe', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
              { speaker: 'Jane', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
            ],
          },
        };
      }

      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: finalPrompt }] }],
        config,
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }

        const ctx = audioContextRef.current;
        const decoded = decodeBase64Audio(base64Audio);
        const buffer = await decodeAudioData(decoded, ctx, 24000, 1);

        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        source.start();
      }
    } catch (err) {
      console.error(err);
      alert("Speech synthesis failed. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-3xl font-extrabold flex items-center gap-3">
            <Volume2 className="text-amber-400" size={32} />
            Text to Speech
          </h2>
