      id: Math.random().toString(36).substr(2, 9),
      origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
      timestamp: Date.now()
    };
    const updated = [newTrip, ...savedTrips];
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const deleteTrip = (id: string) => {
    const updated = savedTrips.filter(t => t.id !== id);
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const shareTrip = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('dest', destination);
    url.searchParams.set('start', dates.start);
    url.searchParams.set('end', dates.end);
    navigator.clipboard.writeText(url.toString());
    alert("Share link copied to clipboard!");
  };

  const convertTemp = (c: number) => {
    return tempUnit === 'C' ? Math.round(c) : Math.round((c * 9/5) + 32);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50/30">
      {/* Navbar */}
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-600/20">
              <Sparkles size={22} fill="currentColor" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-r from-blue-700 to-indigo-600 bg-clip-text text-transparent">
              WanderGenius
            </h1>
          </div>
          <div className="flex items-center space-x-4">
             {savedTrips.length > 0 && (
               <div className="hidden md:flex items-center -space-x-2">
                 {savedTrips.slice(0, 3).map((t, i) => (
                   <div key={i} className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white flex items-center justify-center text-[10px] font-bold text-slate-600">
