                    <Plane size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  </div>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Main Destination (e.g. Tokyo)" 
                      value={destination}
                      onChange={(e) => setDestination(e.target.value)}
                      required
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <MapPin size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-500" />
                  </div>
                </div>

                {/* Additional Cities */}
                <div className="pt-2">
                  <div className="flex gap-2 mb-3">
                    <input 
                      type="text" 
                      placeholder="Add another city..." 
                      value={newCity}
                      onChange={(e) => setNewCity(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                      className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <button type="button" onClick={handleAddCity} className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors">
                      <Plus size={20} />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {additionalCities.map((city, idx) => (
                      <span key={idx} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2 border border-blue-100">
                        {city}
                        <X size={14} className="cursor-pointer" onClick={() => setAdditionalCities(prev => prev.filter((_, i) => i !== idx))} />
                      </span>
                    ))}
                  </div>
                </div>
              </div>

              {/* Timing & Budget */}
              <div className="space-y-6">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <Calendar size={16} className="text-emerald-500" />
                    Timing
                  </label>
                  <div className="grid grid-cols-2 gap-3">
                    <input 
                      type="date" 
                      value={dates.start}
                      onChange={(e) => setDates({...dates, start: e.target.value})}
                      required
                      className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none"
                    />
                    <input 
                      type="date" 
                      value={dates.end}
                      onChange={(e) => setDates({...dates, end: e.target.value})}
                      required
                      className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none"
                    />
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <DollarSign size={16} className="text-amber-500" />
                    Nightly Budget
                  </label>
                  <div className="flex items-center gap-4">
                    <input 
                      type="range" 
                      min="50" 
                      max="1000" 
                      step="50"
                      value={budget.max}
                      onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})}
                      className="flex-1 accent-blue-600"
                    />
                    <span className="text-sm font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">Up to ${budget.max}</span>
                  </div>
                </div>
              </div>
            </div>

            <button 
              type="submit" 
              disabled={isPlanning}
              className={`w-full py-5 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${
                isPlanning 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-600/30 active:scale-[0.98]'
              }`}
            >
              {isPlanning ? <Loader2 size={24} className="animate-spin" /> : <Sparkles size={24} />}
              {isPlanning ? 'Analyzing Destinations...' : 'Craft My Trip'}
            </button>
          </form>

          {/* Saved Trips Bar */}
          {savedTrips.length > 0 && (
            <div className="mt-8 flex items-center gap-3 overflow-x-auto pb-4 custom-scrollbar">
              <span className="text-xs font-bold text-slate-400 uppercase whitespace-nowrap">Recent:</span>
              {savedTrips.map((trip) => (
                <div key={trip.id} className="flex items-center gap-2 bg-white border border-slate-200 rounded-xl px-4 py-2 shadow-sm hover:border-blue-300 transition-all group shrink-0">
                  <span className="text-sm font-semibold text-slate-700">{trip.destination}</span>
                  <Trash2 size={14} className="text-slate-300 hover:text-red-500 cursor-pointer transition-colors" onClick={() => deleteTrip(trip.id)} />
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Results Section */}
      <div ref={resultsRef} className="max-w-6xl mx-auto px-6 pb-24 space-y-8">
        {results && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
            {/* Feasibility Alert */}
            <div className={`mb-8 p-6 rounded-3xl border flex items-start gap-4 ${
              results.feasibility.toLowerCase().includes('realistic') 
              ? 'bg-emerald-50 border-emerald-100 text-emerald-800' 
              : 'bg-amber-50 border-amber-100 text-amber-800'
            }`}>
              {results.feasibility.toLowerCase().includes('realistic') ? <CheckCircle2 className="mt-1" /> : <AlertTriangle className="mt-1" />}
              <div>
                <h4 className="font-bold text-lg">Trip Feasibility</h4>
                <p className="text-sm opacity-90">{results.feasibility}</p>
              </div>
              <div className="ml-auto flex gap-2">
                <button onClick={saveTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm">
                  <Save size={20} className="text-slate-700" />
                </button>
                <button onClick={shareTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm">
                  <Share2 size={20} className="text-slate-700" />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              {/* Left Column: Weather & Itinerary */}
              <div className="lg:col-span-2 space-y-8">
                {/* Weather Section */}
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('weather')}>
                    <h3 className="text-xl font-bold flex items-center gap-3">
                      <CloudSun size={24} className="text-blue-500" />
                      Weather Forecast
                    </h3>
                    <div className="flex items-center gap-4">
                      <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('C')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'C' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°C</button>
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('F')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'F' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°F</button>
                      </div>
                      {expandedSections.weather ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </div>
                  </div>
                  {expandedSections.weather && (
                    <div className="p-8">
                      {weather ? (
                        <div className="grid grid-cols-2 md:grid-cols-7 gap-4">
                          {weather.daily.time.slice(0, 7).map((time: string, i: number) => (
                            <div key={i} className="flex flex-col items-center p-3 rounded-2xl bg-slate-50 text-center border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(time).toLocaleDateString('en-US', { weekday: 'short' })}</span>
                              <div className="my-2 text-2xl">
                                {weather.daily.weathercode[i] < 3 ? '☀️' : weather.daily.weathercode[i] < 50 ? '☁️' : '🌧️'}
                              </div>
                              <div className="text-sm font-bold text-slate-800">
                                {convertTemp(weather.daily.temperature_2m_max[i])}°
                              </div>
                              <div className="text-[10px] text-slate-400">
                                {convertTemp(weather.daily.temperature_2m_min[i])}°
                              </div>
                            </div>
                          ))}
                        </div>
                      ) : (
                        <div className="text-center py-4 text-slate-400 italic">No forecast data available for this range yet.</div>
                      )}
                      <div className="mt-6 p-4 rounded-2xl bg-amber-50 border border-amber-100 text-xs text-amber-800 flex items-center gap-3">
                        <Info size={16} />
                        <p><b>Packing Tip:</b> Layering is key! Bring a light jacket and comfortable walking shoes for ${destination}.</p>
                      </div>
                    </div>
                  )}
                </div>

                {/* Itinerary Section */}
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('itinerary')}>
                    <h3 className="text-xl font-bold flex items-center gap-3">
                      <Briefcase size={24} className="text-emerald-500" />
                      Daily Itinerary
                    </h3>
                    {expandedSections.itinerary ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.itinerary && (
                    <div className="p-8 space-y-8">
                      {results.itinerary.map((day: ItineraryDay, i: number) => (
                        <div key={i} className="relative pl-12">
                          <div className="absolute left-0 top-0 w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center text-white text-xs font-bold shadow-lg shadow-emerald-500/20 z-10">
                            {day.day}
                          </div>
                          {i < results.itinerary.length - 1 && <div className="absolute left-4 top-8 bottom-[-2rem] w-0.5 bg-slate-100"></div>}
                          <div className="space-y-3">
                            <div className="flex items-center justify-between">
                              <h4 className="font-extrabold text-lg text-slate-800">{day.title}</h4>
                              <span className="text-xs font-bold text-slate-400 uppercase">{day.location}</span>
                            </div>
                            <ul className="space-y-2">
                              {day.activities.map((act, idx) => (
                                <li key={idx} className="flex items-center gap-3 text-slate-600 text-sm">
                                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-300"></div>
                                  {act}
                                </li>
                              ))}
                            </ul>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Right Column: Flights, Map & Hotels */}
              <div className="space-y-8">
                {/* Flights Section */}
                <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-xl">
                  <div className="p-6 border-b border-slate-800 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('flights')}>
                    <h3 className="text-xl font-bold text-white flex items-center gap-3">
                      <Plane size={24} className="text-blue-400" />
                      Flight Estimates
                    </h3>
                    {expandedSections.flights ? <ChevronUp size={20} className="text-slate-500" /> : <ChevronDown size={20} className="text-slate-500" />}
                  </div>
                  {expandedSections.flights && (
                    <div className="p-6 space-y-4">
                      {results.flights.map((flight: FlightOffer, i: number) => (
                        <div key={i} className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 hover:border-blue-500 transition-all group">
                          <div className="flex justify-between items-center mb-3">
                            <span className="text-blue-400 font-bold text-sm">{flight.airline}</span>
                            <span className="text-white font-extrabold">${flight.price}</span>
                          </div>
                          <div className="flex items-center gap-3 text-xs text-slate-400">
                             <div className="flex-1 text-right">{flight.departure || 'Local'}</div>
                             <div className="flex-1 h-px bg-slate-700 relative">
                               <Plane size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-600" />
                             </div>
                             <div className="flex-1">{flight.arrival || destination}</div>
                          </div>
                          <div className="mt-3 flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-500">
                             <span>{flight.duration}</span>
                             <span>{flight.stops === 0 ? 'Non-stop' : `${flight.stops} stop${flight.stops > 1 ? 's' : ''}`}</span>
                          </div>
                        </div>
                      ))}
                      <div className="pt-2">
                        <a 
                          href={`https://www.google.com/travel/flights?q=Flights%20to%20${destination}`}
                          target="_blank"
                          className="block text-center py-3 rounded-xl bg-blue-600 text-white font-bold text-sm hover:bg-blue-500 transition-colors shadow-lg shadow-blue-600/20"
                        >
                          Book via Google Flights
                        </a>
                      </div>
                    </div>
                  )}
                </div>

                {/* Map Section */}
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm h-[400px] flex flex-col">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('map')}>
                    <h3 className="text-xl font-bold flex items-center gap-3">
                      <MapIcon size={24} className="text-purple-500" />
                      Neighborhoods
                    </h3>
                    {expandedSections.map ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  <div className={`flex-1 relative ${!expandedSections.map && 'hidden'}`}>
                    <div id="neighborhood-map" className="w-full h-full"></div>
                    <div className="absolute bottom-4 left-4 right-4 bg-white/90 backdrop-blur-md p-3 rounded-2xl border border-slate-200 z-[1000] text-xs shadow-xl max-h-[120px] overflow-y-auto custom-scrollbar">
                       <p className="font-bold mb-1 text-slate-800">Top Picks:</p>
                       <div className="space-y-1">
                         {results.neighborhoods.map((n: Neighborhood, i: number) => (
                           <div key={i} className="flex justify-between items-center">
                             <span className="text-slate-600">• {n.name}</span>
                             <span className="text-[10px] text-purple-600 font-bold uppercase">{n.bestFor}</span>
                           </div>
                         ))}
                       </div>
                    </div>
                  </div>
                </div>

                {/* Accommodations Section */}
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('hotels')}>
                    <h3 className="text-xl font-bold flex items-center gap-3">
                      <Hotel size={24} className="text-amber-500" />
                      Hotels
                    </h3>
                    {expandedSections.hotels ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.hotels && (
                    <div className="p-6 space-y-4">
                      {results.accommodations.map((hotel: any, i: number) => (
                        <div key={i} className="p-4 rounded-2xl bg-slate-50 border border-slate-100 hover:border-amber-400 transition-all cursor-pointer group">
                           <div className="flex justify-between items-start mb-2">
                              <h5 className="font-bold text-slate-800 group-hover:text-amber-600 transition-colors">{hotel.name}</h5>
                              <div className="flex items-center gap-1 text-amber-500 font-bold text-xs bg-amber-50 px-2 py-0.5 rounded-full">
                                <span>{hotel.rating}</span>
                                <Sparkles size={10} fill="currentColor" />
                              </div>
                           </div>
                           <div className="flex justify-between items-center text-sm">
                              <span className="text-slate-500 italic">~${hotel.price}/night</span>
                              <span className="text-blue-600 font-bold text-xs">View Deal</span>
                           </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Empty State / Initial View */}
        {!results && !isPlanning && (
          <div className="flex flex-col items-center justify-center py-12 text-center opacity-30 select-none pointer-events-none">
            <div className="w-32 h-32 bg-slate-200 rounded-full flex items-center justify-center mb-6">
              <MapPin size={64} className="text-slate-400" />
            </div>
            <h3 className="text-2xl font-bold text-slate-400">Plan a trip to see results</h3>
            <p className="max-w-xs text-slate-400 mt-2">Flight estimates, neighborhoods, and itineraries will appear here.</p>
          </div>
        )}
      </div>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-12 px-6">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center space-x-2 grayscale opacity-50">
            <div className="w-8 h-8 bg-slate-800 rounded-lg flex items-center justify-center text-white">
              <Sparkles size={16} fill="currentColor" />
            </div>
            <span className="font-bold tracking-tight text-slate-800">WanderGenius</span>
          </div>
          <p className="text-slate-400 text-sm">© 2025 WanderGenius AI. Powered by Gemini Pro.</p>
          <div className="flex space-x-6">
            <a href="#" className="text-slate-400 hover:text-blue-600 text-sm font-semibold transition-colors">Documentation</a>
            <a href="#" className="text-slate-400 hover:text-blue-600 text-sm font-semibold transition-colors">Privacy</a>
            <a href="#" className="text-slate-400 hover:text-blue-600 text-sm font-semibold transition-colors">Contact</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

export enum AppView {
  DASHBOARD = 'dashboard',
  CHAT = 'chat',
  IMAGE_GEN = 'image_gen',
  LIVE = 'live',
  TTS = 'tts',
  VIDEO = 'video'
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  groundingLinks?: { title: string; uri: string }[];
}

export interface TripPlan {
  id: string;
  origin: string;
  destination: string;
  startDate: string;
  endDate: string;
  budget: { min: number; max: number };
  additionalCities: string[];
  timestamp: number;
}

export interface WeatherDay {
  date: string;
  high: number;
  low: number;
  description: string;
  icon: string;
}

export interface FlightOffer {
  price: number;
  airline: string;
  duration: string;
  stops: number;
  departure: string;
  arrival: string;
}

export interface Neighborhood {
  name: string;
  description: string;
  bestFor: string;
  lat: number;
  lng: number;
}

export interface ItineraryDay {
  day: number;
  title: string;
  activities: string[];
  location: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  ChevronDown, ChevronUp, CloudSun, Map as MapIcon, 
  Hotel, Briefcase, Sparkles, Send, Share2, Save,
  CheckCircle2, Info, AlertTriangle, X, Loader2
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { TripPlan, WeatherDay, FlightOffer, Neighborhood, ItineraryDay } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 300 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
    weather: true,
    flights: true,
    itinerary: true,
    map: true,
    hotels: true
  });

  const resultsRef = useRef<HTMLDivElement>(null);
  // Using any to avoid 'L' namespace error when Leaflet is loaded via window
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_trips');
    if (saved) setSavedTrips(JSON.parse(saved));

    // Handle shared links
    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;

    setIsPlanning(true);
    setResults(null);
    setWeather(null);

    try {
      const intelPromise = getTravelIntelligence({ origin, destination, startDate: dates.start, endDate: dates.end, additionalCities, budget });
      const geo = await geocodeCity(destination);

      let weatherData = null;
      if (geo) {
        weatherData = await fetchWeather(geo.lat, geo.lon, dates.start, dates.end);
      }

      const intel = await intelPromise;
      setResults(intel);
      setWeather(weatherData);

      // Scroll to results
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        initMap(intel.neighborhoods, geo);
      }, 100);

    } catch (err) {
      console.error(err);
      alert("Something went wrong while planning your trip. Please try again.");
    } finally {
      setIsPlanning(false);
    }
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;

    if (mapRef.current) {
      mapRef.current.remove();
    }

    const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; OpenStreetMap contributors'
    }).addTo(map);

    neighborhoods.forEach(n => {
      L.marker([n.lat, n.lng])
        .addTo(map)
        .bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
    });

    mapRef.current = map;
  };

  const saveTrip = () => {
    const newTrip: TripPlan = {
      id: Math.random().toString(36).substr(2, 9),
      origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
      timestamp: Date.now()
    };
    const updated = [newTrip, ...savedTrips];
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const deleteTrip = (id: string) => {
    const updated = savedTrips.filter(t => t.id !== id);
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const shareTrip = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('dest', destination);
    url.searchParams.set('start', dates.start);
    url.searchParams.set('end', dates.end);
    navigator.clipboard.writeText(url.toString());
    alert("Share link copied to clipboard!");
  };

