let accessToken: string | null = null;
let tokenExpiry: number = 0;

async function getAccessToken() {
  const apiKey = (process.env as any).AMADEUS_API_KEY;
  const apiSecret = (process.env as any).AMADEUS_API_SECRET;

  if (!apiKey || !apiSecret) return null;

  if (accessToken && Date.now() < tokenExpiry) {
    return accessToken;
  }

  try {
    const response = await fetch('https://test.api.amadeus.com/v1/security/oauth2/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: `grant_type=client_credentials&client_id=${apiKey}&client_secret=${apiSecret}`
    });
    const data = await response.json();
    accessToken = data.access_token;
    tokenExpiry = Date.now() + (data.expires_in * 1000);
    return accessToken;
  } catch (error) {
    console.error('Amadeus Auth Error:', error);
    return null;
  }
}

export const searchFlights = async (origin: string, destination: string, departureDate: string) => {
  const token = await getAccessToken();
  if (!token) return null;

  const originCode = IATA_MAP[origin.toLowerCase()] || origin.toUpperCase().slice(0, 3);
  const destCode = IATA_MAP[destination.toLowerCase()] || destination.toUpperCase().slice(0, 3);

  try {
    const response = await fetch(
      `https://test.api.amadeus.com/v2/shopping/flight-offers?originLocationCode=${originCode}&destinationLocationCode=${destCode}&departureDate=${departureDate}&adults=1&max=5`,
      {
        headers: { 'Authorization': `Bearer ${token}` }
      }
    );
    const data = await response.json();

    if (!data.data) return null;

    return data.data.map((offer: any) => ({
      price: Math.round(parseFloat(offer.price.total)),
      airline: offer.validatingAirlineCodes[0],
      duration: offer.itineraries[0].duration.replace('PT', '').toLowerCase(),
      stops: offer.itineraries[0].segments.length - 1,
      departure: offer.itineraries[0].segments[0].departure.at,
      arrival: offer.itineraries[0].segments[offer.itineraries[0].segments.length - 1].arrival.at,
      isReal: true
    }));
  } catch (error) {
    console.error('Amadeus Search Error:', error);
    return null;
  }
};

