  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_trips');
    if (saved) setSavedTrips(JSON.parse(saved));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;

    setIsPlanning(true);
    setResults(null);
    setWeather(null);

    try {
      // 1. Qualitative Plan & Geocoding
      const intelPromise = getTravelIntelligence({ origin, destination, startDate: dates.start, endDate: dates.end, additionalCities, budget });
      const geoPromise = geocodeCity(destination);
      const amadeusPromise = searchFlights(origin, destination, dates.start);

      const [intel, geo, amadeusResults] = await Promise.all([
        intelPromise,
        geoPromise,
        amadeusPromise
      ]);

      // 2. Weather
      let weatherData = null;
      if (geo) {
        weatherData = await fetchWeather(geo.lat, geo.lon, dates.start, dates.end);
      }

      // 3. Flight Logic: Prefer Amadeus, Fallback to Gemini Estimates
      if (amadeusResults && amadeusResults.length > 0) {
        intel.flights = amadeusResults;
        intel.isRealFlights = true;
      }

      setResults(intel);
      setWeather(weatherData);

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        initMap(intel.neighborhoods, geo);
      }, 100);

    } catch (err) {
      console.error(err);
      alert("Something went wrong while planning your trip. Please try again.");
    } finally {
      setIsPlanning(false);
    }
  };

