  const [budget, setBudget] = useState({ min: 100, max: 300 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
    weather: true,
    flights: true,
    itinerary: true,
    map: true,
    hotels: true
  });

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_trips');
    if (saved) setSavedTrips(JSON.parse(saved));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;

    setIsPlanning(true);
    setResults(null);
    setWeather(null);

    try {
      // 1. Concurrent fetching for speed
      const intelPromise = getTravelIntelligence({ origin, destination, startDate: dates.start, endDate: dates.end, additionalCities, budget });
      const geoPromise = geocodeCity(destination);
      const amadeusPromise = searchFlights(origin, destination, dates.start);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;

      // Fix: Corrected line 83 to use the settled result status instead of the promise status.
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      // 2. Weather
      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, dates.start, dates.end);
      }

      // 3. Flight Logic: Prefer real-time Amadeus, fallback to Gemini estimates
      if (flightsData && flightsData.length > 0) {
        intelData.flights = flightsData;
        intelData.isRealFlights = true;
      } else {
        intelData.isRealFlights = false;
      }

      setResults(intelData);
      setWeather(weatherData);

      // Scroll to results and init map
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
    }
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;

    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }

    if (mapRef.current) {
      mapRef.current.remove();
    }

    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(map);

      if (neighborhoods && Array.isArray(neighborhoods)) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) {
            L.marker([n.lat, n.lng])
              .addTo(map)
              .bindPopup(`<b>${n.name || 'Neighborhood'}</b><br>${n.bestFor || ''}`);
          }
        });
      }

      mapRef.current = map;
    } catch (err) {
      console.error("Map Error:", err);
    }
  };

  const saveTrip = () => {
    const newTrip: TripPlan = {
      id: Math.random().toString(36).substr(2, 9),
      origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
      timestamp: Date.now()
    };
    const updated = [newTrip, ...savedTrips];
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const deleteTrip = (id: string) => {
    const updated = savedTrips.filter(t => t.id !== id);
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const shareTrip = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('dest', destination);
    url.searchParams.set('start', dates.start);
    url.searchParams.set('end', dates.end);
    navigator.clipboard.writeText(url.toString());
    alert("Share link copied!");
  };

  const convertTemp = (c: number) => {
    return tempUnit === 'C' ? Math.round(c) : Math.round((c * 9/5) + 32);
  };

  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50/30">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-600/20">
              <Sparkles size={22} fill="currentColor" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-r from-blue-700 to-indigo-600 bg-clip-text text-transparent">
              WanderGenius
            </h1>
          </div>
          <div className="flex items-center space-x-4">
             {savedTrips.length > 0 && (
               <div className="hidden md:flex items-center -space-x-2">
                 {savedTrips.slice(0, 3).map((t, i) => (
                   <div key={i} className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white flex items-center justify-center text-[10px] font-bold text-slate-600">
                     {t.destination.charAt(0)}
                   </div>
                 ))}
               </div>
             )}
          </div>
        </div>
      </nav>

      <section className="pt-12 pb-24 px-6">
        <div className="max-w-4xl mx-auto">
          <div className="text-center mb-12 space-y-4">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 leading-tight">
              Where to <span className="text-blue-600 underline decoration-blue-200 decoration-8 underline-offset-4">next?</span>
            </h2>
            <p className="text-slate-500 text-lg max-w-xl mx-auto">
              Live flight results via Amadeus API + Intelligent travel planning.
            </p>
          </div>

          <form onSubmit={handlePlanTrip} className="bg-white rounded-3xl p-8 shadow-2xl shadow-blue-900/5 border border-slate-100 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                  <MapPin size={16} className="text-blue-500" />
                  Route
                </label>
                <div className="space-y-3">
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Origin (e.g. NYC, London)" 
                      value={origin}
                      onChange={(e) => setOrigin(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <Plane size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  </div>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Destination (e.g. Tokyo, Paris)" 
                      value={destination}
                      onChange={(e) => setDestination(e.target.value)}
                      required
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <MapPin size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-500" />
                  </div>
                </div>
                <div className="pt-2">
                  <div className="flex gap-2 mb-3">
                    <input 
                      type="text" 
                      placeholder="Add stop..." 
                      value={newCity}
                      onChange={(e) => setNewCity(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                      className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <button type="button" onClick={handleAddCity} className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700">
                      <Plus size={20} />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {additionalCities.map((city, idx) => (
                      <span key={idx} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2 border border-blue-100">
                        {city}
                        <X size={14} className="cursor-pointer" onClick={() => setAdditionalCities(prev => prev.filter((_, i) => i !== idx))} />
                      </span>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <Calendar size={16} className="text-emerald-500" />
                    Timing
                  </label>
                  <div className="grid grid-cols-2 gap-3">
                    <input type="date" value={dates.start} onChange={(e) => setDates({...dates, start: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                    <input type="date" value={dates.end} onChange={(e) => setDates({...dates, end: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                  </div>
                </div>
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <DollarSign size={16} className="text-amber-500" />
                    Budget per night
                  </label>
                  <div className="flex items-center gap-4">
                    <input type="range" min="50" max="1000" step="50" value={budget.max} onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})} className="flex-1 accent-blue-600" />
                    <span className="text-sm font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">${budget.max}</span>
                  </div>
                </div>
              </div>
            </div>

            <button type="submit" disabled={isPlanning} className={`w-full py-5 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-600/30'}`}>
              {isPlanning ? <Loader2 size={24} className="animate-spin" /> : <Sparkles size={24} />}
              {isPlanning ? 'Analyzing real flights...' : 'Plan Trip with Live Data'}
            </button>
          </form>
        </div>
      </section>

      <div ref={resultsRef} className="max-w-6xl mx-auto px-6 pb-24 space-y-8">
        {results && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
            <div className={`mb-8 p-6 rounded-3xl border flex items-start gap-4 ${isRealistic ? 'bg-emerald-50 border-emerald-100 text-emerald-800' : 'bg-amber-50 border-amber-100 text-amber-800'}`}>
              {isRealistic ? <CheckCircle2 className="mt-1" /> : <AlertTriangle className="mt-1" />}
              <div className="flex-1">
                <h4 className="font-bold text-lg">Trip Feasibility</h4>
                <p className="text-sm opacity-90">{results.feasibility || "Analysis not available."}</p>
              </div>
              <div className="flex gap-2">
                <button onClick={saveTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm"><Save size={20} className="text-slate-700" /></button>
                <button onClick={shareTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm"><Share2 size={20} className="text-slate-700" /></button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('weather')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><CloudSun size={24} className="text-blue-500" />Weather Forecast</h3>
                    <div className="flex items-center gap-4">
                      <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('C')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'C' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°C</button>
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('F')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'F' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°F</button>
                      </div>
                      {expandedSections.weather ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </div>
                  </div>
                  {expandedSections.weather && (
                    <div className="p-8">
                      {weather ? (
                        <div className="grid grid-cols-2 md:grid-cols-7 gap-4">
                          {weather.daily.time.slice(0, 7).map((time: string, i: number) => (
                            <div key={i} className="flex flex-col items-center p-3 rounded-2xl bg-slate-50 text-center border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(time).toLocaleDateString('en-US', { weekday: 'short' })}</span>
                              <div className="my-2 text-2xl">{weather.daily.weathercode[i] < 3 ? '☀️' : weather.daily.weathercode[i] < 50 ? '☁️' : '🌧️'}</div>
                              <div className="text-sm font-bold text-slate-800">{convertTemp(weather.daily.temperature_2m_max[i])}°</div>
                            </div>
                          ))}
                        </div>
                      ) : <div className="text-center py-4 text-slate-400 italic">No forecast available.</div>}
                    </div>
                  )}
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('itinerary')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><Briefcase size={24} className="text-emerald-500" />Daily Itinerary</h3>
                    {expandedSections.itinerary ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.itinerary && (
                    <div className="p-8 space-y-8">
                      {results.itinerary && results.itinerary.map((day: ItineraryDay, i: number) => (
                        <div key={i} className="relative pl-12">
                          <div className="absolute left-0 top-0 w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center text-white text-xs font-bold shadow-lg shadow-emerald-500/20 z-10">{day.day}</div>
                          {i < results.itinerary.length - 1 && <div className="absolute left-4 top-8 bottom-[-2rem] w-0.5 bg-slate-100"></div>}
                          <div className="space-y-3">
                            <h4 className="font-extrabold text-lg text-slate-800">{day.title}</h4>
                            <ul className="space-y-2">
                              {day.activities && day.activities.map((act, idx) => (
                                <li key={idx} className="flex items-center gap-3 text-slate-600 text-sm"><div className="w-1.5 h-1.5 rounded-full bg-emerald-300"></div>{act}</li>
                              ))}
                            </ul>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              <div className="space-y-8">
                <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-xl">
                  <div className="p-6 border-b border-slate-800 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('flights')}>
                    <div className="flex flex-col">
                      <h3 className="text-xl font-bold text-white flex items-center gap-3"><Plane size={24} className="text-blue-400" />Flight Offers</h3>
                      {results.isRealFlights && (
                        <span className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1 flex items-center gap-1"><Zap size={10} fill="currentColor" /> Live Results via Amadeus API</span>
                      )}
                    </div>
                    {expandedSections.flights ? <ChevronUp size={20} className="text-slate-500" /> : <ChevronDown size={20} className="text-slate-500" />}
                  </div>
                  {expandedSections.flights && (
                    <div className="p-6 space-y-4">
                      {results.flights && results.flights.map((flight: FlightOffer & { isReal?: boolean }, i: number) => (
                        <div key={i} className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 hover:border-blue-500 transition-all group">
                          <div className="flex justify-between items-center mb-3">
                            <span className="text-blue-400 font-bold text-sm">{flight.airline}</span>
                            <span className="text-white font-extrabold">${flight.price}</span>
                          </div>
                          <div className="flex items-center gap-3 text-xs text-slate-400">
                             <div className="flex-1 text-right truncate">{flight.departure?.split('T')[0] || '-'}</div>
                             <div className="flex-1 h-px bg-slate-700 relative"><Plane size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-600" /></div>
                             <div className="flex-1 truncate">{flight.arrival?.split('T')[0] || '-'}</div>
                          </div>
                          <div className="mt-3 flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-500">
                             <span>{flight.duration}</span>
                             <span>{flight.stops === 0 ? 'Non-stop' : `${flight.stops} stop`}</span>
                          </div>
                        </div>
                      ))}
                      {!results.isRealFlights && results.flights?.length > 0 && (
                        <div className="p-3 bg-amber-900/20 border border-amber-900/50 rounded-xl text-[10px] text-amber-500 flex items-start gap-2 italic">
                          <Info size={12} className="mt-0.5 shrink-0" />
                          No live flights found for this route. Showing estimated costs based on historical data.
                        </div>
                      )}
                      <div className="pt-2"><a href={`https://www.google.com/travel/flights?q=Flights%20from%20${origin}%20to%20${destination}%20on%20${dates.start}`} target="_blank" className="block text-center py-3 rounded-xl bg-blue-600 text-white font-bold text-sm hover:bg-blue-500 transition-colors shadow-lg shadow-blue-600/20">Verify on Google Flights</a></div>
                    </div>
                  )}
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm h-[400px] flex flex-col">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('map')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><MapIcon size={24} className="text-purple-500" />Neighborhoods</h3>
                    {expandedSections.map ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  <div className={`flex-1 relative ${!expandedSections.map && 'hidden'}`}>
                    <div id="neighborhood-map" className="w-full h-full"></div>
                  </div>
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('hotels')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><Hotel size={24} className="text-amber-500" />Hotels</h3>
                    {expandedSections.hotels ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.hotels && (
                    <div className="p-6 space-y-4">
                      {results.accommodations && results.accommodations.map((hotel: any, i: number) => (
                        <div key={i} className="p-4 rounded-2xl bg-slate-50 border border-slate-100 hover:border-amber-400 transition-all cursor-pointer group">
                           <div className="flex justify-between items-start mb-2">
                              <h5 className="font-bold text-slate-800 group-hover:text-amber-600 transition-colors">{hotel.name}</h5>
                              <div className="flex items-center gap-1 text-amber-500 font-bold text-xs bg-amber-50 px-2 py-0.5 rounded-full"><span>{hotel.rating}</span><Sparkles size={10} fill="currentColor" /></div>
                           </div>
                           <div className="flex justify-between items-center text-sm"><span className="text-slate-500 italic">~${hotel.price}/night</span><span className="text-blue-600 font-bold text-xs">View Deal</span></div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {!results && !isPlanning && (
          <div className="flex flex-col items-center justify-center py-12 text-center opacity-30 select-none pointer-events-none">
            <div className="w-32 h-32 bg-slate-200 rounded-full flex items-center justify-center mb-6"><MapPin size={64} className="text-slate-400" /></div>
            <h3 className="text-2xl font-bold text-slate-400">Enter a trip to start planning</h3>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  ChevronDown, ChevronUp, CloudSun, Map as MapIcon, 
  Hotel, Briefcase, Sparkles, Send, Share2, Save,
  CheckCircle2, Info, AlertTriangle, X, Loader2, Zap
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { searchFlights } from './services/amadeusService';
import { TripPlan, WeatherDay, FlightOffer, Neighborhood, ItineraryDay } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 300 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
    weather: true,
    flights: true,
    itinerary: true,
    map: true,
    hotels: true
  });

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_trips');
    if (saved) setSavedTrips(JSON.parse(saved));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;

    setIsPlanning(true);
    setResults(null);
    setWeather(null);

    try {
      // 1. Concurrent fetching for speed
      const intelPromise = getTravelIntelligence({ origin, destination, startDate: dates.start, endDate: dates.end, additionalCities, budget });
      const geoPromise = geocodeCity(destination);
      const amadeusPromise = searchFlights(origin, destination, dates.start);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;

      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      // 2. Weather
      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, dates.start, dates.end);
      }

      // 3. Flight Logic: Prefer real-time Amadeus, fallback to Gemini estimates
      if (flightsData && flightsData.length > 0) {
        intelData.flights = flightsData;
        intelData.isRealFlights = true;
      } else {
        intelData.isRealFlights = false;
      }

      setResults(intelData);
      setWeather(weatherData);

      // Scroll to results and init map
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
    }
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;

    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }

    if (mapRef.current) {
      mapRef.current.remove();
    }

    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(map);

      if (neighborhoods && Array.isArray(neighborhoods)) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) {
            L.marker([n.lat, n.lng])
              .addTo(map)
              .bindPopup(`<b>${n.name || 'Neighborhood'}</b><br>${n.bestFor || ''}`);
          }
        });
      }

      mapRef.current = map;
    } catch (err) {
      console.error("Map Error:", err);
    }
  };

  const saveTrip = () => {
    const newTrip: TripPlan = {
      id: Math.random().toString(36).substr(2, 9),
      origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
      timestamp: Date.now()
    };
    const updated = [newTrip, ...savedTrips];
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const deleteTrip = (id: string) => {
    const updated = savedTrips.filter(t => t.id !== id);
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const shareTrip = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('dest', destination);
    url.searchParams.set('start', dates.start);
    url.searchParams.set('end', dates.end);
    navigator.clipboard.writeText(url.toString());
    alert("Share link copied!");
  };

  const convertTemp = (c: number) => {
    return tempUnit === 'C' ? Math.round(c) : Math.round((c * 9/5) + 32);
  };

  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50/30">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-600/20">
              <Sparkles size={22} fill="currentColor" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-r from-blue-700 to-indigo-600 bg-clip-text text-transparent">
              WanderGenius
            </h1>
          </div>
          <div className="flex items-center space-x-4">
             {savedTrips.length > 0 && (
               <div className="hidden md:flex items-center -space-x-2">
                 {savedTrips.slice(0, 3).map((t, i) => (
                   <div key={i} className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white flex items-center justify-center text-[10px] font-bold text-slate-600">
                     {t.destination.charAt(0)}
                   </div>
                 ))}
               </div>
             )}
          </div>
        </div>
      </nav>

      <section className="pt-12 pb-24 px-6">
        <div className="max-w-4xl mx-auto">
          <div className="text-center mb-12 space-y-4">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 leading-tight">
              Where to <span className="text-blue-600 underline decoration-blue-200 decoration-8 underline-offset-4">next?</span>
            </h2>
            <p className="text-slate-500 text-lg max-w-xl mx-auto">
              Live flight results via Amadeus API + Intelligent travel planning.
            </p>
          </div>

          <form onSubmit={handlePlanTrip} className="bg-white rounded-3xl p-8 shadow-2xl shadow-blue-900/5 border border-slate-100 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                  <MapPin size={16} className="text-blue-500" />
                  Route
                </label>
                <div className="space-y-3">
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Origin (e.g. NYC, London)" 
                      value={origin}
                      onChange={(e) => setOrigin(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <Plane size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  </div>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Destination (e.g. Tokyo, Paris)" 
                      value={destination}
                      onChange={(e) => setDestination(e.target.value)}
                      required
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <MapPin size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-500" />
                  </div>
                </div>
                <div className="pt-2">
                  <div className="flex gap-2 mb-3">
                    <input 
                      type="text" 
                      placeholder="Add stop..." 
                      value={newCity}
                      onChange={(e) => setNewCity(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                      className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <button type="button" onClick={handleAddCity} className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700">
                      <Plus size={20} />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {additionalCities.map((city, idx) => (
                      <span key={idx} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2 border border-blue-100">
                        {city}
                        <X size={14} className="cursor-pointer" onClick={() => setAdditionalCities(prev => prev.filter((_, i) => i !== idx))} />
                      </span>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <Calendar size={16} className="text-emerald-500" />
                    Timing
                  </label>
                  <div className="grid grid-cols-2 gap-3">
                    <input type="date" value={dates.start} onChange={(e) => setDates({...dates, start: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                    <input type="date" value={dates.end} onChange={(e) => setDates({...dates, end: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                  </div>
                </div>
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <DollarSign size={16} className="text-amber-500" />
                    Budget per night
                  </label>
                  <div className="flex items-center gap-4">
                    <input type="range" min="50" max="1000" step="50" value={budget.max} onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})} className="flex-1 accent-blue-600" />
                    <span className="text-sm font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">${budget.max}</span>
                  </div>
                </div>
              </div>
            </div>

            <button type="submit" disabled={isPlanning} className={`w-full py-5 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-600/30'}`}>
              {isPlanning ? <Loader2 size={24} className="animate-spin" /> : <Sparkles size={24} />}
              {isPlanning ? 'Analyzing real flights...' : 'Plan Trip with Live Data'}
            </button>
          </form>
        </div>
      </section>

      <div ref={resultsRef} className="max-w-6xl mx-auto px-6 pb-24 space-y-8">
        {results && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
            <div className={`mb-8 p-6 rounded-3xl border flex items-start gap-4 ${isRealistic ? 'bg-emerald-50 border-emerald-100 text-emerald-800' : 'bg-amber-50 border-amber-100 text-amber-800'}`}>
              {isRealistic ? <CheckCircle2 className="mt-1" /> : <AlertTriangle className="mt-1" />}
              <div className="flex-1">
                <h4 className="font-bold text-lg">Trip Feasibility</h4>
                <p className="text-sm opacity-90">{results.feasibility || "Analysis not available."}</p>
              </div>
              <div className="flex gap-2">
                <button onClick={saveTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm"><Save size={20} className="text-slate-700" /></button>
                <button onClick={shareTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm"><Share2 size={20} className="text-slate-700" /></button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('weather')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><CloudSun size={24} className="text-blue-500" />Weather Forecast</h3>
                    <div className="flex items-center gap-4">
                      <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('C')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'C' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°C</button>
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('F')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'F' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°F</button>
                      </div>
                      {expandedSections.weather ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </div>
                  </div>
                  {expandedSections.weather && (
                    <div className="p-8">
                      {weather ? (
                        <div className="grid grid-cols-2 md:grid-cols-7 gap-4">
                          {weather.daily.time.slice(0, 7).map((time: string, i: number) => (
                            <div key={i} className="flex flex-col items-center p-3 rounded-2xl bg-slate-50 text-center border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(time).toLocaleDateString('en-US', { weekday: 'short' })}</span>
                              <div className="my-2 text-2xl">{weather.daily.weathercode[i] < 3 ? '☀️' : weather.daily.weathercode[i] < 50 ? '☁️' : '🌧️'}</div>
                              <div className="text-sm font-bold text-slate-800">{convertTemp(weather.daily.temperature_2m_max[i])}°</div>
                            </div>
                          ))}
                        </div>
                      ) : <div className="text-center py-4 text-slate-400 italic">No forecast available.</div>}
                    </div>
                  )}
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('itinerary')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><Briefcase size={24} className="text-emerald-500" />Daily Itinerary</h3>
                    {expandedSections.itinerary ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.itinerary && (
                    <div className="p-8 space-y-8">
                      {results.itinerary && results.itinerary.map((day: ItineraryDay, i: number) => (
                        <div key={i} className="relative pl-12">
                          <div className="absolute left-0 top-0 w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center text-white text-xs font-bold shadow-lg shadow-emerald-500/20 z-10">{day.day}</div>
                          {i < results.itinerary.length - 1 && <div className="absolute left-4 top-8 bottom-[-2rem] w-0.5 bg-slate-100"></div>}
                          <div className="space-y-3">
                            <h4 className="font-extrabold text-lg text-slate-800">{day.title}</h4>
                            <ul className="space-y-2">
                              {day.activities && day.activities.map((act, idx) => (
                                <li key={idx} className="flex items-center gap-3 text-slate-600 text-sm"><div className="w-1.5 h-1.5 rounded-full bg-emerald-300"></div>{act}</li>
                              ))}
                            </ul>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              <div className="space-y-8">
                <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-xl">
                  <div className="p-6 border-b border-slate-800 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('flights')}>
                    <div className="flex flex-col">
                      <h3 className="text-xl font-bold text-white flex items-center gap-3"><Plane size={24} className="text-blue-400" />Flight Offers</h3>
                      {results.isRealFlights && (
                        <span className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1 flex items-center gap-1"><Zap size={10} fill="currentColor" /> Live Results via Amadeus API</span>
                      )}
                    </div>
                    {expandedSections.flights ? <ChevronUp size={20} className="text-slate-500" /> : <ChevronDown size={20} className="text-slate-500" />}
                  </div>
                  {expandedSections.flights && (
                    <div className="p-6 space-y-4">
                      {results.flights && results.flights.map((flight: FlightOffer & { isReal?: boolean }, i: number) => (
                        <div key={i} className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 hover:border-blue-500 transition-all group">
                          <div className="flex justify-between items-center mb-3">
                            <span className="text-blue-400 font-bold text-sm">{flight.airline}</span>
                            <span className="text-white font-extrabold">${flight.price}</span>
                          </div>
                          <div className="flex items-center gap-3 text-xs text-slate-400">
                             <div className="flex-1 text-right truncate">{flight.departure?.split('T')[0] || '-'}</div>
                             <div className="flex-1 h-px bg-slate-700 relative"><Plane size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-600" /></div>
                             <div className="flex-1 truncate">{flight.arrival?.split('T')[0] || '-'}</div>
                          </div>
                          <div className="mt-3 flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-500">
                             <span>{flight.duration}</span>
                             <span>{flight.stops === 0 ? 'Non-stop' : `${flight.stops} stop`}</span>
                          </div>
                        </div>
                      ))}
                      {!results.isRealFlights && results.flights?.length > 0 && (
                        <div className="p-3 bg-amber-900/20 border border-amber-900/50 rounded-xl text-[10px] text-amber-500 flex items-start gap-2 italic">
                          <Info size={12} className="mt-0.5 shrink-0" />
                          No live flights found for this route. Showing estimated costs based on historical data.
                        </div>
                      )}
                      <div className="pt-2"><a href={`https://www.google.com/travel/flights?q=Flights%20from%20${origin}%20to%20${destination}%20on%20${dates.start}`} target="_blank" className="block text-center py-3 rounded-xl bg-blue-600 text-white font-bold text-sm hover:bg-blue-500 transition-colors shadow-lg shadow-blue-600/20">Verify on Google Flights</a></div>
                    </div>
                  )}
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm h-[400px] flex flex-col">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('map')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><MapIcon size={24} className="text-purple-500" />Neighborhoods</h3>
                    {expandedSections.map ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  <div className={`flex-1 relative ${!expandedSections.map && 'hidden'}`}>
                    <div id="neighborhood-map" className="w-full h-full"></div>
                    {results.neighborhoods && results.neighborhoods.length > 0 && (
                      <div className="absolute bottom-4 left-4 right-4 bg-white/90 backdrop-blur-md p-4 rounded-3xl border border-slate-200 z-[1000] text-xs shadow-2xl max-h-[140px] overflow-y-auto custom-scrollbar">
                         <p className="font-bold mb-2 text-slate-900 uppercase tracking-widest text-[10px]">Recommended Areas</p>
                         <div className="space-y-2">
                           {results.neighborhoods.map((n: Neighborhood, i: number) => (
                             <div key={i} className="flex justify-between items-center gap-4">
                               <div className="flex flex-col">
                                 <span className="font-bold text-slate-800">{n.name}</span>
                                 <span className="text-[10px] text-slate-500 line-clamp-1">{n.description}</span>
                               </div>
                               <span className="shrink-0 px-2 py-0.5 rounded-full bg-purple-100 text-purple-700 font-extrabold uppercase text-[9px]">
                                 {n.bestFor}
                               </span>
                             </div>
                           ))}
                         </div>
                      </div>
                    )}
                  </div>
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('hotels')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><Hotel size={24} className="text-amber-500" />Hotels</h3>
                    {expandedSections.hotels ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.hotels && (
                    <div className="p-6 space-y-4">
                      {results.accommodations && results.accommodations.map((hotel: any, i: number) => (
                        <div key={i} className="p-4 rounded-2xl bg-slate-50 border border-slate-100 hover:border-amber-400 transition-all cursor-pointer group">
                           <div className="flex justify-between items-start mb-2">
                              <h5 className="font-bold text-slate-800 group-hover:text-amber-600 transition-colors">{hotel.name}</h5>
                              <div className="flex items-center gap-1 text-amber-500 font-bold text-xs bg-amber-50 px-2 py-0.5 rounded-full"><span>{hotel.rating}</span><Sparkles size={10} fill="currentColor" /></div>
                           </div>
                           <div className="flex justify-between items-center text-sm"><span className="text-slate-500 italic">~${hotel.price}/night</span><span className="text-blue-600 font-bold text-xs">View Deal</span></div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {!results && !isPlanning && (
          <div className="flex flex-col items-center justify-center py-12 text-center opacity-30 select-none pointer-events-none">
            <div className="w-32 h-32 bg-slate-200 rounded-full flex items-center justify-center mb-6"><MapPin size={64} className="text-slate-400" /></div>
            <h3 className="text-2xl font-bold text-slate-400">Enter a trip to start planning</h3>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  ChevronDown, ChevronUp, CloudSun, Map as MapIcon, 
  Hotel, Briefcase, Sparkles, Send, Share2, Save,
  CheckCircle2, Info, AlertTriangle, X, Loader2, Zap,
  Search, ExternalLink
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { searchFlights } from './services/amadeusService';
import { TripPlan, WeatherDay, FlightOffer, Neighborhood, ItineraryDay } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 300 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
    weather: true,
    flights: true,
    itinerary: true,
    map: true,
    hotels: true
  });

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_trips');
    if (saved) setSavedTrips(JSON.parse(saved));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setWeather(null);

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const amadeusPromise = searchFlights(originVal, destVal, startVal);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, startVal, endVal);
      }

      if (flightsData && flightsData.length > 0) {
        intelData.flights = flightsData;
        intelData.isRealFlights = true;
      } else {
        intelData.isRealFlights = false;
      }

      setResults(intelData);
      setWeather(weatherData);

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const loadSavedTrip = (trip: TripPlan) => {
    setOrigin(trip.origin);
    setDestination(trip.destination);
    setDates({ start: trip.startDate, end: trip.endDate });
    setBudget(trip.budget);
    setAdditionalCities(trip.additionalCities);
    executePlan(trip.origin, trip.destination, trip.startDate, trip.endDate, trip.additionalCities, trip.budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;

    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }

    if (mapRef.current) {
      mapRef.current.remove();
    }

    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(map);

      if (neighborhoods && Array.isArray(neighborhoods)) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) {
            L.marker([n.lat, n.lng])
              .addTo(map)
              .bindPopup(`<b>${n.name || 'Neighborhood'}</b><br>${n.bestFor || ''}`);
          }
        });
      }

      mapRef.current = map;
    } catch (err) {
      console.error("Map Error:", err);
    }
  };

  const saveTrip = () => {
    const newTrip: TripPlan = {
      id: Math.random().toString(36).substr(2, 9),
      origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
      timestamp: Date.now()
    };
    const updated = [newTrip, ...savedTrips.filter(t => t.destination !== destination)];
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const deleteTrip = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = savedTrips.filter(t => t.id !== id);
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const shareTrip = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('dest', destination);
    url.searchParams.set('start', dates.start);
    url.searchParams.set('end', dates.end);
    navigator.clipboard.writeText(url.toString());
    alert("Share link copied!");
  };

  const convertTemp = (c: number) => {
    return tempUnit === 'C' ? Math.round(c) : Math.round((c * 9/5) + 32);
  };

  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  // Helper for flight deep links
  const getFlightUrl = (provider: 'google' | 'skyscanner' | 'kayak') => {
    const o = origin || 'any';
    const d = destination;
    const s = dates.start;

    if (provider === 'google') return `https://www.google.com/travel/flights?q=Flights%20from%20${o}%20to%20${d}%20on%20${s}`;
    if (provider === 'skyscanner') return `https://www.skyscanner.net/transport/flights/${o}/${d}/${s}`;
    if (provider === 'kayak') return `https://www.kayak.com/flights/${o}-${d}/${s}`;
    return '#';
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50/30">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-600/20">
              <Sparkles size={22} fill="currentColor" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-r from-blue-700 to-indigo-600 bg-clip-text text-transparent">
              WanderGenius
            </h1>
          </div>
          <div className="flex items-center space-x-4">
             {savedTrips.length > 0 && (
               <div className="hidden md:flex items-center -space-x-2">
                 {savedTrips.slice(0, 5).map((t, i) => (
                   <button 
                    key={t.id} 
                    onClick={() => loadSavedTrip(t)}
                    title={`Reload ${t.destination}`}
                    className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white flex items-center justify-center text-[10px] font-bold text-slate-600 hover:scale-110 transition-transform hover:z-10"
                   >
                     {t.destination.charAt(0)}
                   </button>
                 ))}
               </div>
             )}
          </div>
        </div>
      </nav>

      <section className="pt-12 pb-12 px-6">
        <div className="max-w-4xl mx-auto">
          <div className="text-center mb-12 space-y-4">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 leading-tight">
              Where to <span className="text-blue-600 underline decoration-blue-200 decoration-8 underline-offset-4">next?</span>
            </h2>
            <p className="text-slate-500 text-lg max-w-xl mx-auto">
              Live flight results via Amadeus API + Intelligent travel planning.
            </p>
          </div>

          <form onSubmit={handlePlanTrip} className="bg-white rounded-3xl p-8 shadow-2xl shadow-blue-900/5 border border-slate-100 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                  <MapPin size={16} className="text-blue-500" />
                  Route
                </label>
                <div className="space-y-3">
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Origin (e.g. NYC, London)" 
                      value={origin}
                      onChange={(e) => setOrigin(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <Plane size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  </div>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Destination (e.g. Tokyo, Paris)" 
                      value={destination}
                      onChange={(e) => setDestination(e.target.value)}
                      required
                      className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <MapPin size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-500" />
                  </div>
                </div>
                <div className="pt-2">
                  <div className="flex gap-2 mb-3">
                    <input 
                      type="text" 
                      placeholder="Add stop..." 
                      value={newCity}
                      onChange={(e) => setNewCity(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                      className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <button type="button" onClick={handleAddCity} className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700">
                      <Plus size={20} />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {additionalCities.map((city, idx) => (
                      <span key={idx} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2 border border-blue-100">
                        {city}
                        <X size={14} className="cursor-pointer" onClick={() => setAdditionalCities(prev => prev.filter((_, i) => i !== idx))} />
                      </span>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <Calendar size={16} className="text-emerald-500" />
                    Timing
                  </label>
                  <div className="grid grid-cols-2 gap-3">
                    <input type="date" value={dates.start} onChange={(e) => setDates({...dates, start: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                    <input type="date" value={dates.end} onChange={(e) => setDates({...dates, end: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                  </div>
                </div>
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <DollarSign size={16} className="text-amber-500" />
                    Budget per night
                  </label>
                  <div className="flex items-center gap-4">
                    <input type="range" min="50" max="1000" step="50" value={budget.max} onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})} className="flex-1 accent-blue-600" />
                    <span className="text-sm font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">${budget.max}</span>
                  </div>
                </div>
              </div>
            </div>

            <button type="submit" disabled={isPlanning} className={`w-full py-5 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-600/30'}`}>
              {isPlanning ? <Loader2 size={24} className="animate-spin" /> : <Sparkles size={24} />}
              {isPlanning ? 'Analyzing real flights...' : 'Plan Trip with Live Data'}
            </button>
          </form>

          {savedTrips.length > 0 && (
            <div className="mt-12 space-y-4">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Recent & Saved Journeys</h3>
              <div className="flex gap-4 overflow-x-auto pb-4 px-2 custom-scrollbar">
                {savedTrips.map((trip) => (
                  <button 
                    key={trip.id} 
                    onClick={() => loadSavedTrip(trip)}
                    className="shrink-0 w-48 bg-white p-5 rounded-3xl border border-slate-200 text-left hover:border-blue-500 hover:shadow-lg transition-all group relative"
                  >
                    <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-600 mb-3 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                      <MapPin size={20} />
                    </div>
                    <h4 className="font-bold text-slate-800 line-clamp-1">{trip.destination}</h4>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter mt-1">{new Date(trip.startDate).toLocaleDateString(undefined, {month: 'short', day: 'numeric'})} • {trip.origin || 'Nearby'}</p>
                    <div onClick={(e) => deleteTrip(e, trip.id)} className="absolute top-4 right-4 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                      <Trash2 size={16} />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </section>

      <div ref={resultsRef} className="max-w-6xl mx-auto px-6 pb-24 space-y-8">
        {results && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
            <div className={`mb-8 p-6 rounded-3xl border flex items-start gap-4 ${isRealistic ? 'bg-emerald-50 border-emerald-100 text-emerald-800' : 'bg-amber-50 border-amber-100 text-amber-800'}`}>
              {isRealistic ? <CheckCircle2 className="mt-1" /> : <AlertTriangle className="mt-1" />}
              <div className="flex-1">
                <h4 className="font-bold text-lg">Trip Feasibility</h4>
                <p className="text-sm opacity-90">{results.feasibility || "Analysis not available."}</p>
              </div>
              <div className="flex gap-2">
                <button onClick={saveTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm flex items-center gap-2 font-bold text-xs"><Save size={20} /> Save Trip</button>
                <button onClick={shareTrip} className="p-3 bg-white/50 rounded-2xl hover:bg-white transition-all shadow-sm"><Share2 size={20} /></button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('weather')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><CloudSun size={24} className="text-blue-500" />Weather Forecast</h3>
                    <div className="flex items-center gap-4">
                      <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('C')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'C' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°C</button>
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('F')}} className={`px-2 py-0.5 rounded-md text-xs font-bold ${tempUnit === 'F' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>°F</button>
                      </div>
                      {expandedSections.weather ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </div>
                  </div>
                  {expandedSections.weather && (
                    <div className="p-8">
                      {weather ? (
                        <div className="grid grid-cols-2 md:grid-cols-7 gap-4">
                          {weather.daily.time.slice(0, 7).map((time: string, i: number) => (
                            <div key={i} className="flex flex-col items-center p-3 rounded-2xl bg-slate-50 text-center border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(time).toLocaleDateString('en-US', { weekday: 'short' })}</span>
                              <div className="my-2 text-2xl">{weather.daily.weathercode[i] < 3 ? '☀️' : weather.daily.weathercode[i] < 50 ? '☁️' : '🌧️'}</div>
                              <div className="text-sm font-bold text-slate-800">{convertTemp(weather.daily.temperature_2m_max[i])}°</div>
                            </div>
                          ))}
                        </div>
                      ) : <div className="text-center py-4 text-slate-400 italic">No forecast available.</div>}
                    </div>
                  )}
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('itinerary')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><Briefcase size={24} className="text-emerald-500" />Daily Itinerary</h3>
                    {expandedSections.itinerary ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.itinerary && (
                    <div className="p-8 space-y-8">
                      {results.itinerary && results.itinerary.map((day: ItineraryDay, i: number) => (
                        <div key={i} className="relative pl-12">
                          <div className="absolute left-0 top-0 w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center text-white text-xs font-bold shadow-lg shadow-emerald-500/20 z-10">{day.day}</div>
                          {i < results.itinerary.length - 1 && <div className="absolute left-4 top-8 bottom-[-2rem] w-0.5 bg-slate-100"></div>}
                          <div className="space-y-3">
                            <h4 className="font-extrabold text-lg text-slate-800">{day.title}</h4>
                            <ul className="space-y-2">
                              {day.activities && day.activities.map((act, idx) => (
                                <li key={idx} className="flex items-center gap-3 text-slate-600 text-sm"><div className="w-1.5 h-1.5 rounded-full bg-emerald-300"></div>{act}</li>
                              ))}
                            </ul>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              <div className="space-y-8">
                <div className="bg-[#1e293b] rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-xl">
                  <div className="p-6 border-b border-slate-800 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('flights')}>
                    <div className="flex flex-col">
                      <h3 className="text-xl font-bold text-white flex items-center gap-3"><Plane size={24} className="text-blue-400" />Flight Offers</h3>
                      {results.isRealFlights && (
                        <span className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1 flex items-center gap-1"><Zap size={10} fill="currentColor" /> Live Results via Amadeus API</span>
                      )}
                    </div>
                    {expandedSections.flights ? <ChevronUp size={20} className="text-slate-500" /> : <ChevronDown size={20} className="text-slate-500" />}
                  </div>
                  {expandedSections.flights && (
                    <div className="p-6 space-y-6">
                      <div className="space-y-4">
                        {results.flights && results.flights.map((flight: FlightOffer & { isReal?: boolean }, i: number) => (
                          <div key={i} className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 hover:border-blue-500 transition-all group">
                            <div className="flex justify-between items-center mb-3">
                              <span className="text-blue-400 font-bold text-sm">{flight.airline}</span>
                              <span className="text-white font-extrabold">${flight.price}</span>
                            </div>
                            <div className="flex items-center gap-3 text-xs text-slate-400">
                               <div className="flex-1 text-right truncate">{flight.departure?.split('T')[0] || '-'}</div>
                               <div className="flex-1 h-px bg-slate-700 relative"><Plane size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-600" /></div>
                               <div className="flex-1 truncate">{flight.arrival?.split('T')[0] || '-'}</div>
                            </div>
                            <div className="mt-3 flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-500">
                               <span>{flight.duration}</span>
                               <span>{flight.stops === 0 ? 'Non-stop' : `${flight.stops} stop`}</span>
                            </div>
                          </div>
                        ))}
                      </div>

                      <div className="pt-4 border-t border-slate-800">
                        <p className="text-[11px] font-bold text-slate-500 uppercase tracking-widest mb-4">Compare prices on other sites:</p>
                        <div className="grid grid-cols-3 gap-2">
                           <a href={getFlightUrl('google')} target="_blank" className="flex flex-col items-center justify-center p-4 bg-slate-800/80 rounded-2xl border border-slate-700 hover:bg-slate-700 hover:border-blue-500 transition-all gap-2 text-center group">
                              <span className="text-xl group-hover:scale-110 transition-transform">✈️</span>
                              <span className="text-[10px] font-bold text-slate-300">Google Flights</span>
                           </a>
                           <a href={getFlightUrl('skyscanner')} target="_blank" className="flex flex-col items-center justify-center p-4 bg-slate-800/80 rounded-2xl border border-slate-700 hover:bg-slate-700 hover:border-blue-500 transition-all gap-2 text-center group">
                              <span className="text-xl group-hover:scale-110 transition-transform">🔍</span>
                              <span className="text-[10px] font-bold text-slate-300">Skyscanner</span>
                           </a>
                           <a href={getFlightUrl('kayak')} target="_blank" className="flex flex-col items-center justify-center p-4 bg-slate-800/80 rounded-2xl border border-slate-700 hover:bg-slate-700 hover:border-blue-500 transition-all gap-2 text-center group">
                              <span className="text-xl group-hover:scale-110 transition-transform">🛫</span>
                              <span className="text-[10px] font-bold text-slate-300">Kayak</span>
                           </a>
                        </div>
                      </div>

                      {!results.isRealFlights && results.flights?.length > 0 && (
                        <div className="p-3 bg-amber-900/20 border border-amber-900/50 rounded-xl text-[10px] text-amber-500 flex items-start gap-2 italic">
                          <Info size={12} className="mt-0.5 shrink-0" />
                          No live flights found for this route. Showing estimated costs based on historical data.
                        </div>
                      )}
                    </div>
                  )}
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm h-[400px] flex flex-col">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('map')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><MapIcon size={24} className="text-purple-500" />Neighborhoods</h3>
                    {expandedSections.map ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  <div className={`flex-1 relative ${!expandedSections.map && 'hidden'}`}>
                    <div id="neighborhood-map" className="w-full h-full"></div>
                    {results.neighborhoods && results.neighborhoods.length > 0 && (
                      <div className="absolute bottom-4 left-4 right-4 bg-white/90 backdrop-blur-md p-4 rounded-3xl border border-slate-200 z-[1000] text-xs shadow-2xl max-h-[140px] overflow-y-auto custom-scrollbar">
                         <p className="font-bold mb-2 text-slate-900 uppercase tracking-widest text-[10px]">Recommended Areas</p>
                         <div className="space-y-2">
                           {results.neighborhoods.map((n: Neighborhood, i: number) => (
                             <div key={i} className="flex justify-between items-center gap-4">
                               <div className="flex flex-col">
                                 <span className="font-bold text-slate-800">{n.name}</span>
                                 <span className="text-[10px] text-slate-500 line-clamp-1">{n.description}</span>
                               </div>
                               <span className="shrink-0 px-2 py-0.5 rounded-full bg-purple-100 text-purple-700 font-extrabold uppercase text-[9px]">
                                 {n.bestFor}
                               </span>
                             </div>
                           ))}
                         </div>
                      </div>
                    )}
                  </div>
                </div>

                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-6 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('hotels')}>
                    <h3 className="text-xl font-bold flex items-center gap-3"><Hotel size={24} className="text-amber-500" />Hotels</h3>
                    {expandedSections.hotels ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </div>
                  {expandedSections.hotels && (
                    <div className="p-6 space-y-4">
                      {results.accommodations && results.accommodations.map((hotel: any, i: number) => (
                        <div key={i} className="p-4 rounded-2xl bg-slate-50 border border-slate-100 hover:border-amber-400 transition-all cursor-pointer group">
                           <div className="flex justify-between items-start mb-2">
                              <h5 className="font-bold text-slate-800 group-hover:text-amber-600 transition-colors">{hotel.name}</h5>
                              <div className="flex items-center gap-1 text-amber-500 font-bold text-xs bg-amber-50 px-2 py-0.5 rounded-full"><span>{hotel.rating}</span><Sparkles size={10} fill="currentColor" /></div>
                           </div>
                           <div className="flex justify-between items-center text-sm"><span className="text-slate-500 italic">~${hotel.price}/night</span><span className="text-blue-600 font-bold text-xs">View Deal</span></div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {!results && !isPlanning && (
          <div className="flex flex-col items-center justify-center py-12 text-center opacity-30 select-none pointer-events-none">
            <div className="w-32 h-32 bg-slate-200 rounded-full flex items-center justify-center mb-6"><MapPin size={64} className="text-slate-400" /></div>
            <h3 className="text-2xl font-bold text-slate-400">Enter a trip to start planning</h3>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  ChevronDown, ChevronUp, CloudSun, Map as MapIcon, 
  Hotel, Briefcase, Sparkles, Send, Share2, Save,
  CheckCircle2, Info, AlertTriangle, X, Loader2, Zap,
  Search, Clock, History
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { searchFlights } from './services/amadeusService';
import { TripPlan, WeatherDay, FlightOffer, Neighborhood, ItineraryDay } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 300 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
    weather: true,
    flights: true,
    itinerary: true,
    map: true,
    hotels: true
  });

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  // Load saved trips on mount
  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_trips');
    if (saved) {
      try {
        setSavedTrips(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved trips", e);
      }
    }

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setWeather(null);

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const amadeusPromise = searchFlights(originVal, destVal, startVal);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, startVal, endVal);
      }

      if (flightsData && flightsData.length > 0) {
        intelData.flights = flightsData;
        intelData.isRealFlights = true;
      } else {
        intelData.isRealFlights = false;
      }

      setResults(intelData);
      setWeather(weatherData);

      // AUTO-SAVE to Recents on success
      const recentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal,
        destination: destVal,
        startDate: startVal,
        endDate: endVal,
        budget: budgetVal,
        additionalCities: additionalVal,
        timestamp: Date.now()
      };

      setSavedTrips(prev => {
        // Filter out same destination to keep list clean, then take top 8
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [recentTrip, ...filtered].slice(0, 10);
        localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
        return updated;
      });

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const loadSavedTrip = (trip: TripPlan) => {
    setOrigin(trip.origin);
    setDestination(trip.destination);
    setDates({ start: trip.startDate, end: trip.endDate });
    setBudget(trip.budget);
    setAdditionalCities(trip.additionalCities);
    // Directly re-execute
    executePlan(trip.origin, trip.destination, trip.startDate, trip.endDate, trip.additionalCities, trip.budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;

    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }

    if (mapRef.current) {
      mapRef.current.remove();
    }

    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(map);

      if (neighborhoods && Array.isArray(neighborhoods)) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) {
            L.marker([n.lat, n.lng])
              .addTo(map)
              .bindPopup(`<b>${n.name || 'Neighborhood'}</b><br>${n.bestFor || ''}`);
          }
        });
      }

      mapRef.current = map;
    } catch (err) {
      console.error("Map Error:", err);
    }
  };

  const deleteTrip = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = savedTrips.filter(t => t.id !== id);
    setSavedTrips(updated);
    localStorage.setItem('wandergenius_trips', JSON.stringify(updated));
  };

  const shareTrip = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('dest', destination);
    url.searchParams.set('start', dates.start);
    url.searchParams.set('end', dates.end);
    navigator.clipboard.writeText(url.toString());
    alert("Share link copied!");
  };

  const convertTemp = (c: number) => {
    return tempUnit === 'C' ? Math.round(c) : Math.round((c * 9/5) + 32);
  };

  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  const getFlightUrl = (provider: 'google' | 'skyscanner' | 'kayak') => {
    const o = origin || 'any';
    const d = destination;
    const s = dates.start;
    if (provider === 'google') return `https://www.google.com/travel/flights?q=Flights%20from%20${o}%20to%20${d}%20on%20${s}`;
    if (provider === 'skyscanner') return `https://www.skyscanner.net/transport/flights/${o}/${d}/${s}`;
    if (provider === 'kayak') return `https://www.kayak.com/flights/${o}-${d}/${s}`;
    return '#';
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50/30">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-600/20">
              <Sparkles size={22} fill="currentColor" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-r from-blue-700 to-indigo-600 bg-clip-text text-transparent">
              WanderGenius
            </h1>
          </div>
          <div className="flex items-center space-x-4">
             {savedTrips.length > 0 && (
               <div className="hidden md:flex items-center gap-1">
                 <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mr-2">Quick Access:</span>
                 <div className="flex -space-x-2">
                    {savedTrips.slice(0, 5).map((t) => (
                      <button 
                        key={t.id} 
                        onClick={() => loadSavedTrip(t)}
                        title={`Reload ${t.destination}`}
                        className="w-8 h-8 rounded-full bg-white border-2 border-slate-100 flex items-center justify-center text-[10px] font-bold text-blue-600 hover:scale-110 transition-transform hover:z-10 shadow-sm"
                      >
                        {t.destination.charAt(0)}
                      </button>
                    ))}
                 </div>
               </div>
             )}
          </div>
        </div>
      </nav>

      <section className="pt-12 pb-12 px-6">
        <div className="max-w-4xl mx-auto space-y-12">

          {/* Dashboard Start: Saved Journeys Header */}
          {savedTrips.length > 0 && (
            <div className="animate-in fade-in slide-in-from-top-4 duration-700">
              <div className="flex items-center justify-between mb-6 px-2">
                <h3 className="text-sm font-extrabold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                  <History size={18} className="text-blue-500" />
                  Your Journeys
                </h3>
                <span className="text-[10px] font-bold text-slate-400 uppercase">Last 10 Searches</span>
              </div>
              <div className="flex gap-5 overflow-x-auto pb-6 px-2 custom-scrollbar snap-x">
                {savedTrips.map((trip) => (
                  <button 
                    key={trip.id} 
                    onClick={() => loadSavedTrip(trip)}
                    className="snap-start shrink-0 w-64 bg-white p-6 rounded-[2rem] border border-slate-200 text-left hover:border-blue-500 hover:shadow-2xl hover:shadow-blue-900/10 transition-all group relative overflow-hidden"
                  >
                    <div className="absolute top-0 right-0 w-24 h-24 bg-blue-50/50 rounded-full -mr-10 -mt-10 group-hover:bg-blue-100 transition-colors"></div>
                    <div className="relative">
                      <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 mb-4 group-hover:bg-blue-600 group-hover:text-white transition-all group-hover:scale-110">
                        <MapPin size={24} />
                      </div>
                      <h4 className="font-bold text-slate-900 text-lg mb-1 truncate">{trip.destination}</h4>
                      <div className="flex items-center gap-2 text-slate-500 mb-4 text-xs">
                        <Clock size={12} />
                        <span>{new Date(trip.timestamp).toLocaleDateString()}</span>
                      </div>
                      <div className="flex items-center justify-between mt-auto">
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
                          {trip.origin || 'Nearby'} → {new Date(trip.startDate).toLocaleDateString(undefined, {month: 'short', day: 'numeric'})}
                        </div>
                        <div onClick={(e) => deleteTrip(e, trip.id)} className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100">
                          <Trash2 size={16} />
                        </div>
                      </div>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="text-center space-y-4">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 leading-tight">
              Where to <span className="text-blue-600 underline decoration-blue-200 decoration-8 underline-offset-4">next?</span>
            </h2>
            <p className="text-slate-500 text-lg max-w-xl mx-auto">
              Live flight results via Amadeus API + Intelligent travel planning.
            </p>
          </div>

          <form onSubmit={handlePlanTrip} className="bg-white rounded-[2.5rem] p-10 shadow-2xl shadow-blue-900/5 border border-slate-100 space-y-8 relative z-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                  <MapPin size={16} className="text-blue-500" />
                  Route
                </label>
                <div className="space-y-4">
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Origin (e.g. NYC, London)" 
                      value={origin}
                      onChange={(e) => setOrigin(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-[1.5rem] py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                    />
                    <Plane size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  </div>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Destination (e.g. Tokyo, Paris)" 
                      value={destination}
                      onChange={(e) => setDestination(e.target.value)}
                      required
                      className="w-full bg-slate-50 border border-slate-200 rounded-[1.5rem] py-4 pl-12 pr-4 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none font-semibold text-slate-800"
                    />
                    <MapPin size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-500" />
                  </div>
                </div>
                <div className="pt-2">
                  <div className="flex gap-2 mb-3">
                    <input 
                      type="text" 
                      placeholder="Add stop (optional)..." 
                      value={newCity}
                      onChange={(e) => setNewCity(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                      className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <button type="button" onClick={handleAddCity} className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors">
                      <Plus size={20} />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {additionalCities.map((city, idx) => (
                      <span key={idx} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2 border border-blue-100">
                        {city}
                        <X size={14} className="cursor-pointer hover:text-red-500" onClick={() => setAdditionalCities(prev => prev.filter((_, i) => i !== idx))} />
                      </span>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-8">
                <div className="space-y-6">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <Calendar size={16} className="text-emerald-500" />
                    Timing
                  </label>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <span className="text-[10px] font-bold text-slate-400 uppercase px-1">Departure</span>
                      <input type="date" value={dates.start} onChange={(e) => setDates({...dates, start: e.target.value})} required className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                    </div>
                    <div className="space-y-2">
                      <span className="text-[10px] font-bold text-slate-400 uppercase px-1">Return</span>
                      <input type="date" value={dates.end} onChange={(e) => setDates({...dates, end: e.target.value})} required className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:border-blue-500 outline-none" />
                    </div>
                  </div>
                </div>
                <div className="space-y-6">
                  <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <DollarSign size={16} className="text-amber-500" />
                    Budget per night
                  </label>
                  <div className="space-y-4">
                    <div className="flex items-center gap-4">
                      <input type="range" min="50" max="1000" step="50" value={budget.max} onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})} className="flex-1 accent-blue-600" />
                      <span className="text-sm font-bold text-slate-700 bg-slate-100 px-4 py-2 rounded-xl border border-slate-200">${budget.max}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <button 
              type="submit" 
              disabled={isPlanning} 
              className={`w-full py-6 rounded-[1.5rem] font-bold text-lg flex items-center justify-center gap-3 transition-all ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-2xl shadow-blue-600/30 active:scale-[0.99]'}`}
            >
              {isPlanning ? <Loader2 size={24} className="animate-spin" /> : <Sparkles size={24} />}
              {isPlanning ? 'Analyzing real flights...' : 'Plan Trip with Live Data'}
            </button>
          </form>
        </div>
      </section>

      <div ref={resultsRef} className="max-w-6xl mx-auto px-6 pb-24 space-y-12">
        {results && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
            <div className={`mb-8 p-8 rounded-[2rem] border flex items-start gap-6 ${isRealistic ? 'bg-emerald-50 border-emerald-100 text-emerald-800' : 'bg-amber-50 border-amber-100 text-amber-800 shadow-lg shadow-amber-900/5'}`}>
              <div className={`p-4 rounded-2xl ${isRealistic ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'} shadow-lg shadow-current/20`}>
                {isRealistic ? <CheckCircle2 size={24} /> : <AlertTriangle size={24} />}
              </div>
              <div className="flex-1">
                <h4 className="font-extrabold text-xl mb-1">Trip Feasibility</h4>
                <p className="text-sm opacity-90 leading-relaxed font-medium">{results.feasibility || "Analysis not available."}</p>
              </div>
              <div className="flex gap-3">
                <button onClick={shareTrip} className="p-4 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all shadow-sm"><Share2 size={20} className="text-slate-600" /></button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
              <div className="lg:col-span-2 space-y-10">
                <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-8 border-b border-slate-100 flex items-center justify-between cursor-pointer" onClick={() => toggleSection('weather')}>
                    <h3 className="text-2xl font-extrabold flex items-center gap-4"><CloudSun size={28} className="text-blue-500" />Weather Forecast</h3>
                    <div className="flex items-center gap-6">
                      <div className="flex bg-slate-100 p-1 rounded-xl">
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('C')}} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${tempUnit === 'C' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>°C</button>
                        <button onClick={(e) => {e.stopPropagation(); setTempUnit('F')}} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${tempUnit === 'F' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>°F</button>
                      </div>
                      {expandedSections.weather ? <ChevronUp size={24} className="text-slate-400" /> : <ChevronDown size={24} className="text-slate-400" />}
                    </div>
                  </div>
                  {expandedSections.weather && (
                    <div className="p-10">
                      {weather ? (
                        <div className="grid grid-cols-2 md:grid-cols-7 gap-6">
                          {weather.daily.time.slice(0, 7).map((time: string, i: number) => (
                            <div key={i} className="flex flex-col items-center p-5 rounded-[1.5rem] bg-slate-50 text-center border border-slate-100 hover:border-blue-200 transition-all">
                              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mb-2">{new Date(time).toLocaleDateString('en-US', { weekday: 'short' })}</span>
                              <div className="my-3 text-3xl">{weather.daily.weathercode[i] < 3 ? '☀️' : weather.daily.weathercode[i] < 50 ? '☁️' : '🌧️'}</div>
                              <div className="text-lg font-extrabold text-slate-800">{convertTemp(weather.daily.temperature_2m_max[i])}°</div>
