                  className={`p-4 rounded-2xl transition-all shadow-sm flex items-center gap-2 font-bold text-sm ${isTripSaved ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                >
                  {isTripSaved ? <Bookmark size={20} fill="currentColor" /> : <Save size={20} />}
                  {isTripSaved ? 'Saved' : 'Save Trip'}
                </button>
