    try {
      // 1. Get Intelligence & Geocode
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const amadeusFlightsPromise = searchFlights(originVal, destVal, startVal);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusFlightsPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      // 2. Multi-Step Tool: Get Real Hotels for the Neighborhoods Suggestion
