      const currentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, budget: budgetVal, additionalCities: additionalVal,
        timestamp: Date.now()
      };
      setRecentSearches(prev => {
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [currentTrip, ...filtered].slice(0, 5);
        localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
        return updated;
      });

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Agentic planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
      setPlanningStep('');
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const loadTrip = (trip: TripPlan) => {
    setOrigin(trip.origin);
    setDestination(trip.destination);
    setDates({ start: trip.startDate, end: trip.endDate });
    setBudget(trip.budget);
    setAdditionalCities(trip.additionalCities);
    executePlan(trip.origin, trip.destination, trip.startDate, trip.endDate, trip.additionalCities, trip.budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;
    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }
    if (mapRef.current) mapRef.current.remove();
    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '&copy; OpenStreetMap' }).addTo(map);
      if (neighborhoods) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) L.marker([n.lat, n.lng]).addTo(map).bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
        });
      }
      mapRef.current = map;
    } catch (err) { console.error(err); }
  };

  const toggleSaveTrip = () => {
    if (!destination) return;
    const isAlreadySaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
    if (isAlreadySaved) {
      const updated = savedTrips.filter(t => t.destination.toLowerCase() !== destination.toLowerCase());
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const newSaved: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
        timestamp: Date.now()
      };
      setSavedTrips([newSaved, ...savedTrips]);
      localStorage.setItem('wandergenius_saved', JSON.stringify([newSaved, ...savedTrips]));
    }
  };

  const deleteFromHistory = (e: React.MouseEvent, id: string, list: 'saved' | 'recent') => {
    e.stopPropagation();
    if (list === 'saved') {
      const updated = savedTrips.filter(t => t.id !== id);
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const updated = recentSearches.filter(t => t.id !== id);
      setRecentSearches(updated);
      localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
    }
  };

  const isTripSaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50/30">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-600/20">
              <Sparkles size={22} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-r from-blue-700 to-indigo-600 bg-clip-text text-transparent leading-none">
                WanderGenius
              </h1>
              <span className="text-[8px] font-bold uppercase text-slate-400 tracking-tighter">Agentic Travel Engine</span>
            </div>
          </div>
        </div>
      </nav>

      <section className="pt-12 pb-12 px-6">
        <div className="max-w-4xl mx-auto space-y-12">

          {/* History Header */}
          {(savedTrips.length > 0 || recentSearches.length > 0) && (
            <div className="animate-in fade-in slide-in-from-top-4 duration-700 space-y-8">
              {savedTrips.length > 0 && (
                <div>
                  <h3 className="text-xs font-black text-indigo-600 uppercase tracking-[0.2em] flex items-center gap-2 mb-4 px-2">
                    <Bookmark size={14} className="fill-current" />
                    Saved Destinations
                  </h3>
                  <div className="flex gap-4 overflow-x-auto pb-4 px-2 custom-scrollbar snap-x">
                    {savedTrips.map((trip) => (
                      <button key={trip.id} onClick={() => loadTrip(trip)} className="snap-start shrink-0 w-60 bg-white p-5 rounded-[2rem] border-2 border-indigo-100 text-left hover:border-indigo-500 hover:shadow-2xl transition-all group relative">
                        <div className="absolute -top-4 -right-4 w-12 h-12 bg-indigo-50 rounded-full flex items-center justify-center pt-4 pr-4"><Star size={14} className="text-indigo-400 fill-indigo-400" /></div>
                        <h4 className="font-bold text-slate-900 mb-1 truncate">{trip.destination}</h4>
                        <div className="flex items-center justify-between mt-auto">
                          <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-lg">Permanent</span>
                          <div onClick={(e) => deleteFromHistory(e, trip.id, 'saved')} className="p-1.5 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Trash2 size={14} /></div>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          <div className="text-center space-y-4">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 leading-tight">
              Where to <span className="text-blue-600 underline decoration-blue-200 decoration-8 underline-offset-4">next?</span>
            </h2>
            <p className="text-slate-500 text-lg max-w-xl mx-auto font-medium">Multi-tool Agent orchestrating Amadeus + Gemini Intelligence.</p>
          </div>

          <form onSubmit={handlePlanTrip} className="bg-white rounded-[2.5rem] p-10 shadow-2xl border border-slate-100 space-y-8 relative z-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2"><MapPin size={16} className="text-blue-500" />Route</label>
                <div className="space-y-4">
                  <div className="relative">
                    <input type="text" placeholder="Origin (e.g. NYC, London)" value={origin} onChange={(e) => setOrigin(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-[1.5rem] py-4 pl-12 pr-4 outline-none focus:border-blue-500" />
                    <Plane size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  </div>
                  <div className="relative">
                    <input type="text" placeholder="Destination (e.g. Tokyo, Paris)" value={destination} onChange={(e) => setDestination(e.target.value)} required className="w-full bg-slate-50 border border-slate-200 rounded-[1.5rem] py-4 pl-12 pr-4 outline-none font-semibold text-slate-800 focus:border-blue-500" />
                    <MapPin size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-500" />
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <label className="text-sm font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2"><Calendar size={16} className="text-emerald-500" />Timing</label>
                <div className="grid grid-cols-2 gap-4">
                  <input type="date" value={dates.start} onChange={(e) => setDates({...dates, start: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm outline-none focus:border-blue-500" />
                  <input type="date" value={dates.end} onChange={(e) => setDates({...dates, end: e.target.value})} required className="bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm outline-none focus:border-blue-500" />
                </div>
              </div>
            </div>

            <button type="submit" disabled={isPlanning} className={`w-full py-6 rounded-[1.5rem] font-bold text-lg flex flex-col items-center justify-center transition-all ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 active:scale-[0.99]'}`}>
              {isPlanning ? (
                <>
                  <Loader2 size={24} className="animate-spin mb-2" />
                  <span className="text-xs font-black uppercase tracking-widest">{planningStep}</span>
                </>
              ) : (
                <div className="flex items-center gap-3"><Sparkles size={24} /> <span>Deploy Agentic Engine</span></div>
              )}
            </button>
          </form>
        </div>
      </section>

      <div ref={resultsRef} className="max-w-6xl mx-auto px-6 pb-24 space-y-12">
        {results && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
            {/* Feasibility Summary */}
            <div className={`mb-8 p-8 rounded-[2rem] border flex items-start gap-6 ${isRealistic ? 'bg-emerald-50 border-emerald-100 text-emerald-800' : 'bg-amber-50 border-amber-100 text-amber-800 shadow-lg shadow-amber-900/5'}`}>
              <div className={`p-4 rounded-2xl ${isRealistic ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'} shadow-lg shadow-current/20`}>
                {isRealistic ? <CheckCircle2 size={24} /> : <AlertTriangle size={24} />}
              </div>
              <div className="flex-1">
                <div className="flex items-center gap-3 mb-1">
                  <h4 className="font-extrabold text-xl">Trip Feasibility</h4>
                  <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600 bg-emerald-100/50 px-2 py-0.5 rounded-full">AI Analysis</span>
                </div>
                <p className="text-sm opacity-90 leading-relaxed font-medium">{results.feasibility || "Analysis not available."}</p>
              </div>
              <div className="flex gap-3">
                <button onClick={toggleSaveTrip} className={`p-4 rounded-2xl transition-all shadow-sm flex items-center gap-2 font-bold text-sm ${isTripSaved ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                  {isTripSaved ? <Bookmark size={20} fill="currentColor" /> : <Save size={20} />}
                  {isTripSaved ? 'Saved' : 'Save'}
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
              <div className="lg:col-span-2 space-y-10">
                {/* Weather */}
                <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm p-8">
                  <h3 className="text-2xl font-extrabold flex items-center gap-4 mb-6"><CloudSun size={28} className="text-blue-500" />Weather Forecast</h3>
                  {weather ? (
                    <div className="grid grid-cols-4 md:grid-cols-7 gap-4">
                      {weather.daily.time.slice(0, 7).map((time: string, i: number) => (
                        <div key={i} className="flex flex-col items-center p-3 rounded-2xl bg-slate-50 border border-slate-100">
                          <span className="text-[10px] font-bold text-slate-400 mb-1">{new Date(time).toLocaleDateString('en-US', { weekday: 'short' })}</span>
                          <div className="text-2xl mb-1">{weather.daily.weathercode[i] < 3 ? '☀️' : '☁️'}</div>
                          <div className="text-sm font-extrabold text-slate-800">{tempUnit === 'C' ? Math.round(weather.daily.temperature_2m_max[i]) : Math.round(weather.daily.temperature_2m_max[i] * 9/5 + 32)}°</div>
                        </div>
                      ))}
                    </div>
                  ) : <div className="text-slate-400 italic">No forecast available.</div>}
                </div>

                {/* Itinerary */}
                <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm p-8">
                  <h3 className="text-2xl font-extrabold flex items-center gap-4 mb-10"><Briefcase size={28} className="text-emerald-500" />Daily Itinerary</h3>
                  <div className="space-y-12">
                    {results.itinerary?.map((day: any, i: number) => (
                      <div key={i} className="relative pl-14">
                        <div className="absolute left-0 top-0 w-10 h-10 rounded-2xl bg-emerald-500 flex items-center justify-center text-white text-sm font-bold shadow-lg shadow-emerald-500/20">{day.day}</div>
                        {i < results.itinerary.length - 1 && <div className="absolute left-5 top-10 bottom-[-3rem] w-px bg-slate-100"></div>}
                        <h4 className="font-extrabold text-xl text-slate-800 mb-4">{day.title}</h4>
                        <ul className="space-y-3">
                          {day.activities?.map((act: string, idx: number) => (
                            <li key={idx} className="flex items-start gap-4 text-slate-600 text-sm"><div className="mt-1.5 w-1.5 h-1.5 rounded-full bg-emerald-300 shrink-0"></div>{act}</li>
                          ))}
                        </ul>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-10">
                {/* Flights */}
                <div className="bg-[#1e293b] rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl p-8">
                  <div className="flex flex-col mb-8">
                    <h3 className="text-xl font-extrabold text-white flex items-center gap-3"><Plane size={24} className="text-blue-400" />Flight Offers</h3>
                    {results.isRealFlights && <span className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1">Live Amadeus Data</span>}
                  </div>
                  <div className="space-y-6">
                    {results.flights?.map((flight: any, i: number) => (
                      <div key={i} className="bg-slate-800/40 p-6 rounded-[2rem] border border-slate-700/50 hover:border-blue-500 transition-all">
                        <div className="flex justify-between items-start mb-6">
                          <div className="flex flex-col">
                            <span className="text-blue-400 font-bold text-[11px] uppercase tracking-widest mb-1">{flight.airline}</span>
                            <span className="text-slate-500 font-bold text-[10px]">Carrier: {flight.airlineCode || 'N/A'}</span>
                          </div>
                          <span className="text-white font-black text-2xl tracking-tighter">${flight.price}</span>
                        </div>
                        <div className="flex items-center gap-6 text-3xl text-white font-black mb-6">
                           <div className="flex-1 text-right truncate">
                             <span className="text-[10px] block text-slate-500 font-bold uppercase tracking-widest mb-1">Departure</span>
                             {flight.originCode}
                           </div>
                           <div className="flex-1 h-px bg-slate-700 relative"><Plane size={20} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-blue-500" /></div>
                           <div className="flex-1 truncate">
                             <span className="text-[10px] block text-slate-500 font-bold uppercase tracking-widest mb-1">Arrival</span>
                             {flight.destCode}
                           </div>
                        </div>
                        <div className="flex justify-between text-[10px] font-black uppercase text-slate-500 border-t border-slate-700/30 pt-4">
                           <div className="flex items-center gap-1.5"><Clock size={12} /> {flight.duration}</div>
                           <span className={flight.stops === 0 ? 'text-emerald-500' : 'text-amber-500'}>{flight.stops === 0 ? 'Non-stop' : `${flight.stops} stop`}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Accommodations */}
                <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm p-8">
                  <div className="flex items-center justify-between mb-6">
                    <h3 className="text-xl font-extrabold flex items-center gap-4"><Hotel size={28} className="text-amber-500" />Accommodations</h3>
                    {results.isRealHotels && <span className="text-[10px] bg-amber-50 text-amber-600 px-3 py-1 rounded-full font-black border border-amber-100">LIVE</span>}
                  </div>
                  <div className="space-y-4">
                    {results.accommodations?.map((hotel: any, i: number) => (
                      <div key={i} className="p-5 rounded-[1.5rem] bg-slate-50 border border-slate-100 hover:border-amber-400 hover:bg-white transition-all group">
                         <div className="flex justify-between items-start mb-2">
                            <h5 className="font-bold text-slate-900 text-sm group-hover:text-amber-600 truncate">{hotel.name}</h5>
                            <div className="flex items-center gap-1 text-amber-500 font-black text-[10px] shrink-0">
                              {hotel.rating} <Star size={10} fill="currentColor" />
                            </div>
                         </div>
                         <div className="flex justify-between items-center text-[10px]">
                           <span className="text-slate-400 font-bold uppercase">{hotel.neighborhood || 'Nearby Area'}</span>
                           <span className="text-slate-700 font-black tracking-tight">~${hotel.price}/night</span>
                         </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Neighborhood Map */}
                <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm h-[400px] relative">
                   <div id="neighborhood-map" className="w-full h-full"></div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  ChevronDown, ChevronUp, CloudSun, Map as MapIcon, 
  Hotel, Briefcase, Sparkles, Send, Share2, Save,
  CheckCircle2, Info, AlertTriangle, X, Loader2, Zap,
  Search, Clock, History, Star, Bookmark, ArrowRight,
  Heart, Compass, ExternalLink
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { searchFlights, searchHotelsByGeocode } from './services/amadeusService';
import { TripPlan, WeatherDay, FlightOffer, Neighborhood, ItineraryDay } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 300 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [planningStep, setPlanningStep] = useState('');
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [recentSearches, setRecentSearches] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
    weather: true,
    flights: true,
    itinerary: true,
    map: true,
    hotels: true
  });

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_saved');
    const recents = localStorage.getItem('wandergenius_recents');
    if (saved) setSavedTrips(JSON.parse(saved));
    if (recents) setRecentSearches(JSON.parse(recents));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const toggleSection = (section: string) => {
    setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setWeather(null);
    setPlanningStep('Step 1: AI Reasoning & Storyboarding...');

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const amadeusFlightsPromise = searchFlights(originVal, destVal, startVal);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusFlightsPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      setPlanningStep('Step 2: Fetching Real-World Hotels via Amadeus...');
      const neighborhoodHotels: any[] = [];
      if (intelData.neighborhoods && Array.isArray(intelData.neighborhoods)) {
        const neighborhoodTasks = intelData.neighborhoods.slice(0, 2).map(n => searchHotelsByGeocode(n.lat, n.lng));
        const hotelResults = await Promise.all(neighborhoodTasks);

        hotelResults.forEach((hotels, idx) => {
          const neighborhoodName = intelData.neighborhoods[idx].name;
          hotels.forEach((h: any) => {
            neighborhoodHotels.push({ ...h, neighborhood: neighborhoodName });
          });
        });
      }

      setPlanningStep('Step 3: Analyzing Meteorological Data...');
      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, startVal, endVal);
      }

      intelData.flights = flightsData || intelData.flights;
      intelData.isRealFlights = !!flightsData;
      intelData.accommodations = neighborhoodHotels.length > 0 ? neighborhoodHotels : intelData.accommodations;
      intelData.isRealHotels = neighborhoodHotels.length > 0;

      setResults(intelData);
      setWeather(weatherData);

      const currentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, budget: budgetVal, additionalCities: additionalVal,
        timestamp: Date.now()
      };
      setRecentSearches(prev => {
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [currentTrip, ...filtered].slice(0, 8);
        localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
        return updated;
      });

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Agentic planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
      setPlanningStep('');
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const loadTrip = (trip: TripPlan) => {
    setOrigin(trip.origin);
    setDestination(trip.destination);
    setDates({ start: trip.startDate, end: trip.endDate });
    setBudget(trip.budget);
    setAdditionalCities(trip.additionalCities);
    executePlan(trip.origin, trip.destination, trip.startDate, trip.endDate, trip.additionalCities, trip.budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;
    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }
    if (mapRef.current) mapRef.current.remove();
    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '&copy; OpenStreetMap' }).addTo(map);
      if (neighborhoods) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) L.marker([n.lat, n.lng]).addTo(map).bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
        });
      }
      mapRef.current = map;
    } catch (err) { console.error(err); }
  };

  const toggleSaveTrip = () => {
    if (!destination) return;
    const isAlreadySaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
    if (isAlreadySaved) {
      const updated = savedTrips.filter(t => t.destination.toLowerCase() !== destination.toLowerCase());
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const newSaved: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
        timestamp: Date.now()
      };
      const updated = [newSaved, ...savedTrips];
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    }
  };

  const deleteFromHistory = (e: React.MouseEvent, id: string, list: 'saved' | 'recent') => {
    e.stopPropagation();
    if (list === 'saved') {
      const updated = savedTrips.filter(t => t.id !== id);
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const updated = recentSearches.filter(t => t.id !== id);
      setRecentSearches(updated);
      localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
    }
  };

  const isTripSaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

