  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');
  const [showAdvanced, setShowAdvanced] = useState(false);

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [planningStep, setPlanningStep] = useState('');
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [recentSearches, setRecentSearches] = useState<TripPlan[]>([]);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_saved');
    const recents = localStorage.getItem('wandergenius_recents');
    if (saved) setSavedTrips(JSON.parse(saved));
    if (recents) setRecentSearches(JSON.parse(recents));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const removeCity = (city: string) => {
    setAdditionalCities(additionalCities.filter(c => c !== city));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setWeather(null);
    setPlanningStep('Step 1: AI Reasoning & Storyboarding...');

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const amadeusFlightsPromise = searchFlights(originVal, destVal, startVal);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusFlightsPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      setPlanningStep('Step 2: Fetching Real-World Hotels via Amadeus...');
      const neighborhoodHotels: any[] = [];
      if (intelData.neighborhoods && Array.isArray(intelData.neighborhoods)) {
        const neighborhoodTasks = intelData.neighborhoods.slice(0, 2).map(n => searchHotelsByGeocode(n.lat, n.lng));
        const hotelResults = await Promise.all(neighborhoodTasks);

        hotelResults.forEach((hotels, idx) => {
          const neighborhoodName = intelData.neighborhoods[idx].name;
          hotels.forEach((h: any) => {
            neighborhoodHotels.push({ ...h, neighborhood: neighborhoodName });
          });
        });
      }

      setPlanningStep('Step 3: Analyzing Meteorological Data...');
      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, startVal, endVal);
      }

      intelData.flights = flightsData || intelData.flights;
      intelData.isRealFlights = !!flightsData;
      intelData.accommodations = neighborhoodHotels.length > 0 ? neighborhoodHotels : intelData.accommodations;
      intelData.isRealHotels = neighborhoodHotels.length > 0;

      setResults(intelData);
      setWeather(weatherData);

      const currentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, budget: budgetVal, additionalCities: additionalVal,
        timestamp: Date.now()
      };
      setRecentSearches(prev => {
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [currentTrip, ...filtered].slice(0, 10);
        localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
        return updated;
      });

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Agentic planning failed. Please try again.");
    } finally {
      setIsPlanning(false);
      setPlanningStep('');
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const loadTrip = (trip: TripPlan) => {
    setOrigin(trip.origin);
    setDestination(trip.destination);
    setDates({ start: trip.startDate, end: trip.endDate });
    setBudget(trip.budget);
    setAdditionalCities(trip.additionalCities);
    executePlan(trip.origin, trip.destination, trip.startDate, trip.endDate, trip.additionalCities, trip.budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;
    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }
    if (mapRef.current) mapRef.current.remove();
    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '&copy; OpenStreetMap' }).addTo(map);
      if (neighborhoods) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) L.marker([n.lat, n.lng]).addTo(map).bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
        });
      }
      mapRef.current = map;
    } catch (err) { console.error(err); }
  };

  const toggleSaveTrip = () => {
    if (!destination) return;
    const isAlreadySaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
    if (isAlreadySaved) {
      const updated = savedTrips.filter(t => t.destination.toLowerCase() !== destination.toLowerCase());
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const newSaved: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
        timestamp: Date.now()
      };
      const updated = [newSaved, ...savedTrips];
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    }
  };

  const deleteFromHistory = (e: React.MouseEvent, id: string, list: 'saved' | 'recent') => {
    e.stopPropagation();
    if (list === 'saved') {
      const updated = savedTrips.filter(t => t.id !== id);
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const updated = recentSearches.filter(t => t.id !== id);
      setRecentSearches(updated);
      localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
    }
  };

  const isTripSaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  const formatDateRange = (start: string, end: string) => {
    if (!start || !end) return '';
    const s = new Date(start);
    const e = new Date(end);
    return `${s.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - ${e.toLocaleDateString('en-US', { day: 'numeric' })}`;
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC]">
      <nav className="sticky top-0 z-[100] bg-white border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 lg:px-12 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-[#2563EB] rounded-full flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Compass size={22} strokeWidth={2.5} />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-900 leading-tight">WanderGenius</h1>
              <span className="text-[9px] font-black uppercase text-blue-500 tracking-widest block -mt-1">Travel Intelligence</span>
            </div>
          </div>

          <div className="hidden md:flex items-center space-x-8 text-sm font-bold text-slate-500">
            <button className="hover:text-blue-600 transition-colors">Flights</button>
            <button className="hover:text-blue-600 transition-colors">Hotels</button>
            <button className="hover:text-blue-600 transition-colors">Wishlists</button>
            <button className="px-5 py-2.5 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition-all shadow-md shadow-blue-600/10">Plan Trip</button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 lg:px-12 pt-12 pb-24">

        {/* TOP: Search Experience */}
        <section className="mb-20">
          <div className="max-w-5xl mx-auto">
            <div className="text-center mb-10 space-y-4">
              <h2 className="text-5xl lg:text-6xl font-black text-slate-900 tracking-tight">
                Plan your <span className="text-blue-600">dream trip.</span>
              </h2>
              <p className="text-lg text-slate-500 font-medium max-w-xl mx-auto leading-relaxed">
                Harness Gemini's reasoning to generate optimized itineraries backed by real-time Amadeus GDS data.
              </p>
            </div>

            <form onSubmit={handlePlanTrip} className="bg-white rounded-[2.5rem] p-4 shadow-xl border border-slate-100 space-y-4">
              <div className="flex flex-col lg:flex-row items-stretch gap-2">
                <div className="flex-1 px-6 py-3 hover:bg-slate-50 rounded-2xl transition-colors group">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">Origin</label>
                  <div className="flex items-center gap-2">
                    <Plane size={16} className="text-slate-300" />
                    <input 
                      type="text" 
                      placeholder="Departure City" 
                      value={origin} 
                      onChange={(e) => setOrigin(e.target.value)} 
                      className="bg-transparent w-full text-slate-800 font-bold focus:outline-none placeholder:text-slate-300"
                    />
                  </div>
                </div>
                <div className="w-px h-10 bg-slate-100 self-center hidden lg:block"></div>
                <div className="flex-1 px-6 py-3 hover:bg-slate-50 rounded-2xl transition-colors">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">Destination</label>
                  <div className="flex items-center gap-2">
                    <MapPin size={16} className="text-blue-500" />
                    <input 
                      type="text" 
                      placeholder="Where to?" 
                      value={destination} 
                      onChange={(e) => setDestination(e.target.value)} 
                      required
                      className="bg-transparent w-full text-slate-800 font-bold focus:outline-none placeholder:text-slate-300"
                    />
                  </div>
                </div>
                <div className="w-px h-10 bg-slate-100 self-center hidden lg:block"></div>
                <div className="flex-1 px-6 py-3 hover:bg-slate-50 rounded-2xl transition-colors">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">Travel Window</label>
                  <div className="flex items-center gap-2">
                    <Calendar size={16} className="text-slate-300" />
                    <div className="flex items-center gap-1">
                      <input 
                        type="date" 
                        value={dates.start} 
                        onChange={(e) => setDates({...dates, start: e.target.value})} 
                        className="bg-transparent text-slate-800 font-bold focus:outline-none text-xs"
                      />
                      <span className="text-slate-300">-</span>
                      <input 
                        type="date" 
                        value={dates.end} 
                        onChange={(e) => setDates({...dates, end: e.target.value})} 
                        className="bg-transparent text-slate-800 font-bold focus:outline-none text-xs"
                      />
                    </div>
                  </div>
                </div>
                <button 
                  type="submit" 
                  disabled={isPlanning} 
                  className={`px-8 rounded-2xl flex items-center justify-center transition-all ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-600/20 active:scale-95'}`}
                >
                  {isPlanning ? <Loader2 className="animate-spin" size={24} /> : <div className="flex items-center gap-2 font-bold"><Sparkles size={20} /> Generate</div>}
                </button>
              </div>

              {/* Advanced Section */}
              <div className="px-6 pb-2 border-t border-slate-50 pt-4">
                <button 
                  type="button"
                  onClick={() => setShowAdvanced(!showAdvanced)}
                  className="text-[10px] font-black text-blue-500 uppercase tracking-widest flex items-center gap-2 mb-4 hover:text-blue-600"
                >
                  <SlidersHorizontal size={14} />
                  {showAdvanced ? 'Hide Advanced Options' : 'Additional Cities & Budget'}
                </button>

                {showAdvanced && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Multi-City Route</label>
                      <div className="flex gap-2">
                        <input 
                          type="text" 
                          placeholder="Add another stop..." 
                          value={newCity}
                          onChange={(e) => setNewCity(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                          className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-blue-500"
                        />
                        <button onClick={handleAddCity} type="button" className="p-2 bg-slate-100 hover:bg-slate-200 rounded-xl text-slate-600"><Plus size={20}/></button>
                      </div>
                      <div className="flex flex-wrap gap-2">
                        {additionalCities.map(city => (
                          <span key={city} className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2">
                            {city} <X size={12} className="cursor-pointer" onClick={() => removeCity(city)} />
                          </span>
                        ))}
                      </div>
                    </div>
                    <div className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Hotel Budget (Per Night)</label>
                      <div className="flex items-center gap-4">
                        <div className="flex-1 space-y-2">
                          <input 
                            type="range" 
                            min="50" 
                            max="1000" 
                            step="50"
                            value={budget.max}
                            onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})}
                            className="w-full accent-blue-600"
                          />
                          <div className="flex justify-between text-[10px] font-bold text-slate-500">
                            <span>$50</span>
                            <span className="text-blue-600 font-black">Up to ${budget.max}</span>
                            <span>$1000+</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </form>

            {isPlanning && (
              <div className="mt-8 text-center animate-pulse">
                <span className="text-xs font-black uppercase tracking-[0.3em] text-blue-600 bg-blue-50 px-6 py-2 rounded-full border border-blue-100">
                  {planningStep}
                </span>
              </div>
            )}
          </div>
        </section>

        {/* MIDDLE: Visual History Sections (Compacted) */}
        <div className="space-y-16 mb-20">
          {recentSearches.length > 0 && (
            <div className="animate-in fade-in duration-700">
              <div className="flex items-center gap-3 mb-6 px-2">
                <History size={18} className="text-slate-400" />
                <h2 className="text-sm font-black uppercase tracking-[0.2em] text-slate-400">Jump Back In</h2>
              </div>

              <div className="flex gap-4 overflow-x-auto pb-6 px-1 custom-scrollbar snap-x">
                {recentSearches.map((trip) => (
                  <button 
                    key={trip.id} 
                    onClick={() => loadTrip(trip)}
                    className="snap-start shrink-0 group relative w-60 h-36 rounded-2xl overflow-hidden bg-slate-200 shadow-sm hover:shadow-lg transition-all border border-slate-100"
                  >
                    <img 
                      src={`https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=crop&w=300&h=200&q=80&sig=${trip.id}`} 
                      alt={trip.destination}
                      className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/10 to-transparent p-4 flex flex-col justify-end">
                      <h4 className="text-white font-bold text-sm truncate">{trip.destination}</h4>
                      <p className="text-white/60 text-[9px] font-bold uppercase tracking-widest">
                        {formatDateRange(trip.startDate, trip.endDate)}
                      </p>
                    </div>
                    <div 
                      onClick={(e) => deleteFromHistory(e, trip.id, 'recent')}
                      className="absolute top-2 right-2 p-1 bg-black/40 backdrop-blur-md rounded-lg text-white/80 opacity-0 group-hover:opacity-100"
                    >
                      <X size={12} />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {savedTrips.length > 0 && (
            <div className="animate-in fade-in duration-700 delay-150">
              <div className="flex items-end justify-between mb-6 border-b border-slate-100 pb-3">
                <div className="flex items-center gap-3">
                  <Heart className="text-rose-500 fill-rose-500" size={18} />
                  <h2 className="text-sm font-black uppercase tracking-[0.2em] text-slate-900">Wishlists</h2>
                </div>
                <button className="text-[10px] font-black text-blue-500 uppercase tracking-widest hover:underline">View All</button>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {savedTrips.slice(0, 5).map((trip) => (
                  <div key={trip.id} className="group cursor-pointer" onClick={() => loadTrip(trip)}>
                    <div className="aspect-[4/5] relative rounded-2xl overflow-hidden bg-slate-100 mb-3 transition-all duration-300 group-hover:-translate-y-1">
                      <img 
                        src={`https://images.unsplash.com/photo-1493246507139-91e8bef99c02?auto=format&fit=crop&w=400&h=500&q=80&sig=${trip.id}`} 
                        alt={trip.destination}
                        className="w-full h-full object-cover"
                      />
                      <div className="absolute top-3 right-3">
                        <button 
                          onClick={(e) => { e.stopPropagation(); toggleSaveTrip(); }}
                          className="p-1.5 bg-white/90 backdrop-blur-sm rounded-full shadow-lg text-rose-500"
                        >
                          <Heart size={14} fill="currentColor" />
                        </button>
                      </div>
                    </div>
                    <div className="space-y-0.5 px-1">
                      <h4 className="font-bold text-slate-800 text-sm truncate">{trip.destination}</h4>
                      <p className="text-slate-400 text-[10px] font-bold truncate uppercase">{trip.origin || 'Anywhere'}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* BOTTOM: Results Viewer */}
        <div ref={resultsRef} className="space-y-16">
          {results && (
            <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">

              <div className={`p-6 rounded-3xl flex flex-col md:flex-row items-center gap-6 mb-16 ${isRealistic ? 'bg-blue-50 border border-blue-100' : 'bg-amber-50 border border-amber-100'}`}>
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-lg ${isRealistic ? 'bg-blue-600' : 'bg-amber-500'}`}>
                  {isRealistic ? <CheckCircle2 size={28} /> : <AlertTriangle size={28} />}
                </div>
                <div className="flex-1 text-center md:text-left">
                  <h3 className="text-lg font-black text-slate-900 mb-1 tracking-tight">AI Strategy Insight</h3>
                  <p className="text-slate-600 text-sm font-medium leading-relaxed">{results.feasibility}</p>
                </div>
                <div className="flex gap-3">
                  <button 
                    onClick={toggleSaveTrip} 
                    className={`flex items-center gap-2 px-6 py-3 rounded-full font-bold text-sm transition-all ${isTripSaved ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'bg-white text-slate-900 border border-slate-200 hover:bg-slate-50'}`}
                  >
                    {isTripSaved ? <Bookmark fill="currentColor" size={18} /> : <Save size={18} />}
                    {isTripSaved ? 'Trip Saved' : 'Save Itinerary'}
                  </button>
                  <button className="p-3 bg-white border border-slate-200 rounded-full hover:bg-slate-50 transition-all">
                    <Share2 size={20} className="text-slate-600" />
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

                {/* Main Itinerary */}
                <div className="lg:col-span-8 space-y-12">
                  <div className="flex items-center gap-4 mb-8">
                    <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
                      <Briefcase size={24} />
                    </div>
                    <h3 className="text-3xl font-black text-slate-900 tracking-tight">Master Itinerary</h3>
                  </div>

                  <div className="space-y-10">
                    {results.itinerary?.map((day: any, i: number) => (
                      <div key={i} className="group relative pl-16">
                        <div className="absolute left-0 top-0 w-12 h-12 rounded-2xl border-2 border-white bg-slate-900 flex items-center justify-center text-white text-xs font-black shadow-lg z-10">
                          {day.day}
                        </div>
                        {i < results.itinerary.length - 1 && (
                          <div className="absolute left-6 top-12 bottom-[-2.5rem] w-0.5 bg-slate-100"></div>
                        )}
                        <div className="bg-white p-6 md:p-8 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all duration-500">
                          <h4 className="text-xl font-black text-slate-900 mb-6">{day.title}</h4>
                          <div className="grid md:grid-cols-2 gap-8">
                            <ul className="space-y-4">
                              {day.activities?.map((act: string, idx: number) => (
                                <li key={idx} className="flex items-start gap-4 text-slate-600 text-sm font-medium leading-relaxed">
                                  <div className="mt-1.5 w-2 h-2 rounded-full bg-blue-100 border-2 border-blue-500 shrink-0"></div>
                                  {act}
                                </li>
                              ))}
                            </ul>
                            <div className="rounded-2xl overflow-hidden h-44 relative group/img">
                              <img src={`https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?auto=format&fit=crop&w=400&q=80&sig=${i}`} alt="Day Location" className="w-full h-full object-cover transition-transform group-hover/img:scale-105" />
                              <div className="absolute top-3 left-3 px-3 py-1.5 bg-black/60 backdrop-blur-md rounded-xl text-[9px] font-black uppercase tracking-widest text-white flex items-center gap-1">
                                <MapPin size={10} /> {day.location}
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Sidebar Info */}
                <div className="lg:col-span-4 space-y-12">

                  {/* Airfare */}
                  <div className="bg-slate-900 rounded-[2.5rem] overflow-hidden shadow-2xl p-8 border border-slate-800">
                    <div className="flex items-center justify-between mb-8">
                      <div>
                        <h3 className="text-white font-black text-lg flex items-center gap-2">
                          <Plane size={20} className="text-blue-400" /> Best Airfare
                        </h3>
