                      </h3>
                      {results.isRealHotels && <span className="bg-blue-50 text-blue-600 px-2 py-0.5 rounded text-[9px] font-black">AGENTIC</span>}
                    </div>

                    <div className="space-y-6">
                      {results.accommodations?.map((hotel: any, i: number) => (
                        <div key={i} className="flex gap-4 items-center group cursor-pointer">
                          <div className="w-16 h-16 rounded-2xl overflow-hidden shrink-0 bg-slate-100 shadow-inner">
                             <img src={`https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=100&q=80&sig=${i}`} alt="Hotel" className="w-full h-full object-cover transition-opacity group-hover:opacity-80" />
                          </div>
                          <div className="flex-1 min-w-0">
                             <h5 className="font-black text-slate-800 text-xs truncate group-hover:text-blue-600">{hotel.name}</h5>
                             <p className="text-[9px] font-bold text-slate-400 uppercase mt-0.5">{hotel.neighborhood || 'Nearby'}</p>
                             <div className="flex items-center justify-between mt-1">
                               <span className="text-slate-900 font-black text-xs">${hotel.price}<span className="text-slate-400 font-medium text-[8px]">/nt</span></span>
                               <div className="flex items-center gap-0.5 text-blue-500 text-[10px] font-black">
                                 {hotel.rating} <Star size={10} fill="currentColor" />
                               </div>
                             </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Neighbors Map */}
                  <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm h-[420px] relative">
                     <div id="neighborhood-map" className="w-full h-full"></div>
                     <div className="absolute top-4 left-4 right-4 bg-white/95 backdrop-blur-md p-4 rounded-2xl border border-slate-100 shadow-xl z-[400]">
                        <p className="text-[9px] font-black uppercase text-blue-500 tracking-widest mb-1">Spatial Hub</p>
                        <h4 className="text-xs font-bold text-slate-800 leading-tight">Recommended Neighborhoods</h4>
                     </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-16">
        <div className="max-w-7xl mx-auto px-6 lg:px-12 flex flex-col md:flex-row justify-between items-center gap-10">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-slate-900 rounded-full flex items-center justify-center text-white">
              <Compass size={18} />
            </div>
            <h1 className="text-lg font-bold text-slate-900">WanderGenius</h1>
          </div>
          <p className="text-slate-400 text-xs font-medium">© 2025 WanderGenius Travel Intelligence. Powered by Gemini & Amadeus GDS.</p>
          <div className="flex gap-4 text-slate-400">
            <button className="w-10 h-10 flex items-center justify-center bg-slate-50 hover:bg-slate-100 rounded-full transition-colors"><Bookmark size={18} /></button>
            <button className="w-10 h-10 flex items-center justify-center bg-slate-50 hover:bg-slate-100 rounded-full transition-colors"><Share2 size={18} /></button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  ChevronDown, ChevronUp, CloudSun, Map as MapIcon, 
  Hotel, Briefcase, Sparkles, Send, Share2, Save,
  CheckCircle2, Info, AlertTriangle, X, Loader2, Zap,
  Search, Clock, History, Star, Bookmark, ArrowRight,
  Heart, Compass, ExternalLink, SlidersHorizontal, Settings2
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { searchFlights, searchHotelsByGeocode } from './services/amadeusService';
import { TripPlan, WeatherDay, FlightOffer, Neighborhood, ItineraryDay } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 500 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');
  const [showAdvanced, setShowAdvanced] = useState(true); // Default to true for accessibility

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [planningStep, setPlanningStep] = useState('');
  const [results, setResults] = useState<any>(null);
  const [weather, setWeather] = useState<any>(null);
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [recentSearches, setRecentSearches] = useState<TripPlan[]>([]);

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_saved');
    const recents = localStorage.getItem('wandergenius_recents');
    if (saved) setSavedTrips(JSON.parse(saved));
    if (recents) setRecentSearches(JSON.parse(recents));

    const params = new URLSearchParams(window.location.search);
    if (params.has('dest')) {
      setDestination(params.get('dest') || '');
      setDates({ start: params.get('start') || '', end: params.get('end') || '' });
    }
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const removeCity = (city: string) => {
    setAdditionalCities(additionalCities.filter(c => c !== city));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setWeather(null);
    setPlanningStep('Syncing with Gemini Engines...');

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const amadeusFlightsPromise = searchFlights(originVal, destVal, startVal);

      const [intel, geo, amadeusResults] = await Promise.allSettled([
        intelPromise,
        geoPromise,
        amadeusFlightsPromise
      ]);

      const intelData = intel.status === 'fulfilled' ? (intel as any).value : null;
      const geoData = geo.status === 'fulfilled' ? (geo as any).value : null;
      const flightsData = amadeusResults.status === 'fulfilled' ? (amadeusResults as any).value : null;

      if (!intelData) throw new Error("Intelligence plan failed");

      setPlanningStep('Polling GDS for Live Availability...');
      const neighborhoodHotels: any[] = [];
      if (intelData.neighborhoods && Array.isArray(intelData.neighborhoods)) {
        const neighborhoodTasks = intelData.neighborhoods.slice(0, 2).map(n => searchHotelsByGeocode(n.lat, n.lng));
        const hotelResults = await Promise.all(neighborhoodTasks);

        hotelResults.forEach((hotels, idx) => {
          const neighborhoodName = intelData.neighborhoods[idx].name;
          hotels.forEach((h: any) => {
            neighborhoodHotels.push({ ...h, neighborhood: neighborhoodName });
          });
        });
      }

      setPlanningStep('Aggregating Spatial Insights...');
      let weatherData = null;
      if (geoData) {
        weatherData = await fetchWeather(geoData.lat, geoData.lon, startVal, endVal);
      }

      intelData.flights = flightsData || intelData.flights;
      intelData.isRealFlights = !!flightsData;
      intelData.accommodations = neighborhoodHotels.length > 0 ? neighborhoodHotels : intelData.accommodations;
      intelData.isRealHotels = neighborhoodHotels.length > 0;

      setResults(intelData);
      setWeather(weatherData);

      const currentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, budget: budgetVal, additionalCities: additionalVal,
        timestamp: Date.now()
      };
      setRecentSearches(prev => {
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [currentTrip, ...filtered].slice(0, 10);
        localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
        return updated;
      });

      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
        if (geoData) initMap(intelData.neighborhoods, geoData);
      }, 300);

    } catch (err) {
      console.error(err);
      alert("Search failed. Please ensure your parameters are valid.");
    } finally {
      setIsPlanning(false);
      setPlanningStep('');
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const loadTrip = (trip: TripPlan) => {
    setOrigin(trip.origin);
    setDestination(trip.destination);
    setDates({ start: trip.startDate, end: trip.endDate });
    setBudget(trip.budget);
    setAdditionalCities(trip.additionalCities);
    executePlan(trip.origin, trip.destination, trip.startDate, trip.endDate, trip.additionalCities, trip.budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    if (!center) return;
    const L = (window as any).L;
    if (!L) return;
    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) {
      setTimeout(() => initMap(neighborhoods, center), 200);
      return;
    }
    if (mapRef.current) mapRef.current.remove();
    try {
      const map = L.map('neighborhood-map').setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '&copy; OpenStreetMap' }).addTo(map);
      if (neighborhoods) {
        neighborhoods.forEach(n => {
          if (n.lat && n.lng) L.marker([n.lat, n.lng]).addTo(map).bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
        });
      }
      mapRef.current = map;
    } catch (err) { console.error(err); }
  };

  const toggleSaveTrip = () => {
    if (!destination) return;
    const isAlreadySaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
    if (isAlreadySaved) {
      const updated = savedTrips.filter(t => t.destination.toLowerCase() !== destination.toLowerCase());
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const newSaved: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
        timestamp: Date.now()
      };
      const updated = [newSaved, ...savedTrips];
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    }
  };

  const deleteFromHistory = (e: React.MouseEvent, id: string, list: 'saved' | 'recent') => {
    e.stopPropagation();
    if (list === 'saved') {
      const updated = savedTrips.filter(t => t.id !== id);
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const updated = recentSearches.filter(t => t.id !== id);
      setRecentSearches(updated);
      localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
    }
  };

  const isTripSaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  const formatDateRange = (start: string, end: string) => {
    if (!start || !end) return '';
    const s = new Date(start);
    const e = new Date(end);
    return `${s.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - ${e.toLocaleDateString('en-US', { day: 'numeric' })}`;
  };

  return (
    <div className="min-h-screen bg-[#F1F5F9]">
      <nav className="sticky top-0 z-[100] bg-white border-b border-slate-200 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 lg:px-12 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-11 h-11 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Compass size={24} strokeWidth={2.5} />
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter text-slate-900 leading-none">WanderGenius</h1>
              <span className="text-[10px] font-black uppercase text-blue-500 tracking-[0.2em] block mt-1">Intelligence Layer</span>
            </div>
          </div>

          <div className="hidden md:flex items-center space-x-8 text-sm font-bold text-slate-500">
            <button className="hover:text-blue-600 transition-colors">Flights</button>
            <button className="hover:text-blue-600 transition-colors">Hotels</button>
            <button className="hover:text-blue-600 transition-colors">Wishlists</button>
            <button className="px-6 py-2.5 bg-slate-900 text-white rounded-xl hover:bg-black transition-all shadow-md">Sign In</button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 lg:px-12 pt-16 pb-24">

        {/* 1. PRIMARY SEARCH ENGINE (Top Priority) */}
        <section className="mb-24 relative z-50">
          <div className="max-w-5xl mx-auto text-center mb-12">
            <h2 className="text-6xl lg:text-7xl font-black text-slate-900 tracking-tight leading-[0.9] mb-6">
              Plan smarter. <br/><span className="text-blue-600">Explore further.</span>
            </h2>
            <p className="text-xl text-slate-500 font-medium max-w-2xl mx-auto leading-relaxed">
              Global GDS search integrated with Gemini 3 reasoning for high-fidelity travel strategies.
            </p>
          </div>

          <div className="bg-white rounded-[3rem] p-6 shadow-2xl border border-slate-100">
            <form onSubmit={handlePlanTrip} className="space-y-6">
              <div className="flex flex-col lg:flex-row items-stretch gap-4">
                <div className="flex-[1.2] px-6 py-4 bg-slate-50 hover:bg-slate-100 rounded-3xl transition-colors">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-2">Departure</label>
                  <div className="flex items-center gap-3 text-slate-900">
                    <Plane size={20} className="text-slate-300" />
                    <input 
                      type="text" 
                      placeholder="Origin City" 
                      value={origin} 
                      onChange={(e) => setOrigin(e.target.value)} 
                      className="bg-transparent w-full font-bold focus:outline-none placeholder:text-slate-300 text-lg"
                    />
                  </div>
                </div>

                <div className="flex-[1.2] px-6 py-4 bg-slate-50 hover:bg-slate-100 rounded-3xl transition-colors">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-2">Destination</label>
                  <div className="flex items-center gap-3 text-slate-900">
                    <MapPin size={20} className="text-blue-500" />
                    <input 
                      type="text" 
                      placeholder="Where to?" 
                      value={destination} 
                      onChange={(e) => setDestination(e.target.value)} 
                      required
                      className="bg-transparent w-full font-bold focus:outline-none placeholder:text-slate-300 text-lg"
                    />
                  </div>
                </div>

                <div className="flex-1 px-6 py-4 bg-slate-50 hover:bg-slate-100 rounded-3xl transition-colors">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-2">Window</label>
                  <div className="flex items-center gap-3">
                    <Calendar size={20} className="text-slate-300" />
                    <div className="flex flex-col">
                       <input 
                        type="date" 
                        value={dates.start} 
                        onChange={(e) => setDates({...dates, start: e.target.value})} 
                        className="bg-transparent text-slate-800 font-bold focus:outline-none text-xs"
                      />
                      <input 
                        type="date" 
                        value={dates.end} 
                        onChange={(e) => setDates({...dates, end: e.target.value})} 
                        className="bg-transparent text-slate-800 font-bold focus:outline-none text-xs"
                      />
                    </div>
                  </div>
                </div>

                <button 
                  type="submit" 
                  disabled={isPlanning} 
                  className={`px-12 py-6 lg:py-0 rounded-[2rem] flex items-center justify-center transition-all group ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-600/20 active:scale-95'}`}
                >
                  {isPlanning ? <Loader2 className="animate-spin" size={32} /> : (
                    <div className="flex flex-col items-center">
                      <div className="flex items-center gap-3 font-black text-xl">
                        <Sparkles size={24} className="group-hover:rotate-12 transition-transform" /> 
                        GENERATE
                      </div>
                      <span className="text-[9px] font-bold tracking-[0.2em] opacity-80 mt-1 uppercase">AI Intelligence</span>
                    </div>
                  )}
                </button>
              </div>

              {/* Enhanced Advanced Options Bar */}
              <div className="pt-6 border-t border-slate-50 grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
                  <div className="flex items-center gap-2 mb-1">
                    <Settings2 size={16} className="text-blue-500" />
                    <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Multi-City Strategy</label>
                  </div>
                  <div className="flex gap-2">
                    <input 
                      type="text" 
                      placeholder="Add an additional stop..." 
                      value={newCity}
                      onChange={(e) => setNewCity(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())}
                      className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 text-sm focus:outline-none focus:border-blue-500 font-medium"
                    />
                    <button onClick={handleAddCity} type="button" className="p-3 bg-blue-50 hover:bg-blue-100 rounded-2xl text-blue-600 transition-colors"><Plus size={24}/></button>
                  </div>
                  <div className="flex flex-wrap gap-2 min-h-8">
                    {additionalCities.map(city => (
                      <span key={city} className="bg-blue-600 text-white px-3 py-1.5 rounded-xl text-xs font-bold flex items-center gap-2 shadow-sm animate-in zoom-in-50">
                        {city} <X size={14} className="cursor-pointer hover:bg-white/20 rounded" onClick={() => removeCity(city)} />
                      </span>
                    ))}
                    {additionalCities.length === 0 && <span className="text-slate-300 text-[10px] font-bold uppercase italic">No extra stops added</span>}
                  </div>
                </div>

                <div className="space-y-4">
                   <div className="flex items-center gap-2 mb-1">
                    <DollarSign size={16} className="text-emerald-500" />
                    <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Target nightly budget</label>
                  </div>
                  <div className="px-2">
                    <input 
                      type="range" 
                      min="50" 
                      max="1500" 
                      step="50"
                      value={budget.max}
                      onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})}
                      className="w-full accent-blue-600 h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer"
                    />
                    <div className="flex justify-between mt-4">
                      <div className="bg-slate-900 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">
                        MAX: ${budget.max}
                      </div>
                      <div className="flex flex-col items-end">
                         <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pricing Model</span>
                         <span className="text-xs font-bold text-slate-600">Premium Search Active</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </form>

            {isPlanning && (
              <div className="mt-8 text-center animate-pulse">
                <div className="inline-flex items-center gap-3 px-8 py-3 bg-blue-50 text-blue-600 rounded-2xl border border-blue-100 shadow-sm">
                   <Loader2 size={18} className="animate-spin" />
                   <span className="text-xs font-black uppercase tracking-[0.2em]">{planningStep}</span>
                </div>
              </div>
            )}
          </div>
        </section>

        {/* 2. COMPACT HISTORY SECTIONS */}
        <div className="space-y-12 mb-20">
          {recentSearches.length > 0 && (
            <div className="animate-in fade-in duration-700">
              <div className="flex items-center gap-3 mb-4">
                <History size={16} className="text-slate-400" />
                <h2 className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Pick up where you left off</h2>
              </div>

              <div className="flex gap-4 overflow-x-auto pb-4 px-1 custom-scrollbar snap-x">
                {recentSearches.map((trip) => (
                  <button 
                    key={trip.id} 
                    onClick={() => loadTrip(trip)}
                    className="snap-start shrink-0 group relative w-48 h-32 rounded-2xl overflow-hidden bg-white shadow-sm hover:shadow-xl transition-all border border-slate-100"
                  >
                    <img 
                      src={`https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=crop&w=300&h=200&q=80&sig=${trip.id}`} 
                      alt={trip.destination}
                      className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-slate-900/20 to-transparent p-3 flex flex-col justify-end">
                      <h4 className="text-white font-bold text-xs truncate leading-tight">{trip.destination}</h4>
                      <p className="text-white/60 text-[8px] font-black uppercase tracking-widest mt-0.5">
                        {formatDateRange(trip.startDate, trip.endDate)}
                      </p>
