                             <div className="flex items-center justify-between mt-3">
                               <span className="text-slate-900 font-black text-lg tracking-tighter">${hotel.price}<span className="text-slate-400 font-medium text-[10px]">/night</span></span>
                               <div className="flex items-center gap-1 text-blue-500 text-xs font-black">
