              <Compass size={22} />
            </div>
            <h1 className="text-xl font-black text-slate-900 tracking-tight">WanderGenius</h1>
          </div>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest text-center">© 2025 WanderGenius Travel Intelligence. Powered by Google Gemini.</p>
          <div className="flex gap-6 text-slate-400">
            <button className="w-12 h-12 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-2xl transition-all"><Bookmark size={20} /></button>
            <button className="w-12 h-12 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-2xl transition-all"><Share2 size={20} /></button>
          </div>
