import { GoogleGenAI, Type } from "@google/genai";

export const getTravelIntelligence = async (trip: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Act as a world-class travel architect. Plan a sophisticated trip from ${trip.origin || 'nearby'} to ${trip.destination} from ${trip.startDate} to ${trip.endDate}. 
  Additional cities to visit: ${trip.additionalCities.join(', ')}. 
  Nightly hotel budget: $${trip.budget.max}.

  Format the response in JSON with the following structure:
  1. "flights": Top 3 realistic flight estimates (price, airline, airlineCode, duration, stops, originCode, destCode).
  2. "neighborhoods": 5 diverse neighborhoods (name, description, bestFor, lat, lng coordinates).
  3. "itinerary": Day-by-day plan (day number, activity title, 3 activities, location).
  4. "accommodations": 3 hotel style recommendations matching the budget (name, estimated price, rating).
  5. "feasibility": A message evaluating if the trip is realistic, rushed, or perfectly paced.
  6. "climatology": A 1-2 sentence overview of the weather for ${trip.destination} during ${trip.startDate}. Mention average temp and typical conditions.
  7. "transportation": IF multiple cities are involved, provide a list of transit recommendations between each major stop (route, type e.g. Train/Fly/Drive, recommendation, estimated cost, duration).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          flights: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                price: { type: Type.NUMBER },
                airline: { type: Type.STRING },
                airlineCode: { type: Type.STRING },
                duration: { type: Type.STRING },
                stops: { type: Type.NUMBER },
                originCode: { type: Type.STRING },
                destCode: { type: Type.STRING }
              }
            }
          },
          neighborhoods: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                bestFor: { type: Type.STRING },
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
              }
            }
          },
          itinerary: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.NUMBER },
                title: { type: Type.STRING },
                activities: { type: Type.ARRAY, items: { type: Type.STRING } },
                location: { type: Type.STRING }
              }
            }
          },
          accommodations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                price: { type: Type.NUMBER },
                rating: { type: Type.NUMBER }
              }
            }
          },
          feasibility: { type: Type.STRING },
          climatology: { type: Type.STRING },
          transportation: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                route: { type: Type.STRING },
                type: { type: Type.STRING },
                recommendation: { type: Type.STRING },
                cost: { type: Type.NUMBER },
                duration: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateText = async (prompt: string, model: string, tools?: any[]) => {
