                    <span className="text-[12px] font-black tracking-[0.5em] opacity-60 mt-2 uppercase">Syncing Gemini 3.0 Pro Intelligence</span>
                  </div>
                )}
                {!isPlanning && <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>}
              </button>
            </form>
          </div>
        </section>

        {/* RECENT SEARCHES & WISHLISTS */}
        <div className="space-y-16 mb-24">
          {recentSearches.length > 0 && (
            <div className="animate-in fade-in duration-700">
              <div className="flex items-center gap-3 mb-8">
