              </div>
              <div className="flex gap-6 overflow-x-auto pb-8 px-1 custom-scrollbar snap-x">
                {recentSearches.map((trip) => (
                  <button 
                    key={trip.id} 
                    onClick={() => loadTrip(trip)}
                    className="snap-start shrink-0 group relative w-64 h-40 rounded-[2.5rem] overflow-hidden bg-white shadow-sm hover:shadow-2xl transition-all border border-slate-100"
                  >
                    <img 
                      src={`https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=crop&w=400&h=300&q=80&sig=${trip.id}`} 
                      alt={trip.destination}
                      className="absolute inset-0 w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-950/95 via-slate-950/20 to-transparent p-6 flex flex-col justify-end">
                      <h4 className="text-white font-black text-sm truncate leading-tight">{trip.destination}</h4>
                      <p className="text-white/50 text-[9px] font-black uppercase tracking-widest mt-2">
                        {formatDateRange(trip.startDate, trip.endDate)}
