                </div>
                <button className="text-[10px] font-black text-blue-600 uppercase tracking-widest hover:underline">View All {savedTrips.length}</button>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-8">
                {savedTrips.slice(0, 6).map((trip) => (
                  <div key={trip.id} className="group cursor-pointer" onClick={() => loadTrip(trip)}>
                    <div className="aspect-square relative rounded-[2rem] overflow-hidden bg-slate-200 mb-4 transition-all duration-500 group-hover:-translate-y-2 group-hover:shadow-2xl">
                      <img 
                        src={`https://images.unsplash.com/photo-1493246507139-91e8bef99c02?auto=format&fit=crop&w=300&h=300&q=80&sig=${trip.id}`} 
                        alt={trip.destination}
                        className="w-full h-full object-cover"
                      />
                      <div className="absolute top-3 right-3">
                        <button className="p-2 bg-white/95 backdrop-blur-md rounded-full shadow-lg text-rose-500 hover:scale-110 transition-transform"><Heart size={14} fill="currentColor" /></button>
                      </div>
                    </div>
                    <div className="px-1 text-center sm:text-left">
                      <h4 className="font-black text-slate-900 text-sm truncate mb-1">{trip.destination}</h4>
                      <p className="text-slate-400 text-[10px] font-black uppercase tracking-tighter">{trip.origin || 'Flexible'}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* RESULTS AREA */}
        <div ref={resultsRef} className="space-y-24 scroll-mt-24">
          {results && (
            <div className="animate-in fade-in slide-in-from-bottom-10 duration-1000">

              {/* Verdict Header Strip */}
              <div className={`p-10 rounded-[3.5rem] flex flex-col md:flex-row items-center gap-10 mb-20 border-2 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.08)] bg-white ${isRealistic ? 'border-blue-500/15' : 'border-amber-500/15'}`}>
