                <div className="flex-1 text-center md:text-left">
                  <div className="flex items-center justify-center md:justify-start gap-3 mb-3">
                    <span className="bg-slate-100 text-slate-500 px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-[0.2em]">Strategy Verdict</span>
                    <h3 className="text-3xl font-black text-slate-900 tracking-tight leading-none">AI Insight</h3>
                  </div>
                  <p className="text-slate-600 text-xl font-medium leading-relaxed italic max-w-2xl">"{results.feasibility}"</p>
                </div>
                <div className="flex gap-4">
                  <button 
                    onClick={toggleSaveTrip} 
                    className={`flex items-center gap-4 px-10 py-6 rounded-[2rem] font-black text-sm transition-all shadow-xl ${isTripSaved ? 'bg-blue-600 text-white shadow-blue-500/30' : 'bg-white text-slate-900 border-2 border-slate-100 hover:bg-slate-50'}`}
