                    {isTripSaved ? 'SAVED' : 'SAVE TRIP'}
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-20">

                {/* LEFT COLUMN: Main Experience Flow */}
