                  <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-2xl overflow-hidden relative group">
                     <div className="flex items-center gap-6 mb-12">
                        <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-[2.5rem] flex items-center justify-center shadow-inner group-hover:scale-105 transition-transform duration-500">
                           <CloudSun size={36} />
                        </div>
                        <div>
                          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Climatology Hub</h3>
                          <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mt-2">{weatherData?.isForecast ? 'Real-time 16-Day Sequence' : 'Historical Analysis Layer'}</p>
                        </div>
                     </div>

                     {!weatherData ? (
                       <div className="flex gap-6 overflow-hidden">
                         {[1,2,3,4,5].map(i => <div key={i} className="w-32 h-44 bg-slate-50 rounded-[2.5rem] animate-pulse"></div>)}
                       </div>
                     ) : weatherData.isForecast ? (
                       <div className="flex gap-6 overflow-x-auto pb-10 custom-scrollbar scroll-smooth">
                         {weatherData.daily?.time.map((t: string, i: number) => (
                           <div key={i} className="flex flex-col items-center bg-slate-50/50 px-10 py-8 rounded-[3rem] min-w-[150px] border border-slate-100 hover:bg-white hover:shadow-2xl hover:border-blue-100 transition-all cursor-default group/day">
                             <span className="text-[12px] font-black text-slate-400 mb-5 uppercase tracking-tighter">{new Date(t).toLocaleDateString('en-US', { weekday: 'short', day: 'numeric' })}</span>
