                             <div className="flex flex-col items-center">
                               <span className="text-3xl font-black text-slate-900">{Math.round(weatherData.daily.temperature_2m_max[i])}°</span>
                               <span className="text-[12px] font-bold text-slate-400 mt-1">L: {Math.round(weatherData.daily.temperature_2m_min[i])}°</span>
                             </div>
                           </div>
                         ))}
                       </div>
                     ) : (
                       <div className="bg-blue-50/50 p-12 rounded-[3rem] border-2 border-blue-100/50 text-blue-900 text-xl font-medium leading-relaxed italic shadow-inner">
                         {weatherData.overview}
                       </div>
                     )}
                  </div>

                  {/* Multi-City Logistics Module */}
                  {additionalCities.length > 0 && results.transportation && (
                    <div className="bg-slate-950 p-12 rounded-[4rem] shadow-[0_48px_96px_-24px_rgba(0,0,0,0.3)] relative overflow-hidden border-4 border-white/5 group">
