                          <Navigation size={250} />
                       </div>
                       <div className="relative z-10">
                         <div className="flex items-center gap-6 mb-14">
                            <div className="w-16 h-16 bg-white/10 rounded-[2.5rem] flex items-center justify-center text-white backdrop-blur-xl border border-white/10">
                               <Train size={36} />
                            </div>
                            <div>
                               <h3 className="text-4xl font-black text-white tracking-tight">Transit Logic</h3>
                               <p className="text-indigo-400 text-[11px] font-black uppercase tracking-[0.4em] mt-2">Logistical Connectors</p>
                            </div>
                         </div>
                         <div className="grid md:grid-cols-2 gap-10">
                           {results.transportation.map((t: any, idx: number) => (
                             <div key={idx} className="bg-white/5 border border-white/10 p-12 rounded-[3.5rem] hover:bg-white/10 transition-all group/transit">
                                <div className="flex items-center gap-4 mb-8">
                                   <div className="w-12 h-12 rounded-2xl bg-indigo-500/20 flex items-center justify-center text-indigo-400 group-hover/transit:scale-110 transition-transform">
