                                   </div>
                                   <h4 className="text-white font-black text-2xl tracking-tight">{t.route}</h4>
                                </div>
                                <p className="text-indigo-100 text-lg font-medium leading-relaxed mb-10 opacity-70 italic">"{t.recommendation}"</p>
                                <div className="flex justify-between items-center text-[12px] font-black uppercase tracking-[0.2em] text-indigo-400 border-t border-white/10 pt-8">
                                   <span className="flex items-center gap-3"><DollarSign size={16}/> Est. ${t.cost}</span>
                                   <span className="flex items-center gap-3"><Clock size={16}/> {t.duration}</span>
                                </div>
                             </div>
                           ))}
                         </div>
                       </div>
                    </div>
                  )}

                  {/* Primary Experience Sequencer */}
                  <div className="space-y-16">
                    <div className="flex items-center gap-8 mb-16">
                      <div className="w-20 h-20 bg-blue-600 rounded-[2.5rem] flex items-center justify-center text-white shadow-[0_24px_48px_-12px_rgba(37,99,235,0.5)]">
                        <Briefcase size={40} />
                      </div>
                      <div>
                        <h3 className="text-5xl font-black text-slate-900 tracking-tight leading-none">Experience Path</h3>
                        <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.3em] mt-3 underline decoration-blue-500 decoration-2 underline-offset-8">Curated Daily Strategy</p>
                      </div>
                    </div>

                    <div className="space-y-24">
                      {results.itinerary?.map((day: any, i: number) => (
                        <div key={i} className="group relative pl-24 md:pl-32">
                          <div className="absolute left-0 top-0 w-20 h-20 rounded-[2.5rem] border-4 border-white bg-slate-900 flex items-center justify-center text-white text-2xl font-black shadow-2xl z-10 transition-all group-hover:scale-110 group-hover:bg-blue-600">
                            {day.day}
                          </div>
                          {i < results.itinerary.length - 1 && (
                            <div className="absolute left-10 top-20 bottom-[-6rem] w-1.5 bg-slate-100 rounded-full"></div>
                          )}
                          <div className="bg-white p-12 md:p-16 rounded-[4.5rem] border border-slate-100 shadow-[0_8px_30px_rgb(0,0,0,0.04)] hover:shadow-[0_40px_80px_-20px_rgba(0,0,0,0.08)] transition-all duration-1000 group-hover:border-blue-100">
                            <h4 className="text-4xl font-black text-slate-900 mb-12 border-b-2 border-slate-50 pb-10 tracking-tight leading-tight">{day.title}</h4>
                            <div className="grid md:grid-cols-2 gap-16">
                              <ul className="space-y-8">
                                {day.activities?.map((act: string, idx: number) => (
                                  <li key={idx} className="flex items-start gap-6 text-slate-600 text-xl font-medium leading-relaxed group/item">
                                    <div className="mt-3 w-4 h-4 rounded-full bg-blue-600 shadow-xl shadow-blue-500/30 shrink-0 group-hover/item:scale-125 transition-transform"></div>
                                    {act}
                                  </li>
                                ))}
                              </ul>
                              <div className="rounded-[3.5rem] overflow-hidden h-[400px] relative group/img shadow-2xl">
                                <img src={`https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?auto=format&fit=crop&w=800&q=80&sig=${i}`} alt="Vista" className="w-full h-full object-cover transition-transform duration-[4000ms] group-hover/img:scale-110" />
                                <div className="absolute bottom-8 left-8 right-8 bg-white/95 backdrop-blur-xl p-8 rounded-[2.5rem] border border-slate-100 shadow-2xl flex items-center gap-6">
                                  <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl"><MapPin size={24} /></div>
                                  <span className="text-sm font-black text-slate-900 truncate uppercase tracking-widest">{day.location}</span>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                {/* RIGHT COLUMN: Action & Inventory Hub */}
                <div className="lg:col-span-4 space-y-20">

                  {/* Airfare Hub Module */}
                  <div className="bg-slate-950 rounded-[4rem] overflow-hidden shadow-2xl p-12 border border-slate-800 border-b-[12px] border-b-blue-600">
                    <div className="flex items-center justify-between mb-16">
                      <div>
                        <h3 className="text-white font-black text-3xl flex items-center gap-4">
                          <Plane size={32} className="text-blue-500" /> Airfare Hub
                        </h3>
                        <p className="text-slate-500 text-[11px] font-black uppercase tracking-[0.3em] mt-3">Verified GDS Connectivity</p>
                      </div>
                      <div className="w-14 h-14 rounded-2xl bg-blue-500/10 flex items-center justify-center border border-blue-500/20"><Zap size={28} className="text-blue-500" /></div>
                    </div>

                    <div className="space-y-8">
                      {results.flights?.map((flight: any, i: number) => (
                        <div key={i} className="bg-white/5 p-10 rounded-[3rem] border border-white/5 hover:border-blue-500/50 transition-all cursor-pointer group shadow-inner">
                          <div className="flex justify-between items-start mb-8">
                            <div className="flex items-center gap-5">
                               <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center text-[11px] text-white font-black">{flight.airlineCode || 'AIR'}</div>
                               <span className="text-blue-400 font-black text-base uppercase tracking-tight leading-none">{flight.airline}</span>
                            </div>
                            <span className="text-white font-black text-4xl tracking-tighter">${flight.price}</span>
                          </div>

                          <div className="flex items-center gap-10 text-5xl text-white font-black mb-10">
                             <div className="flex-1 text-right">{flight.originCode}</div>
                             <div className="flex-1 h-px bg-slate-800 relative"><Plane size={24} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-blue-500" /></div>
                             <div className="flex-1">{flight.destCode}</div>
                          </div>

                          <div className="flex justify-between text-[12px] font-black uppercase text-slate-500 tracking-[0.2em]">
                             <span className="flex items-center gap-3"><Clock size={16} /> {flight.duration}</span>
                             <span className={flight.stops === 0 ? 'text-blue-400' : 'text-slate-600'}>{flight.stops === 0 ? 'Non-Stop' : `${flight.stops} Connection`}</span>
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="mt-16 space-y-6">
                       <button className="w-full py-8 bg-blue-600 hover:bg-blue-500 text-white rounded-[2.5rem] font-black text-base transition-all flex items-center justify-center gap-5 shadow-2xl shadow-blue-600/40 uppercase tracking-widest">
                          Book Flights <ExternalLink size={24} />
                       </button>
                       <div className="grid grid-cols-2 gap-6">
                         <button className="py-6 bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-400 rounded-3xl text-[11px] font-black uppercase tracking-widest">Skyscanner</button>
                         <button className="py-6 bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-400 rounded-3xl text-[11px] font-black uppercase tracking-widest">Kayak</button>
                       </div>
                    </div>
                  </div>

                  {/* Neighborhood Hub Module */}
                  <div className="bg-white rounded-[4rem] border border-slate-200 overflow-hidden shadow-[0_8px_40px_rgba(0,0,0,0.03)] p-14">
                    <div className="flex items-center gap-6 mb-16">
                       <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-[2.5rem] flex items-center justify-center shadow-inner">
                          <MapIcon size={40} />
                       </div>
                       <div>
                          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Neighborhoods</h3>
                          <p className="text-[11px] font-black uppercase text-slate-400 tracking-widest mt-2 underline decoration-blue-200 underline-offset-4 decoration-2">Spatial Intelligence</p>
                       </div>
                    </div>
                    <div className="space-y-12">
                       {results.neighborhoods?.map((n: Neighborhood, i: number) => (
                         <div key={i} className="group relative pl-10 border-l-4 border-slate-100 hover:border-blue-500 transition-all py-2">
                            <h4 className="text-2xl font-black text-slate-900 mb-3 leading-none tracking-tight">{n.name}</h4>
                            <p className="text-base text-slate-500 mb-5 leading-relaxed italic">"{n.description}"</p>
                            <span className="inline-block bg-blue-50 text-blue-600 px-5 py-2 rounded-full text-[11px] font-black uppercase border border-blue-100 shadow-sm">Best for {n.bestFor}</span>
                         </div>
                       ))}
                    </div>
                  </div>

                  {/* Live Stay Curations Module */}
                  <div className="bg-white rounded-[4.5rem] border border-slate-200 overflow-hidden shadow-2xl p-14 relative group/stays">
                    <div className="flex items-center justify-between mb-16">
                      <div>
                        <h3 className="text-4xl font-black text-slate-900 flex items-center gap-6">
                          <Hotel size={44} className="text-blue-600" /> Stays
                        </h3>
                        <p className="text-[11px] font-black uppercase text-slate-400 tracking-widest mt-4">Localized Inventory</p>
                      </div>
                      {results.isRealHotels ? (
                         <span className="bg-emerald-50 text-emerald-600 px-6 py-2.5 rounded-full text-[11px] font-black border border-emerald-100 shadow-sm animate-pulse">GDS LIVE</span>
                      ) : (
                         <span className="bg-slate-50 text-slate-400 px-6 py-2.5 rounded-full text-[11px] font-black border border-slate-100">LOADING...</span>
                      )}
                    </div>

                    <div className="space-y-14">
                      {!results.isRealHotels ? (
                        [1,2,3].map(i => (
                          <div key={i} className="flex gap-8 items-center animate-pulse">
                            <div className="w-32 h-32 rounded-[3rem] bg-slate-100 shrink-0"></div>
                            <div className="flex-1 space-y-4">
                               <div className="h-6 bg-slate-100 rounded-full w-3/4"></div>
                               <div className="h-4 bg-slate-100 rounded-full w-1/2"></div>
                               <div className="h-8 bg-slate-100 rounded-full w-1/4"></div>
                            </div>
                          </div>
                        ))
                      ) : (
                        results.accommodations?.map((hotel: any, i: number) => (
                          <div key={i} className="flex gap-8 items-center group/hotel cursor-pointer">
                            <div className="w-32 h-32 rounded-[3rem] overflow-hidden shrink-0 bg-slate-100 shadow-inner group-hover/hotel:scale-105 transition-transform duration-500">
                               <img src={`https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=300&q=80&sig=${i}`} alt="Stay" className="w-full h-full object-cover transition-opacity group-hover/hotel:opacity-80" />
                            </div>
                            <div className="flex-1 min-w-0">
                               <h5 className="font-black text-slate-900 text-xl truncate group-hover/hotel:text-blue-600 leading-tight mb-2 tracking-tight">{hotel.name}</h5>
                               <p className="text-[12px] font-bold text-slate-400 uppercase tracking-widest mb-4">{hotel.neighborhood || 'Top Choice'}</p>
                               <div className="flex items-center justify-between">
                                 <span className="text-slate-900 font-black text-3xl tracking-tighter">${hotel.price}<span className="text-slate-400 font-medium text-[12px]">/night</span></span>
                                 <div className="flex items-center gap-2 text-blue-600 text-base font-black">
                                   {hotel.rating} <Star size={20} fill="currentColor" />
                                 </div>
                               </div>
                            </div>
                          </div>
                        ))
                      )}
                    </div>
                    {isLoadingHotels && <div className="absolute inset-0 bg-white/40 backdrop-blur-[1px] flex items-center justify-center rounded-[4.5rem] z-10"><Loader2 className="animate-spin text-blue-600" size={48} /></div>}
                  </div>

                  {/* Interactive Spatial Engine Module */}
                  <div className="bg-white rounded-[4.5rem] border border-slate-200 overflow-hidden shadow-2xl h-[650px] relative border-b-8 border-b-slate-50 group/map">
                     <div id="neighborhood-map" className="w-full h-full opacity-90 group-hover/map:opacity-100 transition-opacity duration-1000"></div>
                     <div className="absolute top-12 left-12 right-12 bg-white/95 backdrop-blur-2xl p-10 rounded-[3.5rem] border border-slate-100 shadow-2xl z-[400] group-hover/map:-translate-y-2 transition-transform duration-500">
                        <p className="text-[11px] font-black uppercase text-blue-500 tracking-[0.4em] mb-4">Spatial Intelligence</p>
                        <h4 className="text-xl font-black text-slate-900 leading-tight italic tracking-tight">Mapping high-potential neighborhoods.</h4>
                     </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-32">
        <div className="max-w-7xl mx-auto px-6 lg:px-12 flex flex-col md:flex-row justify-between items-center gap-20">
          <div className="flex items-center space-x-6">
            <div className="w-16 h-16 bg-slate-900 rounded-[2.5rem] flex items-center justify-center text-white shadow-2xl shadow-slate-900/10 hover:scale-110 transition-transform">
              <Compass size={36} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">WanderGenius</h1>
          </div>
          <p className="text-slate-400 text-[11px] font-black uppercase tracking-[0.4em] text-center opacity-60">© 2025 Intelligence Engine. Integrated Amadeus GDS Ecosystem.</p>
          <div className="flex gap-12 text-slate-400">
            <button className="w-16 h-16 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all shadow-sm active:scale-90"><Bookmark size={32} /></button>
            <button className="w-16 h-16 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all shadow-sm active:scale-90"><Share2 size={32} /></button>
          </div>
        </div>
      </footer>
    </div>
  );
};

