export const getTravelIntelligence = async (trip: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Act as a travel architect. Plan a high-end trip from ${trip.origin || 'nearby'} to ${trip.destination} (${trip.startDate} to ${trip.endDate}). 
  Extra stops: ${trip.additionalCities.join(', ')}. 
  Stay budget: $${trip.budget.max}/nt.

  Return a JSON object with:
  - "flights": Top 3 real flight estimates (price, airline, airlineCode, duration, stops, originCode, destCode).
  - "neighborhoods": 5 districts (name, description, bestFor, lat, lng).
  - "itinerary": Sequential day plan (day, title, 3 specific activities, location).
  - "accommodations": 3 style-matched hotel ideas (name, price, rating).
  - "feasibility": One-sentence strategy verdict.
  - "climatology": Short seasonal weather overview.
  - "transportation": IF multi-city, transit plan (route, type, recommendation, cost, duration).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          flights: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                price: { type: Type.NUMBER },
                airline: { type: Type.STRING },
                airlineCode: { type: Type.STRING },
                duration: { type: Type.STRING },
                stops: { type: Type.NUMBER },
                originCode: { type: Type.STRING },
                destCode: { type: Type.STRING }
              }
            }
          },
          neighborhoods: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                bestFor: { type: Type.STRING },
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
              }
            }
          },
          itinerary: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.NUMBER },
                title: { type: Type.STRING },
                activities: { type: Type.ARRAY, items: { type: Type.STRING } },
                location: { type: Type.STRING }
              }
            }
          },
          accommodations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                price: { type: Type.NUMBER },
                rating: { type: Type.NUMBER }
              }
            }
          },
          feasibility: { type: Type.STRING },
          climatology: { type: Type.STRING },
          transportation: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                route: { type: Type.STRING },
                type: { type: Type.STRING },
                recommendation: { type: Type.STRING },
                cost: { type: Type.NUMBER },
                duration: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

