                {/* RIGHT: Inventory & Maps */}
                <div className="lg:col-span-4 space-y-12">

                  {/* Airfare Hub with Restored 3-Button Layout */}
                  <div className="bg-slate-950 rounded-[3rem] overflow-hidden shadow-2xl p-8 border border-slate-800 border-b-8 border-b-blue-600">
