                          <div className="flex justify-between items-center mb-2">
                            <span className="text-blue-400 font-black text-[10px] uppercase">{flight.airline}</span>
                            <span className="text-white font-black text-xl tracking-tighter">${flight.price}</span>
                          </div>
                          <div className="flex justify-between text-[9px] font-black uppercase text-slate-500 tracking-widest">
                             <span className="flex items-center gap-2">{flight.originCode} <Plane size={10} className="text-blue-500 rotate-90" /> {flight.destCode}</span>
                             <span>{flight.stops === 0 ? 'Direct' : `${flight.stops} Stop`}</span>
                          </div>
