                      ))}
                    </div>

                    <p className="text-slate-500 text-[11px] font-bold mb-4">Compare prices on other sites:</p>
                    <div className="grid grid-cols-3 gap-3">
                       <button className="py-4 bg-[#334155] border border-slate-800 hover:bg-slate-700 text-white rounded-xl text-[10px] font-black flex items-center justify-center gap-2 transition-all">
