      url = `https://www.skyscanner.com/transport/flights/${originCode}/${destCode}/${start}/${end}/`;
    } else if (platform === 'kayak') {
      url = `https://www.kayak.com/flights/${originCode}-${destCode}/${start}/${end}?sort=bestflight_a`;
    }

    if (url) window.open(url, '_blank');
