                          </div>
                          <div className="flex-1 min-w-0">
                             <h5 className="font-black text-slate-900 text-base truncate leading-tight mb-2">{hotel.name}</h5>
                             <div className="flex items-center justify-between">
                               <span className="text-slate-900 font-black text-xl tracking-tighter">${hotel.price}<span className="text-slate-400 font-medium text-[10px]">/nt</span></span>
                               <div className="flex items-center gap-1.5 text-blue-600 text-xs font-black">
                                 {hotel.rating} <Star size={14} fill="currentColor" />
                               </div>
                             </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Neighborhood Insights */}
                  <div className="bg-white rounded-[3.5rem] border border-slate-200 overflow-hidden shadow-sm p-10">
                    <div className="flex items-center gap-4 mb-8">
                       <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                          <MapIcon size={24} />
                       </div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">Neighborhoods</h3>
                    </div>
                    <div className="space-y-8">
                       {results.neighborhoods?.map((n: any, i: number) => (
                         <div key={i} className="group relative pl-6 border-l-4 border-slate-100 hover:border-blue-500 transition-all py-1">
                            <h4 className="text-base font-black text-slate-900 mb-1 leading-none">{n.name}</h4>
                            <p className="text-xs text-slate-500 mb-3 leading-relaxed italic">"{n.description}"</p>
                            <span className="inline-block bg-blue-50 text-blue-600 px-4 py-1.5 rounded-full text-[9px] font-black uppercase">Best for {n.bestFor}</span>
                         </div>
                       ))}
                    </div>
                  </div>

                  {/* Spatial Map */}
                  <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-2xl h-[400px] relative">
                     <div id="neighborhood-map" className="w-full h-full"></div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-20">
        <div className="max-w-7xl mx-auto px-6 lg:px-12 flex flex-col md:flex-row justify-between items-center gap-12">
          <div className="flex items-center space-x-4">
            <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-white">
              <Compass size={28} />
            </div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tighter">WanderGenius</h1>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest text-center">© 2025 Intelligence Engine. Integrated GDS Ecosystem.</p>
          <div className="flex gap-8 text-slate-400">
            <button className="w-12 h-12 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-2xl transition-all"><Bookmark size={24} /></button>
            <button className="w-12 h-12 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-2xl transition-all"><Share2 size={24} /></button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plane, MapPin, Calendar, DollarSign, Plus, Trash2, 
  CloudSun, Map as MapIcon, Hotel, Briefcase, Sparkles, 
  Share2, Save, CheckCircle2, AlertTriangle, X, Loader2, 
  Zap, Clock, History, Star, Bookmark, ExternalLink, Navigation, Compass
} from 'lucide-react';
import { getTravelIntelligence, fetchWeather, geocodeCity } from './services/geminiService';
import { searchFlights, searchHotelsByCity } from './services/amadeusService';
import { TripPlan, Neighborhood } from './types';

const App: React.FC = () => {
  // Form State
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [dates, setDates] = useState({ start: '', end: '' });
  const [budget, setBudget] = useState({ min: 100, max: 400 });
  const [additionalCities, setAdditionalCities] = useState<string[]>([]);
  const [newCity, setNewCity] = useState('');

  // App State
  const [isPlanning, setIsPlanning] = useState(false);
  const [planningStep, setPlanningStep] = useState('');
  const [results, setResults] = useState<any>(null);
  const [weatherData, setWeatherData] = useState<any>(null);
  const [tempUnit, setTempUnit] = useState<'C' | 'F'>('C');
  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [recentSearches, setRecentSearches] = useState<TripPlan[]>([]);

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_saved');
    const recents = localStorage.getItem('wandergenius_recents');
    if (saved) setSavedTrips(JSON.parse(saved));
    if (recents) setRecentSearches(JSON.parse(recents));
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const removeCity = (city: string) => {
    setAdditionalCities(additionalCities.filter(c => c !== city));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setWeatherData(null);
    setPlanningStep('Syncing Global Systems...');

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const geoPromise = geocodeCity(destVal);
      const flightsPromise = searchFlights(originVal, destVal, startVal);
      const hotelsPromise = searchHotelsByCity(destVal);

      const [intel, geo, amadeusFlights, amadeusHotels] = await Promise.all([
        intelPromise,
        geoPromise,
        flightsPromise,
        hotelsPromise
      ]);

      if (!intel) throw new Error("Intelligence Engine Unavailable");

      intel.flights = amadeusFlights || intel.flights;
      intel.accommodations = amadeusHotels.length > 0 ? amadeusHotels : intel.accommodations;
      intel.isRealHotels = amadeusHotels.length > 0;
      intel.isRealFlights = !!amadeusFlights;

      setResults(intel);
      setIsPlanning(false);

      if (geo) {
        const today = new Date();
        const start = new Date(startVal);
        const diffDays = Math.ceil((start.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
        if (diffDays <= 16 && diffDays >= -1) {
          fetchWeather(geo.lat, geo.lon, startVal, endVal).then(w => {
            if (w) setWeatherData({ ...w, isForecast: true });
          });
        } else {
          setWeatherData({ overview: intel.climatology || "Standard seasonal conditions.", isForecast: false });
        }
        setTimeout(() => initMap(intel.neighborhoods, geo), 200);
      }

      setTimeout(() => resultsRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

      const currentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, budget: budgetVal, additionalCities: additionalVal,
        timestamp: Date.now()
      };
      setRecentSearches(prev => {
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [currentTrip, ...filtered].slice(0, 10);
        localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
        return updated;
      });

    } catch (err) {
      console.error(err);
      setIsPlanning(false);
      alert("A synchronization error occurred. Please verify your cities.");
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    const L = (window as any).L;
    if (!L || !center) return;
    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) return;
    if (mapRef.current) mapRef.current.remove();
    try {
      const map = L.map('neighborhood-map', { scrollWheelZoom: false }).setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '&copy; OSM' }).addTo(map);
      neighborhoods?.forEach(n => {
        if (n.lat && n.lng) L.marker([n.lat, n.lng]).addTo(map).bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
      });
      mapRef.current = map;
    } catch (err) { console.error(err); }
  };

  const toggleSaveTrip = () => {
    if (!destination) return;
    const isAlreadySaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
    if (isAlreadySaved) {
      const updated = savedTrips.filter(t => t.destination.toLowerCase() !== destination.toLowerCase());
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const newSaved: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
        timestamp: Date.now()
      };
      const updated = [newSaved, ...savedTrips];
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    }
  };

  const openExternalSearch = (platform: 'google' | 'skyscanner' | 'kayak') => {
    const firstFlight = results?.flights?.[0];
    const originCode = firstFlight?.originCode || origin;
    const destCode = firstFlight?.destCode || destination;
    const start = dates.start;
    const end = dates.end;

    if (!start || !end) return;

    let url = '';
    if (platform === 'google') {
      url = `https://www.google.com/travel/flights?q=flights from ${originCode} to ${destCode} on ${start} returning ${end}`;
    } else if (platform === 'kayak') {
      url = `https://www.kayak.com/flights/${originCode}-${destCode}/${start}/${end}?sort=bestflight_a`;
    }

    if (url) window.open(url, '_blank');
  };

  const convertTemp = (celsius: number) => {
    if (tempUnit === 'C') return Math.round(celsius);
    return Math.round((celsius * 9) / 5 + 32);
  };

  const isTripSaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
  const isRealistic = results?.feasibility?.toLowerCase?.()?.includes('realistic') ?? true;

  return (
    <div className="min-h-screen bg-[#F8FAFC]">
      <nav className="sticky top-0 z-[100] bg-white/90 backdrop-blur-md border-b border-slate-200 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 lg:px-12 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-11 h-11 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Compass size={24} strokeWidth={2.5} />
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter text-slate-900 leading-none">WanderGenius</h1>
              <span className="text-[10px] font-black uppercase text-blue-500 tracking-[0.2em] block mt-1">Intelligence Layer</span>
            </div>
          </div>
          <div className="hidden md:flex items-center space-x-8 text-sm font-bold text-slate-500">
            <button className="hover:text-blue-600 transition-colors">Flights</button>
            <button className="hover:text-blue-600 transition-colors">Hotels</button>
            <button className="px-6 py-2.5 bg-slate-900 text-white rounded-xl shadow-lg hover:bg-black transition-all">My Account</button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 lg:px-12 pt-12 pb-24">

        {/* BIG SEARCH FORM */}
        <section className="mb-24">
          <div className="max-w-5xl mx-auto text-center mb-10">
            <h2 className="text-5xl lg:text-6xl font-black text-slate-900 tracking-tight leading-none mb-4">
              AI Travel <span className="text-blue-600">Reimagined.</span>
            </h2>
            <p className="text-lg text-slate-500 font-medium">Synced with Amadeus GDS & Gemini 3 Pro.</p>
          </div>

          <div className="bg-white rounded-[3rem] p-8 shadow-[0_40px_80px_-20px_rgba(0,0,0,0.1)] border border-slate-100">
            <form onSubmit={handlePlanTrip} className="space-y-10">

              {/* Row 1: Core Inputs with HUGE Date Picker */}
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-5">
                <div className="lg:col-span-3 space-y-4">
                  <div className="px-6 py-4 bg-slate-50 border border-slate-100 rounded-3xl hover:bg-slate-100 transition-colors">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">Origin</label>
                    <div className="flex items-center gap-3">
                      <Plane size={20} className="text-slate-300" />
                      <input type="text" placeholder="Home City" value={origin} onChange={(e) => setOrigin(e.target.value)} className="bg-transparent w-full font-bold focus:outline-none text-lg text-slate-900" />
                    </div>
                  </div>
                  <div className="px-6 py-4 bg-slate-50 border border-slate-100 rounded-3xl hover:bg-slate-100 transition-colors">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">Destination</label>
                    <div className="flex items-center gap-3">
                      <MapPin size={20} className="text-blue-600" />
                      <input type="text" placeholder="Goal City" value={destination} onChange={(e) => setDestination(e.target.value)} required className="bg-transparent w-full font-bold focus:outline-none text-lg text-slate-900" />
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-9 px-8 py-10 bg-blue-50 border-2 border-blue-100 rounded-[3rem] flex flex-col justify-center shadow-inner">
                  <div className="flex items-center gap-4 mb-6">
                    <Calendar size={32} className="text-blue-600" />
                    <label className="text-sm font-black uppercase text-blue-900 tracking-[0.2em]">Travel Window Selection</label>
                  </div>
                  <div className="grid grid-cols-2 gap-12">
                    <div className="relative">
                      <label className="absolute -top-3 left-6 bg-blue-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.1em] z-10">Departure Date</label>
                      <input 
                        type="date" 
                        value={dates.start} 
                        onChange={(e) => setDates({...dates, start: e.target.value})} 
                        className="w-full bg-white border-2 border-blue-200 rounded-[2rem] px-10 py-8 text-3xl font-black text-slate-900 focus:border-blue-500 outline-none transition-all shadow-md focus:ring-4 focus:ring-blue-500/10"
                      />
                    </div>
                    <div className="relative">
                      <label className="absolute -top-3 left-6 bg-blue-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.1em] z-10">Return Date</label>
                      <input 
                        type="date" 
                        value={dates.end} 
                        onChange={(e) => setDates({...dates, end: e.target.value})} 
                        className="w-full bg-white border-2 border-blue-200 rounded-[2rem] px-10 py-8 text-3xl font-black text-slate-900 focus:border-blue-500 outline-none transition-all shadow-md focus:ring-4 focus:ring-blue-500/10"
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* Row 2: Optional Options */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 bg-slate-50/50 p-8 rounded-[2.5rem] border border-slate-100 border-dashed">
                <div className="space-y-4">
                  <div className="flex items-center gap-3">
                    <Navigation size={18} className="text-blue-500" />
                    <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Multi-City stops</label>
                  </div>
                  <div className="flex gap-2">
                    <input type="text" placeholder="Add extra stop..." value={newCity} onChange={(e) => setNewCity(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCity())} className="flex-1 bg-white border border-slate-200 rounded-2xl px-6 py-3.5 text-sm font-bold shadow-sm outline-none focus:border-blue-500" />
                    <button onClick={handleAddCity} type="button" className="p-4 bg-blue-600 text-white rounded-2xl transition-all shadow-md"><Plus size={24}/></button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {additionalCities.map(city => (
                      <span key={city} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2 animate-in zoom-in-50">
                        {city} <X size={14} className="cursor-pointer" onClick={() => removeCity(city)} />
                      </span>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="flex items-center gap-3">
                    <DollarSign size={18} className="text-emerald-500" />
                    <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Max Stay Budget</label>
                  </div>
                  <div className="px-2">
                    <input type="range" min="50" max="1500" step="50" value={budget.max} onChange={(e) => setBudget({...budget, max: parseInt(e.target.value)})} className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer" />
                    <div className="flex justify-between items-center mt-6">
                      <div className="bg-white border border-slate-200 text-slate-900 px-6 py-3 rounded-2xl text-base font-black shadow-sm">
                        ${budget.max} <span className="text-[10px] text-slate-400 ml-1">/ NIGHT</span>
                      </div>
                      <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">Live Inventory Priority</span>
                    </div>
                  </div>
                </div>
              </div>

              {/* ACTION BUTTON */}
              <button 
                type="submit" 
                disabled={isPlanning} 
                className={`w-full py-8 rounded-[2rem] flex items-center justify-center transition-all group overflow-hidden relative ${isPlanning ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl active:scale-[0.98]'}`}
              >
                {isPlanning ? (
                   <div className="flex items-center gap-4">
                     <Loader2 className="animate-spin" size={32} />
                     <span className="text-xl font-black uppercase tracking-widest">{planningStep}</span>
                   </div>
                ) : (
                  <div className="flex flex-col items-center">
                    <div className="flex items-center gap-4 font-black text-2xl tracking-tight">
                      <Sparkles size={28} className="group-hover:rotate-12 transition-transform" /> 
                      GENERATE TRIP STRATEGY
                    </div>
                  </div>
                )}
              </button>
            </form>
          </div>
        </section>

        {/* RESULTS HUB */}
        <div ref={resultsRef} className="space-y-16 scroll-mt-24">
          {results && (
            <div className="animate-in fade-in slide-in-from-bottom-10 duration-1000">

              {/* Verdict Strip */}
              <div className={`p-8 rounded-[2.5rem] flex flex-col md:flex-row items-center gap-8 mb-16 border shadow-2xl bg-white ${isRealistic ? 'border-blue-500/10' : 'border-amber-500/10'}`}>
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center text-white shadow-xl ${isRealistic ? 'bg-blue-600' : 'bg-amber-500'}`}>
                  {isRealistic ? <CheckCircle2 size={32} /> : <AlertTriangle size={32} />}
                </div>
                <div className="flex-1 text-center md:text-left">
                  <h3 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-1">Strategy Outcome</h3>
                  <p className="text-slate-600 font-medium leading-relaxed italic">"{results.feasibility}"</p>
                </div>
                <button onClick={toggleSaveTrip} className={`flex items-center gap-4 px-8 py-4 rounded-2xl font-black text-xs transition-all ${isTripSaved ? 'bg-blue-600 text-white shadow-lg' : 'bg-white text-slate-900 border border-slate-200 hover:bg-slate-50'}`}>
                   {isTripSaved ? <Bookmark fill="currentColor" size={20} /> : <Save size={20} />}
                   {isTripSaved ? 'SAVED' : 'SAVE TRIP'}
                </button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

                {/* LEFT: COMPACT ITINERARY */}
                <div className="lg:col-span-8 space-y-12">

                  {/* Weather Module */}
                  {weatherData && (
                    <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl relative overflow-hidden">
                       <div className="flex items-center justify-between mb-8">
                          <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                               <CloudSun size={24} />
                            </div>
                            <h3 className="text-2xl font-black text-slate-900 tracking-tight">Weather Hub</h3>
                          </div>

                          {/* UNIT TOGGLE */}
                          <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
                             <button 
                               onClick={() => setTempUnit('C')}
                               className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${tempUnit === 'C' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
                             >
                               °C
                             </button>
                             <button 
                               onClick={() => setTempUnit('F')}
                               className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${tempUnit === 'F' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
                             >
                               °F
                             </button>
                          </div>
                       </div>

                       {weatherData.isForecast ? (
                         <div className="flex gap-4 overflow-x-auto pb-6 custom-scrollbar">
                           {weatherData.daily?.time.map((t: string, i: number) => (
                             <div key={i} className="flex flex-col items-center bg-slate-50/50 px-6 py-4 rounded-[2rem] min-w-[110px] border border-slate-100">
                               <span className="text-[10px] font-black text-slate-400 mb-2 uppercase">{new Date(t).toLocaleDateString('en-US', { weekday: 'short', day: 'numeric' })}</span>
                               <div className="text-blue-600 mb-2"><CloudSun size={24} /></div>
                               <div className="flex flex-col items-center">
                                 <span className="text-lg font-black text-slate-900">{convertTemp(weatherData.daily.temperature_2m_max[i])}°{tempUnit}</span>
                               </div>
                             </div>
                           ))}
                         </div>
                       ) : (
                         <div className="bg-blue-50/50 p-8 rounded-2xl border border-blue-100 text-blue-900 font-medium italic shadow-inner">
                           {weatherData.overview}
                         </div>
                       )}
                    </div>
                  )}

                  {/* Compact Optimized Path */}
                  <div className="space-y-6">
                    <div className="flex items-center gap-5 mb-4">
                      <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                        <Briefcase size={20} />
                      </div>
                      <h3 className="text-2xl font-black text-slate-900 tracking-tight">Optimized Path</h3>
                    </div>

                    <div className="space-y-4">
                      {results.itinerary?.map((day: any, i: number) => (
                        <div key={i} className="group flex gap-4 items-start">
                          <div className="w-8 h-8 shrink-0 bg-slate-900 text-white rounded-lg flex items-center justify-center text-[10px] font-black shadow-md mt-1">
                            {day.day}
                          </div>
