import { GoogleGenAI, Type } from "@google/genai";

// Always instantiate GoogleGenAI inside the function to ensure the correct API key is used.
// DO NOT initialize at the top level.

export const getTravelIntelligence = async (trip: any) => {
  // Guideline: Create instance inside the function right before making an API call.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Act as an expert travel planner. Plan a trip from ${trip.origin || 'nearby'} to ${trip.destination} for ${trip.startDate} to ${trip.endDate}. 
  Additional cities to visit: ${trip.additionalCities.join(', ')}. 
  Budget range: $${trip.budget.min} - $${trip.budget.max} per night.

  Provide a detailed JSON response including:
  1. "flights": Top 3 realistic flight estimates (price in USD, airline, duration, stops).
  2. "neighborhoods": 5 best neighborhoods to stay in for tourists (name, description, bestFor, and estimated lat/lng coordinates).
  3. "itinerary": Day-by-day plan (day number, activity title, 3 activities, location).
  4. "accommodations": 3 hotel recommendations matching the budget (name, estimated price, rating).
  5. "climatology": Historical weather averages for the destination during these specific dates (avgHigh in Celsius, avgLow in Celsius, precipitationChance as a percentage, cloudCover description, and generalAdvice).
  6. "feasibility": A message evaluating if the trip is realistic, rushed, or unrealistic based on the dates and locations.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          flights: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                price: { type: Type.NUMBER },
                airline: { type: Type.STRING },
                duration: { type: Type.STRING },
                stops: { type: Type.NUMBER },
                departure: { type: Type.STRING },
                arrival: { type: Type.STRING }
              }
            }
          },
          neighborhoods: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                bestFor: { type: Type.STRING },
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
              }
            }
          },
          itinerary: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.NUMBER },
                title: { type: Type.STRING },
                activities: { type: Type.ARRAY, items: { type: Type.STRING } },
                location: { type: Type.STRING }
              }
            }
          },
          accommodations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                price: { type: Type.NUMBER },
                rating: { type: Type.NUMBER }
              }
            }
          },
          climatology: {
            type: Type.OBJECT,
            properties: {
              avgHigh: { type: Type.NUMBER },
              avgLow: { type: Type.NUMBER },
              precipitationChance: { type: Type.NUMBER },
              cloudCover: { type: Type.STRING },
              generalAdvice: { type: Type.STRING }
            }
          },
          feasibility: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

// Generic generate text helper
export const generateText = async (prompt: string, model: string, tools?: any[]) => {
