                      />
                    </div>
                    <div className="relative">
                      <label className="absolute -top-3 left-6 bg-blue-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.1em] z-10">Return Date</label>
                      <input 
                        type="date" 
                        value={dates.end} 
                        onChange={(e) => setDates({...dates, end: e.target.value})} 
