                              <span className="text-4xl font-black text-blue-900 tracking-tighter">{convertTemp(weatherData.climatology?.avgLow || 0)}°{tempUnit}</span>
                            </div>
                            <div className="bg-blue-600 p-8 rounded-[2.5rem] flex flex-col items-center justify-center text-center shadow-lg shadow-blue-600/10">
                              <span className="text-[10px] font-black text-white/60 uppercase mb-2 tracking-widest">Climate Outlook</span>
                              <p className="text-sm font-bold text-white leading-relaxed italic">
                                "{weatherData.climatology?.generalAdvice}"
                              </p>
                            </div>
                         </div>
                       )}
                    </div>
                  )}

                  {/* Compact Optimized Path */}
                  <div className="space-y-6">
                    <div className="flex items-center gap-5 mb-4">
                      <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                        <Briefcase size={20} />
                      </div>
                      <h3 className="text-2xl font-black text-slate-900 tracking-tight">Optimized Path</h3>
                    </div>

                    <div className="space-y-4">
                      {results.itinerary?.map((day: any, i: number) => (
                        <div key={i} className="group flex gap-4 items-start">
