                        <div key={i} className="group flex gap-4 items-start">
                          <div className="w-8 h-8 shrink-0 bg-slate-900 text-white rounded-lg flex items-center justify-center text-[10px] font-black shadow-md mt-1">
                            {day.day}
                          </div>
                          <div className="flex-1 bg-white px-5 py-4 rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-all flex items-center gap-6">
