                                  </span>
                                ))}
                              </div>
                            </div>
                            <div className="w-24 h-16 rounded-xl overflow-hidden shrink-0 shadow-inner relative group/img hidden md:block">
                              <img src={`https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?auto=format&fit=crop&w=200&q=80&sig=${i}`} alt="Vista" className="w-full h-full object-cover group-hover/img:scale-110 transition-transform duration-700" />
                              <div className="absolute inset-0 bg-black/10 group-hover/img:bg-transparent transition-colors"></div>
                              <div className="absolute bottom-1 left-1 right-1 bg-white/80 backdrop-blur-md p-1 rounded-md text-[6px] font-black uppercase text-slate-900 truncate">
                                {day.location}
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
