                  </div>
                </div>

                {/* RIGHT: Inventory & Maps */}
                <div className="lg:col-span-4 space-y-12">

                  {/* Airfare Hub with Explicit Route and Layover info */}
                  <div className="bg-slate-950 rounded-[3rem] overflow-hidden shadow-2xl p-8 border border-slate-800 border-b-8 border-b-blue-600">
                    <div className="flex items-center justify-between mb-8">
                      <h3 className="text-white font-black text-xl flex items-center gap-3"><Plane size={24} className="text-blue-500" /> Airfare Hub</h3>
                      <div className="w-10 h-10 rounded-2xl bg-blue-500/10 flex items-center justify-center border border-blue-500/20"><Zap size={20} className="text-blue-500" /></div>
                    </div>

                    <div className="space-y-4 mb-10">
                      {results.flights?.map((flight: any, i: number) => (
                        <div key={i} className="bg-white/5 p-5 rounded-[1.5rem] border border-white/5 hover:border-blue-500/40 transition-all cursor-pointer group shadow-inner">
                          <div className="flex justify-between items-center mb-3">
                            <span className="text-blue-400 font-black text-[10px] uppercase tracking-wider">{flight.airline}</span>
                            <span className="text-white font-black text-xl tracking-tighter">${flight.price}</span>
                          </div>

                          <div className="flex flex-col gap-2 mb-3">
                             <div className="flex items-center justify-between">
                                <div className="text-white text-xs font-bold flex flex-col">
                                   <span className="text-slate-500 text-[8px] uppercase tracking-widest mb-0.5">Origin</span>
