                        <h3 className="text-3xl font-black text-slate-900 flex items-center gap-5"><Hotel size={32} className="text-blue-600" /> Stays</h3>
                        <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-2">Curated Inventory</p>
                      </div>
                      {results.isRealHotels && <span className="bg-emerald-50 text-emerald-600 px-3 py-1.5 rounded-full text-[9px] font-black border border-emerald-100 shadow-sm">LIVE</span>}
                    </div>
                    <div className="space-y-8">
