                       <button onClick={() => openExternalSearch('kayak')} className="py-3.5 bg-[#334155] border border-slate-800 hover:bg-slate-700 text-white rounded-xl text-[9px] font-black flex items-center justify-center gap-2 transition-all shadow-lg">🚢 Kayak</button>
                    </div>
