                            <img src={`https://loremflickr.com/400/300/travel,landmark,${attr.imageSearchTerm || attr.name.replace(/\s/g, ',')}`} alt={attr.name} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
                            <div className="absolute top-2 left-2 bg-white/90 backdrop-blur-md px-2 py-0.5 rounded-full text-[7px] font-black text-slate-900 uppercase">
