import { GoogleGenAI, Type } from "@google/genai";

export const getTravelIntelligence = async (trip: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Act as an expert travel planner. Plan a trip from ${trip.origin || 'nearby'} to ${trip.destination} for ${trip.startDate} to ${trip.endDate}. 
  Additional cities to visit: ${trip.additionalCities.join(', ')}. 
  Budget range: $${trip.budget.min} - $${trip.budget.max} per night.

  Provide a detailed JSON response including:
  1. "flights": Top 3 realistic flight estimates (price in USD, airline, duration, stops).
  2. "neighborhoods": 5 best neighborhoods to stay in for tourists (name, description, bestFor, and estimated lat/lng coordinates).
  3. "attractions": Exactly 10 must-visit attractions (name, description, category, whyItIsFamous, imageSearchTerm).
  4. "accommodations": 3 hotel recommendations matching the budget (name, estimated price, rating).
  5. "climatology": {
      "avgHigh": (number, realistic historical Celsius high),
      "avgLow": (number, realistic historical Celsius low),
      "generalAdvice": (string, mandatory descriptive sentence about overall conditions)
     }
  6. "feasibility": A message evaluating if the trip is realistic.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          flights: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                price: { type: Type.NUMBER },
                airline: { type: Type.STRING },
                duration: { type: Type.STRING },
                stops: { type: Type.NUMBER },
                departure: { type: Type.STRING },
                arrival: { type: Type.STRING },
                originCode: { type: Type.STRING },
                destCode: { type: Type.STRING }
              }
            }
          },
          neighborhoods: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                bestFor: { type: Type.STRING },
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
              }
            }
          },
          attractions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                category: { type: Type.STRING },
                whyItIsFamous: { type: Type.STRING },
                imageSearchTerm: { type: Type.STRING }
              }
            }
          },
          accommodations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                price: { type: Type.NUMBER },
                rating: { type: Type.NUMBER }
              }
            }
          },
          climatology: {
            type: Type.OBJECT,
            properties: {
              avgHigh: { type: Type.NUMBER },
              avgLow: { type: Type.NUMBER },
              generalAdvice: { type: Type.STRING }
            },
            required: ["avgHigh", "avgLow", "generalAdvice"]
          },
          feasibility: { type: Type.STRING }
        },
        required: ["flights", "neighborhoods", "attractions", "accommodations", "climatology", "feasibility"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const getMarketGrounding = async (origin: string, destination: string, date: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Find the current real-time market price ranges for flights from ${origin} to ${destination} on ${date}. 
  Focus on identifying if premium airlines like Cathay Pacific, Singapore Airlines, or Emirates have specific price points. 
  Provide a concise summary of the cheapest found and the average for premium carriers.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingLinks: { title: string; uri: string }[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) groundingLinks.push({ title: chunk.web.title, uri: chunk.web.uri });
    });
  }

  return {
    text: response.text,
    sources: groundingLinks
  };
};

export const generateText = async (prompt: string, model: string, tools?: any[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return await ai.models.generateContent({
    model,
    contents: prompt,
    config: { tools }
  });
};

export function decodeBase64Audio(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function encodeUint8ArrayToBase64(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export const fetchWeather = async (lat: number, lon: number, startDate: string, endDate: string) => {
  try {
    const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&daily=temperature_2m_max,temperature_2m_min,weathercode&timezone=auto`);
    const data = await res.json();
    return data;
  } catch (err) {
    console.error("Weather fetch failed", err);
    return null;
  }
};

export const geocodeCity = async (city: string) => {
  try {
    const res = await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(city)}&count=1&language=en&format=json`);
    const data = await res.json();
    if (data.results && data.results.length > 0) {
      return { lat: data.results[0].latitude, lon: data.results[0].longitude };
    }
    return null;
  } catch (err) {
    return null;
  }
};

