                  )}

                  {/* Neighborhood Map Hub */}
                  <div className="bg-white rounded-[3.5rem] border border-slate-200 overflow-hidden shadow-2xl h-[550px] relative group">
                     <div id="neighborhood-map" className="w-full h-full"></div>

                     {/* Neighborhood Overlay */}
                     <div className="absolute top-6 right-6 bottom-6 w-80 bg-white/95 backdrop-blur-md rounded-[2.5rem] p-8 shadow-2xl z-[10] border border-slate-100 overflow-y-auto custom-scrollbar transition-transform group-hover:scale-[1.01]">
