  const [savedTrips, setSavedTrips] = useState<TripPlan[]>([]);
  const [recentSearches, setRecentSearches] = useState<TripPlan[]>([]);

  const resultsRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('wandergenius_saved');
    const recents = localStorage.getItem('wandergenius_recents');
    if (saved) setSavedTrips(JSON.parse(saved));
    if (recents) setRecentSearches(JSON.parse(recents));
  }, []);

  const handleAddCity = () => {
    if (newCity && !additionalCities.includes(newCity)) {
      setAdditionalCities([...additionalCities, newCity]);
      setNewCity('');
    }
  };

  const removeCity = (city: string) => {
    setAdditionalCities(additionalCities.filter(c => c !== city));
  };

  const executePlan = async (originVal: string, destVal: string, startVal: string, endVal: string, additionalVal: string[], budgetVal: {min: number, max: number}) => {
    setIsPlanning(true);
    setResults(null);
    setLiveFlightInfo(null);
    setLiveHotelInfo(null);
    setWeatherData(null);
    setPlanningStep('Syncing Global Systems...');

    try {
      const intelPromise = getTravelIntelligence({ origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, additionalCities: additionalVal, budget: budgetVal });
      const flightMarketPromise = getLiveFlightPrices(originVal, destVal, startVal);
      const hotelMarketPromise = getLiveHotelPrices(destVal, startVal, endVal);
      const geoPromise = geocodeCity(destVal);
      const flightsPromise = searchFlights(originVal, destVal, startVal);
      const hotelsPromise = searchHotelsByCity(destVal);

      const [intel, flightMarket, hotelMarket, geo, amadeusFlights, amadeusHotels] = await Promise.all([
        intelPromise,
        flightMarketPromise,
        hotelMarketPromise,
        geoPromise,
        flightsPromise,
        hotelsPromise
      ]);

      if (!intel) throw new Error("Intelligence Engine Unavailable");

      intel.flights = amadeusFlights || intel.flights;
      intel.accommodations = amadeusHotels.length > 0 ? amadeusHotels : intel.accommodations;
      intel.isRealHotels = amadeusHotels.length > 0;
      intel.isRealFlights = !!amadeusFlights;

      setResults(intel);
      setLiveFlightInfo(flightMarket);
      setLiveHotelInfo(hotelMarket);
      setIsPlanning(false);

      if (geo) {
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const start = new Date(startVal);
        start.setHours(0, 0, 0, 0);
        const diffDays = Math.ceil((start.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        if (diffDays <= 15 && diffDays >= 0) {
          fetchWeather(geo.lat, geo.lon, startVal, endVal).then(w => {
            if (w && w.daily) {
              setWeatherData({ ...w, isForecast: true });
            } else {
              setWeatherData({ climatology: intel.climatology, isForecast: false });
            }
          });
        } else {
          setWeatherData({ climatology: intel.climatology, isForecast: false });
        }
        setTimeout(() => initMap(intel.neighborhoods, geo), 200);
      }

      setTimeout(() => resultsRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

      const currentTrip: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin: originVal, destination: destVal, startDate: startVal, endDate: endVal, budget: budgetVal, additionalCities: additionalVal,
        timestamp: Date.now()
      };
      setRecentSearches(prev => {
        const filtered = prev.filter(t => t.destination.toLowerCase() !== destVal.toLowerCase());
        const updated = [currentTrip, ...filtered].slice(0, 10);
        localStorage.setItem('wandergenius_recents', JSON.stringify(updated));
        return updated;
      });

    } catch (err) {
      console.error(err);
      setIsPlanning(false);
      alert("A synchronization error occurred. Please verify your cities.");
    }
  };

  const handlePlanTrip = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination || !dates.start || !dates.end) return;
    await executePlan(origin, destination, dates.start, dates.end, additionalCities, budget);
  };

  const initMap = (neighborhoods: Neighborhood[], center: any) => {
    const L = (window as any).L;
    if (!L || !center) return;
    const mapContainer = document.getElementById('neighborhood-map');
    if (!mapContainer) return;
    if (mapRef.current) mapRef.current.remove();
    try {
      const map = L.map('neighborhood-map', { scrollWheelZoom: false }).setView([center.lat, center.lon], 12);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '&copy; OSM' }).addTo(map);
      neighborhoods?.forEach(n => {
        if (n.lat && n.lng) L.marker([n.lat, n.lng]).addTo(map).bindPopup(`<b>${n.name}</b><br>${n.bestFor}`);
      });
      mapRef.current = map;
    } catch (err) { console.error(err); }
  };

  const toggleSaveTrip = () => {
    if (!destination) return;
    const isAlreadySaved = savedTrips.some(t => t.destination.toLowerCase() === destination.toLowerCase());
    if (isAlreadySaved) {
      const updated = savedTrips.filter(t => t.destination.toLowerCase() !== destination.toLowerCase());
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    } else {
      const newSaved: TripPlan = {
        id: Math.random().toString(36).substr(2, 9),
        origin, destination, startDate: dates.start, endDate: dates.end, budget, additionalCities,
        timestamp: Date.now()
      };
      const updated = [newSaved, ...savedTrips];
      setSavedTrips(updated);
      localStorage.setItem('wandergenius_saved', JSON.stringify(updated));
    }
