                      <div className="px-4 py-1.5 bg-blue-50 border border-blue-100 rounded-full flex items-center gap-2">
                        <Sparkles size={12} className="text-blue-600" />
                        <span className="text-[9px] font-black text-blue-900 uppercase">Logic Engine</span>
                      </div>
                   </div>

                   <div className="px-10 grid grid-cols-1 lg:grid-cols-12 gap-10">
                      <div className="lg:col-span-8">
                         <div className="flex flex-wrap items-center gap-y-6">
                            {results.routeStrategy.stops?.map((stop: string, idx: number) => (
                               <React.Fragment key={idx}>
                                  <div className="group relative">
                                    <div className="px-6 py-3 bg-slate-900 text-white rounded-2xl text-xs font-black uppercase tracking-tight flex items-center gap-3 transition-transform group-hover:scale-105">
                                       <MapPin size={14} className="text-blue-400" />
