import { GoogleGenAI, Type } from "@google/genai";

export const getTravelIntelligence = async (trip: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Act as an expert travel planner with access to real-time global travel data. 
  Plan a trip from ${trip.origin || 'nearby'} to ${trip.destination} for ${trip.startDate} to ${trip.endDate}. 
  Additional cities to visit: ${trip.additionalCities.join(', ')}. 
  Stay budget: $${trip.budget.min} - $${trip.budget.max} per night.

  MANDATORY: Use Google Search to find CURRENT REAL-TIME flight prices from ${trip.origin || 'nearby'} to ${trip.destination} departing on ${trip.startDate}. 
  Also find 3 REAL hotel options in ${trip.destination} for the specified dates that fit the $${trip.budget.max}/night budget.

  Provide a detailed JSON response including:
  1. "flights": Top 3 CURRENT flight offers found (price in USD, airline, duration, stops, originCode, destCode).
  2. "neighborhoods": 5 best neighborhoods to stay in for tourists (name, description, bestFor, and estimated lat/lng coordinates).
  3. "attractions": Exactly 10 must-visit attractions (name, description, category, whyItIsFamous, imageSearchTerm).
  4. "accommodations": 3 specific real hotel recommendations found via search matching the budget (name, estimated price per night, rating).
  5. "climatology": {
      "avgHigh": (number, realistic historical Celsius high),
      "avgLow": (number, realistic historical Celsius low),
      "generalAdvice": (string, mandatory descriptive sentence about overall conditions)
     }
  6. "feasibility": A message evaluating if the trip is realistic.
  7. "routeStrategy": {
      "stops": (array of strings in the optimal geographic sequence),
      "segments": (array of objects with { from, to, mode, durationSuggestion }),
      "logic": (one short sentence explaining the routing efficiency)
     }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          flights: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                price: { type: Type.NUMBER },
                airline: { type: Type.STRING },
                duration: { type: Type.STRING },
                stops: { type: Type.NUMBER },
                originCode: { type: Type.STRING },
                destCode: { type: Type.STRING }
              }
            }
          },
          neighborhoods: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                bestFor: { type: Type.STRING },
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
              }
            }
          },
          attractions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                category: { type: Type.STRING },
                whyItIsFamous: { type: Type.STRING },
                imageSearchTerm: { type: Type.STRING }
              }
            }
          },
          accommodations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                price: { type: Type.NUMBER },
                rating: { type: Type.NUMBER }
              }
            }
          },
          climatology: {
            type: Type.OBJECT,
            properties: {
              avgHigh: { type: Type.NUMBER },
              avgLow: { type: Type.NUMBER },
              generalAdvice: { type: Type.STRING }
            },
            required: ["avgHigh", "avgLow", "generalAdvice"]
          },
          feasibility: { type: Type.STRING },
          routeStrategy: {
            type: Type.OBJECT,
            properties: {
              stops: { type: Type.ARRAY, items: { type: Type.STRING } },
              segments: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    from: { type: Type.STRING },
                    to: { type: Type.STRING },
                    mode: { type: Type.STRING },
                    durationSuggestion: { type: Type.STRING }
                  }
                }
              },
              logic: { type: Type.STRING }
            }
          }
        },
        required: ["flights", "neighborhoods", "attractions", "accommodations", "climatology", "feasibility", "routeStrategy"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const getLiveFlightPrices = async (origin: string, destination: string, date: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Search the web for current real-time flight prices from ${origin} to ${destination} departing on ${date}. 
  Identify specific pricing for major carriers like Cathay Pacific, Delta, or Singapore Airlines. 
  What is the current cheapest fare found on sites like Google Flights or Skyscanner for these specific parameters?`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingLinks: { title: string; uri: string }[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) groundingLinks.push({ title: chunk.web.title, uri: chunk.web.uri });
    });
  }

  return { summary: response.text, sources: groundingLinks };
};

export const getLiveHotelPrices = async (destination: string, startDate: string, endDate: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `What are the current real-time hotel price ranges in ${destination} for a stay from ${startDate} to ${endDate}? 
  Find typical rates for 4-star and 5-star hotels. Mention if any major hotels have specific deals. 
  Cite your findings from sources like Booking.com, Hotels.com or Expedia.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingLinks: { title: string; uri: string }[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) groundingLinks.push({ title: chunk.web.title, uri: chunk.web.uri });
    });
  }

  return { summary: response.text, sources: groundingLinks };
};

export const generateText = async (prompt: string, model: string, tools?: any[]) => {
