import { GoogleGenAI, Type } from "@google/genai";

export const getTravelIntelligence = async (trip: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Using 2.5 Flash for speed and Maps tool support
  const model = 'gemini-2.5-flash';

  const prompt = `Act as an expert travel planner. Plan a trip from ${trip.origin || 'nearby'} to ${trip.destination} for ${trip.startDate} to ${trip.endDate}. 
  Additional cities: ${trip.additionalCities.join(', ')}. 
  Budget: $${trip.budget.max}/night.

  MANDATORY: 
  1. Use Google Search and Google Maps tools.
  2. Find 3 REAL hotels in ${trip.destination}.
  3. For each hotel, provide a specific 'imageSearchTerm' that would yield a professional photo of that exact property.

  Response must be JSON:
  {
    "flights": [{"price": number, "airline": string, "duration": string, "stops": number, "originCode": string, "destCode": string}],
    "neighborhoods": [{"name": string, "description": string, "bestFor": string, "lat": number, "lng": number}],
    "attractions": [{"name": string, "description": string, "category": string, "whyItIsFamous": string}],
    "accommodations": [{"name": string, "price": number, "rating": number, "description": string, "imageSearchTerm": string}],
    "climatology": {"avgHigh": number, "avgLow": number, "generalAdvice": string},
    "feasibility": string,
    "routeStrategy": {"stops": string[], "segments": any[], "logic": string}
  }`;

  const response = await ai.models.generateContent({
    model: model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }, { googleMaps: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          flights: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { price: { type: Type.NUMBER }, airline: { type: Type.STRING }, duration: { type: Type.STRING }, stops: { type: Type.NUMBER }, originCode: { type: Type.STRING }, destCode: { type: Type.STRING } } } },
          neighborhoods: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING }, bestFor: { type: Type.STRING }, lat: { type: Type.NUMBER }, lng: { type: Type.NUMBER } } } },
          attractions: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING }, category: { type: Type.STRING }, whyItIsFamous: { type: Type.STRING } } } },
          accommodations: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT, 
              properties: { 
                name: { type: Type.STRING }, 
                price: { type: Type.NUMBER }, 
                rating: { type: Type.NUMBER },
                description: { type: Type.STRING },
                imageSearchTerm: { type: Type.STRING }
              } 
            } 
          },
          climatology: { type: Type.OBJECT, properties: { avgHigh: { type: Type.NUMBER }, avgLow: { type: Type.NUMBER }, generalAdvice: { type: Type.STRING } }, required: ["avgHigh", "avgLow", "generalAdvice"] },
          feasibility: { type: Type.STRING },
          routeStrategy: { type: Type.OBJECT, properties: { stops: { type: Type.ARRAY, items: { type: Type.STRING } }, segments: { type: Type.ARRAY, items: { type: Type.OBJECT } }, logic: { type: Type.STRING } } }
        },
        required: ["flights", "neighborhoods", "attractions", "accommodations", "climatology", "feasibility", "routeStrategy"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');

  // Extract grounding metadata for URLs if available
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (groundingChunks && data.accommodations) {
    data.accommodations = data.accommodations.map((hotel: any) => {
      // Find a chunk that matches the hotel name
      const chunk = groundingChunks.find((c: any) => 
        (c.maps?.title?.toLowerCase().includes(hotel.name.toLowerCase())) || 
        (c.web?.title?.toLowerCase().includes(hotel.name.toLowerCase()))
      );
      return {
        ...hotel,
        mapUrl: chunk?.maps?.uri || chunk?.web?.uri || `https://www.google.com/maps/search/${encodeURIComponent(hotel.name + ' ' + trip.destination)}`
      };
    });
  }

  return data;
};

export const fetchWeather = async (lat: number, lon: number, startDate: string, endDate: string) => {
  try {
    const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&daily=temperature_2m_max,temperature_2m_min,weathercode&timezone=auto`);
    return await res.json();
  } catch (err) {
    return null;
  }
};

export const geocodeCity = async (city: string) => {
  try {
    const res = await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(city)}&count=1&language=en&format=json`);
    const data = await res.json();
    if (data.results?.[0]) {
      return { lat: data.results[0].latitude, lon: data.results[0].longitude };
    }
    return null;
  } catch (err) {
    return null;
  }
};

