                        const bookingUrl = hotel.mapUrl?.includes('google.com') 
                          ? `${hotel.mapUrl}&checkin=${checkIn}&checkout=${checkOut}`
                          : `https://www.google.com/search?q=${encodeURIComponent(hotel.name + ' ' + destination + ' hotel booking')}&checkin=${checkIn}&checkout=${checkOut}`;

                        return (
                          <div key={i} className="flex flex-col gap-4 group">
                            <div className="flex gap-6 items-center">
                              <div className="w-24 h-24 rounded-[1.5rem] overflow-hidden shrink-0 bg-slate-100 shadow-inner">
                                <img 
                                  src={`https://source.unsplash.com/featured/?hotel,luxury,room,${encodeURIComponent(hotel.imageSearchTerm || hotel.name)}`} 
                                  alt={hotel.name} 
                                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                                  onError={(e: any) => {
