                            <span className="text-[8px] font-bold text-slate-400 uppercase tracking-wider">{attr.whyItIsFamous}</span>
                         </div>
                      </div>
                   ))}
                </div>
              </section>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-20">
